function TextField(text, fontSize, font, onlyNumbers, maxChars = Infinity) {
    this.text = text
    this.fontSize = fontSize
    this.font = font
    this.onlyNumbers = onlyNumbers
    this.maxChars = maxChars
    this.cursor = text.length
    this.ClearSelection()
}

// получение текста
TextField.prototype.GetText = function() {
    return this.text
}

// получение текста слева от курсора
TextField.prototype.GetLeftText = function() {
    return this.text.substr(0, this.cursor)
}

// получение текста справа от курсора
TextField.prototype.GetRightText = function() {
    return this.text.substr(this.cursor)
}

// получение выделенного текста
TextField.prototype.GetSelectedText = function() {
    if (!this.HaveSelection())
        return this.text

    let start = Math.min(this.selectionStart, this.selectionEnd)
    let end = Math.max(this.selectionStart, this.selectionEnd)

    return this.text.substr(start, end - start)
}

// изменение текста
TextField.prototype.SetText = function(text) {
    this.text = text
}

// начало редактирования
TextField.prototype.StartEdit = function() {
    this.cursor = this.text.length
    this.SelectAll()
}

// завершение редактирования
TextField.prototype.EndEdit = function() {
    if (this.onlyNumbers && isNaN(this.text))
        this.text = ''
}

// получение ширины строки
TextField.prototype.GetLineWidth = function(ctx, size, start = 0, length = -1, scale = 1) {
    ctx.font = (size * scale) + this.font

    if (length > -1)
        return ctx.measureText(this.text.substr(start, length)).width

    return ctx.measureText(this.text.substr(start)).width
}

// получение длины текста
TextField.prototype.GetTextLength = function(start = 0, length = -1) {
    if (length > -1)
        return this.text.substr(start, length).length

    return this.text.substr(start).length
}

// получение горизонтальной позиции
TextField.prototype.GetHorizontalPosition = function(ctx, x0, position) {
    let width = ctx.measureText(this.text.substr(0, position)).width
    let allWidth = ctx.measureText(this.text).width

    if (ctx.textAlign == 'left')
        return x0 + width

    if (ctx.textAlign == 'right')
        return x0 - allWidth + width

    return x0 + width - allWidth / 2
}

// получение вертикальной позиции
TextField.prototype.GetVerticalPosition = function(ctx, y0, fontSize) {
    if (ctx.textBaseline == 'top') {
        return y0 + fontSize / 2
    }

    if (ctx.textBaseline == 'bottom') {
        return y0 - fontSize / 2
    }

    return y0
}

// отрисовка курсора
TextField.prototype.DrawCursor = function(ctx, x0, y0, scale, fontSize) {
    let x = this.GetHorizontalPosition(ctx, x0, this.cursor)
    let y = this.GetVerticalPosition(ctx, y0, fontSize * scale)

    ctx.lineWidth = fontSize / 12 * scale

    ctx.beginPath()
    ctx.moveTo(x, y - fontSize * 0.6 * scale)
    ctx.lineTo(x, y + fontSize * 0.6 * scale)
    ctx.stroke()
}

// отрисовка выделения
TextField.prototype.DrawSelection = function(ctx, x0, y0, scale, fontSize) {
    if (this.selectionStart == this.selectionEnd)
        return

    let start = this.GetHorizontalPosition(ctx, x0, this.selectionStart)
    let end = this.GetHorizontalPosition(ctx, x0, this.selectionEnd)
    let y = this.GetVerticalPosition(ctx, y0, fontSize * scale)

    if (start > end) {
        let tmp = start
        start = end
        end = tmp
    }

    ctx.fillStyle = TEXT_FIELD_SELECTION_COLOR
    ctx.beginPath()
    ctx.rect(start, y - fontSize / 2 * scale, (end - start), fontSize * scale)
    ctx.fill()
}

// отрисовка текста
TextField.prototype.Draw = function(ctx, x, y, scale, isEdit) {
    let size = this.fontSize
    ctx.font = (size * scale) + this.font
    ctx.fillText(this.text, x, y)

    if (isEdit) {
        this.DrawSelection(ctx, x, y, scale, size)
        this.DrawCursor(ctx, x, y, scale, size)
    }
}

// в начале ли курсов
TextField.prototype.IsBegin = function() {
    return this.cursor == 0
}

// в конце ли курсов
TextField.prototype.IsEnd = function() {
    return this.cursor == this.text.length
}

// перемещение в начало
TextField.prototype.Home = function() {
    this.cursor = 0
}

// перемещение в конец
TextField.prototype.End = function() {
    this.cursor = this.text.length
}

// очистка выделения
TextField.prototype.ClearSelection = function() {
    this.selectionStart = -1
    this.selectionEnd = -1
}

// начало выделения
TextField.prototype.StartSelection = function() {
    this.selectionStart = this.cursor
}

// конец выделения
TextField.prototype.EndSelection = function() {
    this.selectionEnd = this.cursor
}

// добавление выделения
TextField.prototype.AppendSelection = function() {
    if (this.cursor < this.selectionStart) {
        this.StartSelection()
    }
    else if (this.cursor > this.selectionEnd) {
        this.EndSelection()
    }
    else {
        this.ClearSelection()
    }
}

// выделение всего
TextField.prototype.SelectAll = function() {
    this.selectionStart = 0
    this.selectionEnd = this.text.length
}

// проверка наличия выделения
TextField.prototype.HaveSelection = function() {
    return this.selectionStart > -1 && this.selectionEnd > -1
}

// установка курсора
TextField.prototype.SetCursor = function(cursor, clearSelection = true) {
    this.cursor = Math.max(0, Math.min(this.text.length, cursor))

    if (clearSelection)
        this.ClearSelection()
}

// установка курсора
TextField.prototype.SetCursorPosition = function(ctx, offset, isCentered, modifications = '') {
    if (modifications == 'shift' && !this.HaveSelection()) {
        this.StartSelection()
        this.EndSelection()
    }

    let width = this.GetLineWidth(ctx, this.fontSize)
    let length = this.GetTextLength()

    if (isCentered)
        offset += width / 2

    if (width == 0)
        width = 1

    let cursor = Math.round(offset / width * length)
    this.SetCursor(cursor, false)

    if (modifications == 'clear') {
        this.ClearSelection()
    }
    else if (modifications == 'shift') {
        this.AppendSelection()
    }
}

// проверка на пробельный символ
TextField.prototype.IsSpace = function() {
    return /[\s.\[\]\(\)\{\}]/.test(this.text[this.cursor])
}

// поиск предыдущей последовательности непробельных символов
TextField.prototype.FindPrevNonSpace = function() {
    if (this.IsBegin())
        return

    this.cursor--

    while (this.cursor > 0 && this.IsSpace())
        this.cursor--

    while (this.cursor > 0 && !this.IsSpace())
        this.cursor--

    if (this.cursor > 0 && this.IsSpace())
        this.cursor++
}

// поиск следующей последовательности непробельных символов
TextField.prototype.FindNextNonSpace = function() {
    if (this.IsEnd())
        return

    this.cursor++

    while (this.cursor < this.text.length && !this.IsSpace())
        this.cursor++

    while (this.cursor < this.text.length && this.IsSpace())
        this.cursor++
}

// удаление выделенного текста
TextField.prototype.RemoveSelected = function() {
    let start = Math.min(this.selectionStart, this.selectionEnd)
    let end = Math.max(this.selectionStart, this.selectionEnd)

    this.text = this.text.substr(0, start) + this.text.substr(end)
    this.cursor = start
    this.ClearSelection()
}

// обработка нажатия Backspace
TextField.prototype.BackSpace = function(ctrlKey) {
    if (this.HaveSelection()) {
        this.RemoveSelected()
        return
    }

    if (this.IsBegin())
        return

    let end = this.GetRightText()
    this.MoveCursorLeft(ctrlKey)
    let start = this.GetLeftText()
    this.text = start + end
}

// обработка нажатия Delete
TextField.prototype.Delete = function(ctrlKey) {
    if (this.HaveSelection()) {
        this.RemoveSelected()
        return
    }

    if (this.IsEnd())
        return

    let start = this.GetLeftText()
    let cursor = this.cursor
    this.MoveCursorRight(ctrlKey)
    let end = this.GetRightText()
    this.text = start + end
    this.cursor = cursor
}

// перемещение курсора влево
TextField.prototype.MoveCursorLeft = function(ctrlKey) {
    if (ctrlKey) {
        this.FindPrevNonSpace()
    }
    else {
        this.cursor = Math.max(0, this.cursor - 1)
    }
}

// перемещение курсора вправо
TextField.prototype.MoveCursorRight = function(ctrlKey) {
    if (ctrlKey) {
        this.FindNextNonSpace()
    }
    else {
        this.cursor = Math.min(this.text.length, this.cursor + 1)
    }
}

// добавление текста
TextField.prototype.AppendText = function(text) {
    if (this.HaveSelection()) {
        this.RemoveSelected()
    }

    if (this.onlyNumbers) {
        text = text.trim()
    }

    let start = this.GetLeftText()
    let end = this.GetRightText()

    if (start.length + text.length + end.length > this.maxChars)
        text = text.substr(0, this.maxChars - start.length - end.length)

    let result = start + text + end

    if (this.onlyNumbers && isNaN(result) && result != '-')
        return

    this.text = result
    this.cursor += text.length
}

TextField.prototype.IncrementNumber = function(step = 1, min = -Infinity, max = Infinity) {
    let value = `${Math.max(min, Math.min(max, +this.text + step))}`

    if (value.length > this.maxChars)
        return

    this.text = value
    this.End()
}

// перемещение курсора
TextField.prototype.MoveCursor = function(key, ctrlKey, shiftKey) {
    if (!shiftKey) {
        let haveSelection = this.HaveSelection()
        let start = Math.min(this.selectionStart, this.selectionEnd)
        let end = Math.max(this.selectionStart, this.selectionEnd)

        this.ClearSelection()

        if (haveSelection && key == 'ArrowLeft' && !ctrlKey) {
            this.cursor = start
            return
        }
        
        if (haveSelection && key == 'ArrowRight' && !ctrlKey) {
            this.cursor = end
            return
        }
    }
    else if (!this.HaveSelection()) {
        this.selectionStart = this.cursor
    }

    if (key == 'Home' || key == 'ArrowUp') {
        this.Home()
    }
    else if (key == 'End' || key == 'ArrowDown') {
        this.End()
    }
    else if (key == 'ArrowLeft') {
        this.MoveCursorLeft(ctrlKey)
    }
    else if (key == 'ArrowRight') {
        this.MoveCursorRight(ctrlKey)
    }

    if (shiftKey) {
        this.selectionEnd = this.cursor
    }
}

// обработка клавиши
TextField.prototype.KeyPress = function(e, isReadonly = false) {
    let ctrlKey = e.ctrlKey || e.metaKey

    if (e.key == 'Backspace' && !isReadonly) {
        this.BackSpace(ctrlKey)
    }
    else if (e.key == 'Delete' && !isReadonly) {
        this.Delete(ctrlKey)
    }
    else if (e.key == 'Home' || e.key == 'End' || e.key == 'ArrowUp' || e.key == 'ArrowDown' || e.key == 'ArrowLeft' || e.key == 'ArrowRight') {
        this.MoveCursor(e.key, ctrlKey, e.shiftKey)
    }
    else if ((e.code == 'KeyA' || e.keyCode == 65) && ctrlKey) {
        this.SelectAll()
    }
    else if (e.key != 'Enter' && !isReadonly) {
        this.AppendText(e.key)
    }
}
