function Tip(text, time=1000) {
    this.text = text
    this.time = time
    this.isShow = false
    this.opacity = 255
    this.isStarted = false
}

// отображается ли подсказка
Tip.prototype.IsShow = function() {
    return this.isShow && this.opacity > 0
}

// запуск отображения совета
Tip.prototype.StartShow = function() {
    setTimeout(() => {
        let interval = setInterval(() => {
            this.opacity -= TIP_FADE_STEP

            if (this.opacity <= 0) {
                clearInterval(interval)
                this.isShow = false
            }
        }, TIP_FADE_PERIOD)
    }, this.time)
}

// отложенный запуск отображения совета
Tip.prototype.Show = function() {
    this.isShow = true

    let waitInterval = setInterval(() => {
        if (this.isStarted) {
            clearInterval(waitInterval)
            this.StartShow()
        }
    }, 10)
}

// получение hex значения прозрачности
Tip.prototype.GetOpacity = function() {
    let opacity = Math.max(0, Math.floor(this.opacity))
    let letters = "0123456789ABCDEF"
    return letters[Math.floor(opacity / 16)] + letters[opacity % 16]
}

// получение строки с наибольшей длиной
Tip.prototype.GetLongestLine = function(lines) {
    let imax = 0

    for (let i = 1; i < lines.length; i++)
        if (lines[i].length > lines[imax].length)
            imax = i

    return lines[imax]
}

// отрисовка совета
Tip.prototype.Draw = function(ctx, x, y, width) {
    if (!this.IsShow())
        return

    this.isStarted = true
    ctx.font = TIP_FONT_SIZE + TIP_FONT
    let textWidth = ctx.measureText(this.text).width
    let lines = []

    if (textWidth > width) {
        lines = this.text.split('\n')
    }
    else {
        lines = [this.text]
    }
    
    textWidth = ctx.measureText(this.GetLongestLine(lines)).width
    this.height = lines.length * TIP_FONT_SIZE + 2 * TIP_PADDING
    let top = y - TIP_FONT_SIZE - TIP_PADDING

    ctx.fillStyle = TIP_BACKGROUND_COLOR
    ctx.fillRect(x - textWidth / 2 - TIP_PADDING, top - TIP_PADDING, textWidth + 2 * TIP_PADDING, this.height)

    ctx.fillStyle = TIP_TEXT_COLOR + this.GetOpacity()
    ctx.textAlign = 'center'
    ctx.textBaseline = 'top'

    for (let i = 0; i < lines.length; i++) {
        ctx.fillText(lines[i], x, top + i * TIP_FONT_SIZE)
    }
}
