Menu.prototype.IsVisible=function(){return this.isVisible}
Menu.prototype.IsMouseHover=function(x,y){if(!this.isVisible)return false
return this.x()<=x&&x<=this.x()+this.width&&this.y()<=y+this.scrollHeight&&y+this.scrollHeight<=this.y()+this.height}
