function LeftMenu(isFull, maxHeight) {
    this.items = []
    this.infoItems = []
    this.isFull = isFull
    this.width = isFull ? LEFT_MENU_FULL_WIDTH : LEFT_MENU_WIDTH
    this.maxHeight = maxHeight
    this.height = 0
    this.infoHeight = 0
    this.scrollHeight = 0
}

// изменение отображения меню
LeftMenu.prototype.Toggle = function() {
    this.isFull = !this.isFull

    let currWidth = this.width
    let nextWidth = this.isFull ? LEFT_MENU_FULL_WIDTH : LEFT_MENU_WIDTH
    let t = 0

    let interval = setInterval(() => {
        this.width = currWidth * (1 - t) + t * nextWidth
        t += LEFT_MENU_TOGGLE_STEP

        if (t >= 1) {
            this.width = nextWidth
            clearInterval(interval)
        }
    }, LEFT_MENU_TOGGLE_PERIOD)
}

// свернуть меню
LeftMenu.prototype.ToggleLeft = function() {
    if (this.isFull) {
        this.Toggle()
    }
}

// добавление пункта меню
LeftMenu.prototype.AddItem = function(text, imageSrc, imageHoverSrc, onclick, hover = null) {
    let image = this.LoadImage(imageSrc)
    let imageHover = this.LoadImage(imageHoverSrc)
    let y = LEFT_MENU_TOP_OFFSET + LEFT_MENU_ITEM_HEIGHT * this.items.length

    if (hover == null) {
        hover = () => false
    }

    this.items.push({ text: text, image: image, imageHover: imageHover, onclick: onclick, y: y, hover: hover })
    this.height += LEFT_MENU_ITEM_HEIGHT
}

// добавление пункта меню с информацией
LeftMenu.prototype.AddInfoItem = function(text, imageSrc, getValue) {
    this.infoItems.push({ text: text, image: this.LoadImage(imageSrc), getValue: getValue })
    this.infoHeight += LEFT_MENU_INFO_HEIGHT
}

// находится ли мышь внутри меню
LeftMenu.prototype.IsMouseHover = function(x, y) {
    return x < this.width && y >= LEFT_MENU_TOP_OFFSET
}

// находится ли мышь внутри пункта меню
LeftMenu.prototype.IsItemMouseHover = function(item, x0, y0) {
    if (!this.IsMouseHover(x0, y0))
        return false

    if (y0 >= this.maxHeight() - this.infoHeight)
        return false

    return y0 >= item.y - this.scrollHeight && y0 < item.y - this.scrollHeight + LEFT_MENU_ITEM_HEIGHT
}

LeftMenu.prototype.NeedScroll = function() {
    return this.height + this.infoHeight > this.maxHeight()
}

LeftMenu.prototype.Scroll = function(delta) {
    this.scrollHeight = Math.max(0, Math.min(this.height + this.infoHeight - this.maxHeight(), this.scrollHeight + delta))
}

// нажатие на клавишу мыши
LeftMenu.prototype.MouseDown = function(x, y) {
    for (let item of this.items)
        if (this.IsItemMouseHover(item, x, y))
            item.onclick()
}

// загрузка изображения
LeftMenu.prototype.LoadImage = function(src) {
    let image = new Image()
    image.src = src
    return image
}

// отрисовка фона
LeftMenu.prototype.DrawBackground = function(ctx, canvasWidth, canvasHeight) {
    ctx.fillStyle = LEFT_MENU_BACKGROUND_COLOR
    ctx.beginPath()
    ctx.rect(0, LEFT_MENU_TOP_OFFSET, this.width, canvasHeight - LEFT_MENU_TOP_OFFSET)
    ctx.fill()

    ctx.strokeStyle = LEFT_MENU_BORDER_COLOR
    ctx.lineWidth = 1
    ctx.beginPath()
    ctx.rect(-1, LEFT_MENU_TOP_OFFSET - 1, this.width + 1, canvasHeight - LEFT_MENU_TOP_OFFSET + 1)
    ctx.stroke()
}

LeftMenu.prototype.DrawScroll = function(ctx) {
    if (!this.NeedScroll())
        return

    let scrollHeight = (this.maxHeight() - this.infoHeight) * (this.maxHeight() - this.infoHeight) / this.height
    let start = (this.maxHeight() - this.infoHeight) * (this.scrollHeight / this.height)

    ctx.fillStyle = MENU_SCROLL_BACKGROUND_COLOR
    ctx.beginPath()
    ctx.rect(this.width - MENU_SCROLL_WIDTH, start, MENU_SCROLL_WIDTH, scrollHeight)
    ctx.fill()
}

// отрисовка пункта меню
LeftMenu.prototype.DrawItem = function(item, ctx, canvas, x0, y0, needHover) {
    let isHover = item.hover() || (needHover && this.IsItemMouseHover(item, x0, y0))
    let image = null

    if (isHover) {
        ctx.fillStyle = LEFT_MENU_ITEM_ACTIVE_BACKGROUND_COLOR
        ctx.fillRect(0, item.y - this.scrollHeight, this.width - 1, LEFT_MENU_ITEM_HEIGHT)
        ctx.fillStyle = LEFT_MENU_ITEM_FONT_COLOR
        image = item.imageHover

        if (!item.hover()) {
            canvas.style.cursor = 'pointer'
        }

        if (!this.isFull) {
            canvas.title = item.text
        }
    }
    else {
        image = item.image
    }

    ctx.drawImage(image, LEFT_MENU_ICON_WIDTH - image.width / 2, item.y + LEFT_MENU_ITEM_HEIGHT / 2 - image.height / 2 - this.scrollHeight)

    if (this.width == LEFT_MENU_FULL_WIDTH) {
        ctx.font = LEFT_MENU_ITEM_FONT
        ctx.textAlign = 'left'
        ctx.textBaseline = 'middle'
        ctx.fillStyle = isHover ? LEFT_MENU_ITEM_ACTIVE_FONT_COLOR : LEFT_MENU_ITEM_FONT_COLOR
        ctx.fillText(item.text, LEFT_MENU_PADDING * 2 + LEFT_MENU_ICON_WIDTH, item.y + LEFT_MENU_ITEM_HEIGHT / 2 - this.scrollHeight)
    }
}

// отрисовка пунктов меню
LeftMenu.prototype.DrawItems = function(ctx, canvas, x0, y0, needHover) {
    for (let item of this.items) {
        this.DrawItem(item, ctx, canvas, x0, y0, needHover)
    }
}

// отрисовка информационного пункта
LeftMenu.prototype.DrawInfoItem = function(item, ctx, y) {
    ctx.fillStyle = LEFT_MENU_BACKGROUND_COLOR
    ctx.fillRect(0, y, this.width - 1, LEFT_MENU_INFO_HEIGHT)

    ctx.drawImage(item.image, LEFT_MENU_PADDING + LEFT_MENU_ICON_WIDTH / 2 - item.image.width / 2, y + LEFT_MENU_INFO_HEIGHT / 2 - item.image.height / 2)
    ctx.fillStyle = LEFT_MENU_ITEM_FONT_COLOR
    ctx.textBaseline = 'middle'

    if (this.isFull) {
        ctx.font = LEFT_MENU_FULL_INFO_FONT
        ctx.textAlign = 'left'
        ctx.fillText(item.text + ': ' + item.getValue(), LEFT_MENU_PADDING * 2 + LEFT_MENU_ICON_WIDTH, y + LEFT_MENU_INFO_HEIGHT / 2)
    }
    else {
        ctx.font = LEFT_MENU_INFO_FONT
        ctx.textAlign = 'center'
        ctx.fillText(item.getValue(), LEFT_MENU_PADDING + LEFT_MENU_ICON_WIDTH - 4, y + LEFT_MENU_INFO_HEIGHT / 2 + item.image.height / 2)
    }
}

// отрисовка информационных пунктов
LeftMenu.prototype.DrawInfoItems = function(ctx, canvasHeight) {
    let y = canvasHeight

    for (let i = this.infoItems.length - 1; i >= 0; i--) {
        y -= LEFT_MENU_INFO_HEIGHT
        this.DrawInfoItem(this.infoItems[i], ctx, y)
    }
}

// отрисовка меню
LeftMenu.prototype.Draw = function(ctx, canvas, canvasWidth, canvasHeight, x0, y0, needHover) {
    this.DrawBackground(ctx, canvasWidth, canvasHeight)
    this.DrawItems(ctx, canvas, x0, y0, needHover)
    this.DrawInfoItems(ctx, canvasHeight)
    this.DrawScroll(ctx)
}

