function HotKeys(){this.keys=[]
this.isVisible=false
this.scrollHeight=0}HotKeys.prototype.SetVisible=function(visible){this.isVisible=visible}
HotKeys.prototype.IsVisible=function(){return this.isVisible}
HotKeys.prototype.AddKey=function(key,description){this.keys.push({key:key,description:description})}
HotKeys.prototype.NeedScroll=function(){return this.height>=this.maxHeight}
HotKeys.prototype.FixScroll=function(){this.scrollHeight=0}
HotKeys.prototype.Scroll=function(delta){this.scrollHeight=Math.max(0,Math.min(this.height-this.maxHeight,this.scrollHeight+delta))}
HotKeys.prototype.DrawKeyBorder=function(ctx,x,y,width,height,radius=4){ctx.lineWidth=1
ctx.beginPath()
ctx.moveTo(x+radius,y)
ctx.lineTo(x+width-radius,y)
ctx.quadraticCurveTo(x+width,y,x+width,y+radius)
ctx.lineTo(x+width,y+height-radius)
ctx.quadraticCurveTo(x+width,y+height,x+width-radius,y+height)
ctx.lineTo(x+radius,y+height)
ctx.quadraticCurveTo(x,y+height,x,y+height-radius)
ctx.lineTo(x,y+radius)
ctx.quadraticCurveTo(x,y,x+radius,y)
ctx.stroke()}
HotKeys.prototype.DrawItem=function(ctx,x,y,key,description){ctx.font=HOTKEY_FONT_SIZE+HOTKEY_FONT
ctx.textAlign='left'
ctx.textBaseline='top'
ctx.fillStyle=HOTKEY_TEXT_COLOR
ctx.strokeStyle=HOTKEY_TEXT_COLOR
ctx.fillText(description,x+HOTKEY_KEY_WIDTH,y)
let keys=key.split(' + ')
let dx=4
let dy=3
let shiftWidth=ctx.measureText('Shift').width
let letterWidth=ctx.measureText('A').width
for(let i=0;i<keys.length;i++){if(i>0){let text=' + '
ctx.textAlign='left'
ctx.fillText(text,x,y)
x+=ctx.measureText(text).width+dx}let width=['Shift','Alt','Ctrl','Esc','Del'].indexOf(keys[i])>-1?shiftWidth:Math.max(letterWidth,ctx.measureText(keys[i]).width)
ctx.textAlign='center'
ctx.fillText(keys[i],x+width/2,y)
this.DrawKeyBorder(ctx,x-dx,y-dy-2,width+2*dx,HOTKEY_FONT_SIZE+2*dy)
x+=width+dx}}
HotKeys.prototype.DrawScroll=function(ctx){if(!this.NeedScroll())return
let scrollHeight=this.maxHeight*this.maxHeight/(this.height-HOTKEY_HEADER_HEIGHT)
let start=HOTKEY_HEADER_HEIGHT+this.maxHeight*(this.scrollHeight/(this.height-HOTKEY_HEADER_HEIGHT))
ctx.fillStyle=HOTKEY_SCROLL_BACKGROUND_COLOR
ctx.beginPath()
ctx.rect(this.x+this.width-HOTKEY_SCROLL_WIDTH,this.y+start,HOTKEY_SCROLL_WIDTH,scrollHeight)
ctx.fill()}
HotKeys.prototype.Draw=function(ctx,bbox){let columns=Math.max(1,Math.floor((bbox.width-2*HOTKEY_PADDING)/HOTKEY_ITEM_WIDTH))
let itemsPerColumn=Math.round(this.keys.length/columns)
if(itemsPerColumn<HOTKEY_MIN_ROWS){itemsPerColumn=HOTKEY_MIN_ROWS
columns=Math.round(this.keys.length/itemsPerColumn)}this.width=columns*HOTKEY_ITEM_WIDTH+2*HOTKEY_PADDING
this.height=itemsPerColumn*HOTKEY_ITEM_HEIGHT+2*HOTKEY_PADDING+HOTKEY_HEADER_HEIGHT
this.maxHeight=bbox.height
this.x=(bbox.xmin+bbox.xmax)/2-this.width/2
this.y=Math.max(0,(bbox.ymin+bbox.ymax)/2-this.height/2)
ctx.fillStyle=HOTKEY_BACKGROUND_COLOR
ctx.strokeStyle=HOTKEY_BORDER_COLOR
ctx.lineWidth=2
ctx.beginPath()
ctx.rect(this.x,this.y,this.width,Math.min(this.maxHeight,this.height))
ctx.fill()
ctx.stroke()
this.DrawScroll(ctx)
ctx.save()
ctx.rect(this.x,this.y+HOTKEY_HEADER_HEIGHT+HOTKEY_PADDING,this.width,this.height-HOTKEY_HEADER_HEIGHT-HOTKEY_PADDING)
ctx.clip()
for(let i=0;i<this.keys.length;i++){let x=this.x+HOTKEY_PADDING+Math.floor(i/itemsPerColumn)*HOTKEY_ITEM_WIDTH
let y=this.y+HOTKEY_PADDING+HOTKEY_HEADER_HEIGHT+(i%itemsPerColumn)*HOTKEY_ITEM_HEIGHT-this.scrollHeight
this.DrawItem(ctx,x+HOTKEY_PADDING,y+HOTKEY_PADDING,this.keys[i].key,this.keys[i].description)}ctx.restore()
ctx.fillStyle=HOTKEY_TEXT_COLOR
ctx.textAlign='left'
ctx.textBaseline='top'
ctx.font=HOTKEY_HEADER_FONT
ctx.fillText('Горячие клавишы',this.x+HOTKEY_PADDING,this.y+HOTKEY_PADDING)}
;
function TouchEvents(redactor){this.redactor=redactor
this.touches=[]
this.prevTime=0
this.redactor.canvas.addEventListener('touchstart',(e)=>{this.TouchStart(e)})
this.redactor.canvas.addEventListener('touchmove',(e)=>{this.TouchMove(e)})
this.redactor.canvas.addEventListener('touchend',(e)=>{this.TouchEnd(e)})}TouchEvents.prototype.GetPoint=function(touch){return{x:Math.round(touch.clientX),y:Math.round(touch.clientY-this.redactor.offset)}}
TouchEvents.prototype.GetDistance=function(p1,p2){let dx=p2.x-p1.x
let dy=p2.y-p1.y
return Math.sqrt(dx*dx+dy*dy)}
TouchEvents.prototype.MaxAbs=function(a,b){return Math.abs(a)>Math.abs(b)?a:b}
TouchEvents.prototype.TouchStart=function(e){e.preventDefault()
this.touches=[]
let time=performance.now()
let delta=time-this.prevTime
this.prevTime=time
if(e.targetTouches.length==1){let p=this.GetPoint(e.targetTouches[0])
e.offsetX=p.x
e.offsetY=p.y
e.doubleTap=delta<300
this.redactor.MouseDown(e)
return}if(e.targetTouches.length==2){this.touches.push(this.GetPoint(e.targetTouches[0]))
this.touches.push(this.GetPoint(e.targetTouches[1]))
if(this.redactor.activeObject instanceof Selection&&!this.redactor.activeObject.IsCreated()){this.redactor.activeObject=null}}}
TouchEvents.prototype.TouchMove=function(e){e.preventDefault()
if(e.targetTouches.length==1){e.offsetX=e.targetTouches[0].clientX
e.offsetY=e.targetTouches[0].clientY-this.redactor.offset
e.button=0
this.redactor.MouseMove(e)
return}if(e.targetTouches.length!=2)return
let p1=this.GetPoint(e.targetTouches[0])
let p2=this.GetPoint(e.targetTouches[1])
let dst1=this.GetDistance(this.touches[0],this.touches[1])
let dst2=this.GetDistance(p1,p2)
this.redactor.currPoint.x=(p1.x+p2.x)/2
this.redactor.currPoint.y=(p1.y+p2.y)/2
let isMenu=this.redactor.IsMenuMouseHover()
if(Math.abs(dst2-dst1)>TOUCH_SCALE_DELTA&&!isMenu){this.redactor.SetScale(this.redactor.scale*dst2/dst1)}let dx1=p1.x-this.touches[0].x
let dx2=p2.x-this.touches[1].x
if(Math.sign(dx1)==Math.sign(dx2)){if(this.redactor.IsInput(this.redactor.activeObject)){this.redactor.MouseWheel({deltaY:-Math.sign(dx1),shiftKey:true})}else if(!isMenu){this.redactor.x0+=this.MaxAbs(dx1,dx2)}}let dy1=p1.y-this.touches[0].y
let dy2=p2.y-this.touches[1].y
if(Math.sign(dy1)==Math.sign(dy2)){if(this.redactor.IsInput(this.redactor.activeObject)){this.redactor.MouseWheel({deltaY:-Math.sign(dy1),shiftKey:false})}else if(this.redactor.IsExampleCreator(this.redactor.activeObject)){this.redactor.activeObject.Scroll(-dy1)}else if(isMenu){this.redactor.MenuMouseWheel(-dy1)}else{this.redactor.y0+=this.MaxAbs(dy1,dy2)}}this.touches[0].x=p1.x
this.touches[0].y=p1.y
this.touches[1].x=p2.x
this.touches[1].y=p2.y}
TouchEvents.prototype.TouchEnd=function(e){e.preventDefault()
this.redactor.MouseUp(e)}
