function Keyboard(){this.rows={}
this.rows[KEYBOARD_RUSSIAN_MODE]=[]
this.rows[KEYBOARD_ENGLISH_MODE]=[]
this.rows[KEYBOARD_SYMBOLS_MODE]=[]
this.rows[KEYBOARD_NUMERIC_MODE]=[]
this.mode=KEYBOARD_RUSSIAN_MODE
this.isUpperCase=false}Keyboard.prototype.AddRow=function(mode){this.rows[mode].push([])}
Keyboard.prototype.AddKey=function(mode,row,key){this.rows[mode][row].push({key:key,x:-1,y:-1,width:0,isHover:false})}
Keyboard.prototype.SetMode=function(mode){this.mode=mode
this.isUpperCase=false}
Keyboard.prototype.IsMouseHoverKey=function(key,x,y){return key.x<=x&&x<=key.x+key.width&&key.y<=y&&y<=key.y+KEYBOARD_KEY_HEIGHT}
Keyboard.prototype.IsMouseHover=function(x,y){return this.x<=x&&x<=this.x+this.width&&this.y<=y&&y<=this.y+this.height}
Keyboard.prototype.PressKey=function(key,redactor){if(key==KEYBOARD_UPPERCASE){this.isUpperCase=!this.isUpperCase
return}if(key==KEYBOARD_SWAP_TO_RUSSIAN_MODE){this.mode=KEYBOARD_RUSSIAN_MODE}else if(key==KEYBOARD_SWAP_TO_ENGLIGH_MODE){this.mode=KEYBOARD_ENGLISH_MODE}else if(key==KEYBOARD_SWAP_TO_SYMBOLS_MODE){this.mode=KEYBOARD_SYMBOLS_MODE}else if(key==KEYBOARD_SWAP_TO_NUMERIC_MODE){this.mode=KEYBOARD_NUMERIC_MODE}else if(key==KEYBOARD_ENTER){redactor.KeyPress({key:'Enter'})}else if(key==KEYBOARD_BACKSPACE){redactor.KeyPress({key:'Backspace'})}else if(key==KEYBOARD_LEFT){redactor.KeyPress({key:'ArrowLeft'})}else if(key==KEYBOARD_RIGHT){redactor.KeyPress({key:'ArrowRight'})}else{redactor.KeyPress({key:this.isUpperCase?key.toUpperCase():key})}if(this.isUpperCase){this.isUpperCase=false}}
Keyboard.prototype.Press=function(x,y,redactor){for(let i=0;i<this.rows[this.mode].length;i++){for(let key of this.rows[this.mode][i]){if(!this.IsMouseHoverKey(key,x,y)||key.key=='')continue
this.PressKey(key.key,redactor)
key.isHover=true
setTimeout(()=>key.isHover=false,100)
return true}}return this.IsMouseHover(x,y)}
Keyboard.prototype.DrawKey=function(ctx,key,radius=5){if(key.key==''){ctx.fillStyle=KEYBOARD_BACKGROUND_COLOR}else if(key.isHover){ctx.fillStyle=KEYBOARD_KEY_BACKGROUND_HOVER_COLOR}else{ctx.fillStyle=KEYBOARD_KEY_BACKGROUND_COLOR}ctx.strokeStyle=KEYBOARD_KEY_BORDER_COLOR
ctx.beginPath()
ctx.moveTo(key.x+radius,key.y)
ctx.lineTo(key.x+key.width-radius,key.y)
ctx.quadraticCurveTo(key.x+key.width,key.y,key.x+key.width,key.y+radius)
ctx.lineTo(key.x+key.width,key.y+KEYBOARD_KEY_HEIGHT-radius)
ctx.quadraticCurveTo(key.x+key.width,key.y+KEYBOARD_KEY_HEIGHT,key.x+key.width-radius,key.y+KEYBOARD_KEY_HEIGHT)
ctx.lineTo(key.x+radius,key.y+KEYBOARD_KEY_HEIGHT)
ctx.quadraticCurveTo(key.x,key.y+KEYBOARD_KEY_HEIGHT,key.x,key.y+KEYBOARD_KEY_HEIGHT-radius)
ctx.lineTo(key.x,key.y+radius)
ctx.quadraticCurveTo(key.x,key.y,key.x+radius,key.y)
ctx.fill()
ctx.stroke()
let text=key.key
if(this.isUpperCase&&KEYBOARD_CONTROLS_KEYS.indexOf(text)==-1){text=text.toUpperCase()}ctx.fillStyle=KEYBOARD_KEY_TEXT_COLOR
ctx.fillText(text,key.x+key.width/2,key.y+KEYBOARD_KEY_HEIGHT/2)}
Keyboard.prototype.DrawRow=function(ctx,x,y,width,row){let keyWidths=[]
let keysWidth=(row.length-1)*KEYBOARD_KEY_HORIZONTAL_PADDING
for(let i=0;i<row.length;i++){keyWidths[i]=row[i].key==' '?KEYBOARD_SPACE_WIDTH:KEYBOARD_KEY_WIDTH
keysWidth+=keyWidths[i]}let scale=width/keysWidth
keysWidth=(row.length-1)*KEYBOARD_KEY_HORIZONTAL_PADDING
for(let i=0;i<row.length;i++){keyWidths[i]=Math.floor(keyWidths[i]*scale)
keysWidth+=keyWidths[i]}let position=x+width/2-keysWidth/2
for(let i=0;i<row.length;i++){row[i].x=position
row[i].y=y
row[i].width=keyWidths[i]
this.DrawKey(ctx,row[i])
position+=row[i].width+KEYBOARD_KEY_HORIZONTAL_PADDING}}
Keyboard.prototype.Draw=function(ctx,x,y,areaWidth){this.width=Math.min(areaWidth,KEYBOARD_MAX_WIDTH)
this.height=this.rows[this.mode].length*(KEYBOARD_KEY_HEIGHT+KEYBOARD_KEY_VERTICAL_PADDING)+KEYBOARD_VERTICAL_PADDING*2-KEYBOARD_KEY_VERTICAL_PADDING
this.x=x-this.width/2+1
this.y=y-this.height
ctx.fillStyle=KEYBOARD_BACKGROUND_COLOR
ctx.fillRect(this.x,this.y,this.width,this.height)
ctx.font=KEYBOARD_FONT_SIZE+KEYBOARD_FONT
ctx.textAlign='center'
ctx.textBaseline='middle'
let rowPosition=this.y+KEYBOARD_VERTICAL_PADDING
for(let i=0;i<this.rows[this.mode].length;i++){this.DrawRow(ctx,this.x+KEYBOARD_HORIZONTAL_PADDING,rowPosition,this.width-2*KEYBOARD_HORIZONTAL_PADDING,this.rows[this.mode][i])
rowPosition+=KEYBOARD_KEY_HEIGHT+KEYBOARD_KEY_VERTICAL_PADDING}}
;
function ColorPicker(text, onSelect, onCancel, onLast, lastText = 'Применить ко всем') {
    this.text = text
    this.onSelect = onSelect
    this.onCancel = onCancel
    this.onLast = onLast
    this.baseAngle = 0
    this.gradientPoint = null
    this.gradientData = null
    this.colors = []

    for (let color of COLOR_PICKER_INITIAL_COLORS)
        this.colors.push(color)

    this.buttons = []
    this.buttons.push({text: 'Отменить', onclick: () => this.Cancel()})
    this.buttons.push({text: lastText, onclick: () => this.onLast()})

    this.buttonWidth = COLOR_PICKER_WIDTH / this.buttons.length
}

ColorPicker.prototype.UpdateGradientData = function(ctx) {
    let dpr = window.devicePixelRatio || 1
    let width = (COLOR_PICKER_WIDTH - 2) * dpr
    let height = (COLOR_PICKER_GRADIENT_HEIGHT - 2) * dpr

    this.gradientData = ctx.createImageData(width, height)

    for (let y = 1; y <= height; y++) {
        for (let x = 1; x <= width; x++) {
            let point = this.GetGradientPoint(this.gradientX + x / dpr, this.gradientY + y / dpr)
            let color = this.GetGradientColorAtPoint(point, true)
            let rgb = HSLToRGB(color.h, color.s, color.l)
            let index = ((y - 1) * width + (x - 1)) * 4

            this.gradientData.data[index + 0] = rgb.r
            this.gradientData.data[index + 1] = rgb.g
            this.gradientData.data[index + 2] = rgb.b
            this.gradientData.data[index + 3] = 255
        }
    }
}

ColorPicker.prototype.SetColor = function(color, updatePrev = true) {
    if (updatePrev)
        this.prevColor = color

    if (typeof color !== 'string')
        color = '#000000'

    this.color = color

    this.infoMode = COLOR_PICKER_INFO_MODES[0]

    let hsl = ColorToHSL(color)

    if (this.baseAngle != hsl.h) {
        this.baseAngle = hsl.h
        this.gradientData = null
    }

    this.SetGradientPointFromHSL(hsl)
}

ColorPicker.prototype.SetCoordinates = function(x, y) {
    this.x = x
    this.y = y

    this.gradientX = this.x
    this.gradientY = this.y + COLOR_PICKER_HEADER_HEIGHT

    this.currColorX = this.x
    this.currColorY = this.gradientY + COLOR_PICKER_GRADIENT_HEIGHT

    this.trackX = this.x + 20 + COLOR_PICKER_CURRENT_COLOR_RADIUS + COLOR_PICKER_CURRENT_COLOR_RADIUS
    this.trackY = this.currColorY + COLOR_PICKER_CURRENT_COLOR_HEIGHT / 2 - COLOR_PICKER_BASE_COLOR_HEIGHT / 2

    this.infoX = this.x
    this.infoY = this.currColorY + COLOR_PICKER_CURRENT_COLOR_HEIGHT

    this.colorsX = this.x + COLOR_PICKER_PADDING_X
    this.colorsY = this.infoY + COLOR_PICKER_INFO_HEIGHT

    this.buttonsX = this.x
    this.buttonsY = this.colorsY + COLOR_PICKER_COLORS_HEIGHT
}

ColorPicker.prototype.SetGradientPointFromHSL = function(hsl) {
    let tx = Math.max(0, Math.min(1, hsl.s / 100))
    let ty = Math.max(0, Math.min(1, 1 - hsl.l / (100 - 50 * tx)))
    this.gradientPoint = {tx: tx, ty: ty}
}

ColorPicker.prototype.GetGradientPoint = function(x, y) {
    if (x < this.gradientX)
        x = this.gradientX
    else if (x > this.gradientX + COLOR_PICKER_WIDTH)
        x = this.gradientX + COLOR_PICKER_WIDTH

    if (y < this.gradientY)
        y = this.gradientY
    else if (y > this.gradientY + COLOR_PICKER_GRADIENT_HEIGHT)
        y = this.gradientY + COLOR_PICKER_GRADIENT_HEIGHT

    let tx = (x - this.gradientX + 1) / (COLOR_PICKER_WIDTH - 3)
    let ty = (y - this.gradientY + 1) / (COLOR_PICKER_GRADIENT_HEIGHT - 3)

    return {tx, ty}
}

ColorPicker.prototype.GradientPointToScreen = function(point) {
    let x = this.gradientX - 1 + point.tx * (COLOR_PICKER_WIDTH - 3)
    let y = this.gradientY - 1 + point.ty * (COLOR_PICKER_GRADIENT_HEIGHT - 3)

    return {x, y}
}

ColorPicker.prototype.GetAngleAtPoint = function(x, y) {
    if (x < this.trackX)
        return 0

    if (x >= this.trackX + COLOR_PICKER_CURRENT_COLOR_WIDTH)
        return 360

    return (x - this.trackX) / COLOR_PICKER_CURRENT_COLOR_WIDTH * 360
}

ColorPicker.prototype.GetGradientColorAtPoint = function(point, asDict = false) {
    let s = Math.max(0, Math.min(100, Math.floor(100 * point.tx)))
    let l = Math.max(0, Math.min(100, Math.floor((100 - 50 * point.tx) * (1 - point.ty))))

    return asDict ? {h: this.baseAngle, s: s, l: l} : `hsl(${this.baseAngle},${s}%,${l}%)`
}

ColorPicker.prototype.GetColorAtPoint = function(x, y) {
    for (let i = 0; i < this.colors.length; i++) {
        let cx = this.colorsX + (i % COLOR_PICKER_CELLS_PER_ROW) * (COLOR_PICKER_CELL_SIZE + COLOR_PICKER_CELL_DX)
        let cy = this.colorsY + COLOR_PICKER_PADDING_Y + Math.floor(i / COLOR_PICKER_CELLS_PER_ROW) * (COLOR_PICKER_CELL_SIZE + COLOR_PICKER_CELL_DY)

        if (cx <= x && x <= cx + COLOR_PICKER_CELL_SIZE && cy <= y && y <= cy + COLOR_PICKER_CELL_SIZE)
            return this.colors[i]
    }

    return null
}

ColorPicker.prototype.GetCurrentColorByAngle = function(angle) {
    return `hsl(${angle},100%,50%)`
}

ColorPicker.prototype.IsMouseHover = function(x, y) {
    return this.x <= x && x <= this.x + COLOR_PICKER_WIDTH && this.y <= y && y <= this.y + COLOR_PICKER_HEIGHT
}

ColorPicker.prototype.IsMouseHoverGradient = function(x, y) {
    return this.gradientX <= x && x <= this.gradientX + COLOR_PICKER_WIDTH && this.gradientY <= y && y <= this.gradientY + COLOR_PICKER_GRADIENT_HEIGHT
}

ColorPicker.prototype.IsMouseHoverCurrentTrack = function(x, y) {
    return this.trackX <= x && x <= this.trackX + COLOR_PICKER_CURRENT_COLOR_WIDTH && this.trackY <= y && y <= this.trackY + COLOR_PICKER_BASE_COLOR_HEIGHT
}

ColorPicker.prototype.IsMouseHoverModeButton = function(x, y, isLeft) {
    if (this.infoY > y || y > this.infoY + COLOR_PICKER_INFO_HEIGHT)
        return false

    let xmin = isLeft ? this.infoX : this.infoX + COLOR_PICKER_WIDTH - COLOR_PICKER_INFO_FONT_SIZE
    let xmax = isLeft ? this.infoX + COLOR_PICKER_INFO_FONT_SIZE : this.infoX + COLOR_PICKER_WIDTH

    return xmin <= x && x <= xmax
}

ColorPicker.prototype.IsMouseHoverButtons = function(x, y) {
    return this.buttonsX <= x && x <= this.buttonsX + COLOR_PICKER_WIDTH && this.buttonsY <= y && y <= this.buttonsY + COLOR_PICKER_BUTTONS_HEIGHT
}

ColorPicker.prototype.SetGradientPoint = function(point) {
    this.gradientPoint = point
    this.color = this.GetGradientColorAtPoint(point)
}

ColorPicker.prototype.SetBaseAngle = function(angle) {
    this.baseAngle = Math.floor(angle)

    this.color = this.GetCurrentColorByAngle(angle)

    if (this.gradientPoint != null)
        this.color = this.GetGradientColorAtPoint(this.gradientPoint)

    this.gradientData = null
}

ColorPicker.prototype.SwitchMode = function(dir) {
    let index = COLOR_PICKER_INFO_MODES.indexOf(this.infoMode) + dir + COLOR_PICKER_INFO_MODES.length
    this.infoMode = COLOR_PICKER_INFO_MODES[(index) % COLOR_PICKER_INFO_MODES.length]
}

ColorPicker.prototype.ClickButton = function(x, y) {
    let index = Math.floor((x - this.buttonsX) / this.buttonWidth)
    this.buttons[index].onclick()
}

ColorPicker.prototype.Cancel = function() {
    this.onSelect(this.prevColor)
    this.onCancel()
}

ColorPicker.prototype.Close = function() {
    if (this.colors.indexOf(this.color) > -1)
        return

    this.colors.push(this.color)

    if (this.colors.length > COLOR_PICKER_MAX_COLORS)
        this.colors.splice(COLOR_PICKER_INITIAL_COLORS.length, 1)
}

ColorPicker.prototype.MouseDown = function(x, y) {
    this.down = ''

    if (this.IsMouseHoverGradient(x, y)) {
        let point = this.GetGradientPoint(x, y)
        this.SetGradientPoint(point)
        this.down = 'gradient'
    }
    else if (this.IsMouseHoverCurrentTrack(x, y)) {
        let angle = this.GetAngleAtPoint(x, y)
        this.SetBaseAngle(angle)
        this.down = 'track'
    }
    else if (this.IsMouseHoverButtons(x, y)) {
        this.ClickButton(x, y)
        return false
    }
    else if (this.IsMouseHoverModeButton(x, y, true)) {
        this.SwitchMode(-1)
        return false
    }
    else if (this.IsMouseHoverModeButton(x, y, false)) {
        this.SwitchMode(1)
        return false
    }
    else {
        let color = this.GetColorAtPoint(x, y)

        if (color == null)
            return false

        this.SetColor(color, false)
    }

    this.onSelect(this.color)
    return this.down != ''
}

ColorPicker.prototype.MouseMove = function(x, y, dx, dy) {
    if (this.down == 'gradient') {
        this.SetGradientPoint(this.GetGradientPoint(x + dx, y + dy))
    }
    else if (this.down == 'track') {
        this.SetBaseAngle(this.GetAngleAtPoint(x + dx, y + dy))
    }
    else {
        return
    }

    this.onSelect(this.color)
}

ColorPicker.prototype.DrawHeader = function(ctx) {
    ctx.font = COLOR_PICKER_FONT
    ctx.textAlign = 'center'
    ctx.textBaseline = 'middle'
    ctx.fillStyle = COLOR_PICKER_TEXT_COLOR
    ctx.fillText(this.text, this.x + COLOR_PICKER_WIDTH / 2, this.y + COLOR_PICKER_HEADER_HEIGHT / 2)
}

ColorPicker.prototype.DrawGradient = function(ctx) {
    if (this.gradientData == null)
        this.UpdateGradientData(ctx)

    let dpr = window.devicePixelRatio || 1
    ctx.putImageData(this.gradientData, (this.gradientX + 1) * dpr, (this.gradientY + 1) * dpr)

    ctx.strokeStyle = COLOR_PICKER_BORDER_COLOR
    ctx.lineWidth = 1
    ctx.beginPath()
    ctx.rect(this.gradientX, this.gradientY, COLOR_PICKER_WIDTH, COLOR_PICKER_GRADIENT_HEIGHT)
    ctx.stroke()

    if (this.gradientPoint == null)
        return

    ctx.save()
    ctx.clip()

    let point = this.GradientPointToScreen(this.gradientPoint)

    ctx.strokeStyle = COLOR_PICKER_GRADIENT_POINT_COLOR
    ctx.beginPath()
    ctx.arc(point.x, point.y, COLOR_PICKER_GRADIENT_POINT_RADIUS, 0, Math.PI * 2)
    ctx.stroke()
    ctx.restore()
}

ColorPicker.prototype.DrawCurrentColor = function(ctx) {
    ctx.strokeStyle = COLOR_PICKER_BORDER_COLOR
    ctx.fillStyle = COLOR_PICKER_BACKGROUND_COLOR
    ctx.lineWidth = 1

    ctx.beginPath()
    ctx.rect(this.currColorX, this.currColorY, COLOR_PICKER_WIDTH, COLOR_PICKER_CURRENT_COLOR_HEIGHT)
    ctx.fill()
    ctx.stroke()

    let cx = this.currColorX + 5 + COLOR_PICKER_CURRENT_COLOR_RADIUS
    let cy = this.currColorY + COLOR_PICKER_CURRENT_COLOR_HEIGHT / 2

    ctx.fillStyle = this.color
    ctx.beginPath()
    ctx.arc(cx, cy, COLOR_PICKER_CURRENT_COLOR_RADIUS, 0, Math.PI * 2)
    ctx.fill()
    ctx.stroke()

    for (let i = 0; i < COLOR_PICKER_CURRENT_COLOR_WIDTH; i++) {
        let angle = this.GetAngleAtPoint(this.trackX + i, this.trackY)

        ctx.beginPath()
        ctx.fillStyle = this.GetCurrentColorByAngle(angle)
        ctx.rect(this.trackX + i, this.trackY, 1, COLOR_PICKER_BASE_COLOR_HEIGHT)
        ctx.fill()
    }

    ctx.fillStyle = COLOR_PICKER_TRACK_BACKGROUND
    ctx.strokeStyle = COLOR_PICKER_TRACK_BORDER
    ctx.beginPath()
    ctx.arc(this.trackX + this.baseAngle / 360 * COLOR_PICKER_CURRENT_COLOR_WIDTH, this.trackY + COLOR_PICKER_BASE_COLOR_HEIGHT / 2, COLOR_PICKER_BASE_COLOR_HEIGHT / 2 + 1, 0, Math.PI * 2)
    ctx.fill()
    ctx.stroke()
}

ColorPicker.prototype.DrawInfo = function(ctx, x, y) {
    ctx.strokeStyle = COLOR_PICKER_BORDER_COLOR
    ctx.fillStyle = COLOR_PICKER_BACKGROUND_COLOR
    ctx.font = COLOR_PICKER_INFO_FONT
    ctx.beginPath()
    ctx.rect(this.infoX, this.infoY, COLOR_PICKER_WIDTH, COLOR_PICKER_INFO_HEIGHT)
    ctx.fill()
    ctx.stroke()

    let hsl = ColorToHSL(this.color)
    let text = ''

    if (this.infoMode == COLOR_PICKER_INFO_HSL_MODE) {
        text = `hsl(${hsl.h}, ${hsl.s}%, ${hsl.l}%)`
    }
    else if (this.infoMode == COLOR_PICKER_INFO_RGB_MODE) {
        let rgb = HSLToRGB(hsl.h, hsl.s, hsl.l)
        text = `rgb(${rgb.r}, ${rgb.g}, ${rgb.b})`
    }
    else if (this.infoMode == COLOR_PICKER_INFO_HEX_MODE) {
        let rgb = HSLToRGB(hsl.h, hsl.s, hsl.l)
        let digits = '0123456789abcdef'
        let r = digits[rgb.r >> 4] + digits[rgb.r % 16]
        let g = digits[rgb.g >> 4] + digits[rgb.g % 16]
        let b = digits[rgb.b >> 4] + digits[rgb.b % 16]
        text = `#${r}${g}${b}`
    }

    ctx.fillStyle = COLOR_PICKER_TEXT_COLOR
    ctx.fillText(text, this.infoX + COLOR_PICKER_WIDTH / 2, this.infoY + COLOR_PICKER_INFO_HEIGHT / 2)

    if (this.IsMouseHoverModeButton(x, y, true))
        ctx.fillStyle = COLOR_PICKER_BUTTONS_HOVER_BACKGROUND
    else
        ctx.fillStyle = COLOR_PICKER_TEXT_COLOR

    ctx.fillText('❰', this.infoX + 8, this.infoY + COLOR_PICKER_INFO_HEIGHT / 2)

    if (this.IsMouseHoverModeButton(x, y, false))
        ctx.fillStyle = COLOR_PICKER_BUTTONS_HOVER_BACKGROUND
    else
        ctx.fillStyle = COLOR_PICKER_TEXT_COLOR

    ctx.fillText('❱', this.infoX + COLOR_PICKER_WIDTH - 8, this.infoY + COLOR_PICKER_INFO_HEIGHT / 2)
}

ColorPicker.prototype.DrawColors = function(canvas, ctx, x0, y0) {
    ctx.strokeStyle = COLOR_PICKER_BORDER_COLOR
    ctx.fillStyle = COLOR_PICKER_BACKGROUND_COLOR
    ctx.beginPath()
    ctx.rect(this.x, this.colorsY, COLOR_PICKER_WIDTH, COLOR_PICKER_COLORS_HEIGHT)
    ctx.fill()
    ctx.stroke()

    let x = this.colorsX
    let y = this.colorsY + COLOR_PICKER_PADDING_Y

    for (let i = 0; i < this.colors.length; i++) {
        let row = Math.floor(i / COLOR_PICKER_CELLS_PER_ROW)
        let column = i % COLOR_PICKER_CELLS_PER_ROW

        let cx = x + column * (COLOR_PICKER_CELL_SIZE + COLOR_PICKER_CELL_DX)
        let cy = y + row * (COLOR_PICKER_CELL_SIZE + COLOR_PICKER_CELL_DY)

        let isHover = cx <= x0 && x0 <= cx + COLOR_PICKER_CELL_SIZE && cy <= y0 && y0 <= cy + COLOR_PICKER_CELL_SIZE

        if (isHover)
            canvas.style.cursor = 'pointer'

        if (isHover || this.color == this.colors[i]) {
            ctx.strokeStyle = COLOR_PICKER_CELLS_BORDER_HOVER
            ctx.lineWidth = 2
        }
        else {
            ctx.strokeStyle = COLOR_PICKER_CELLS_BORDER
            ctx.lineWidth = 1
        }

        ctx.fillStyle = this.colors[i]
        ctx.beginPath()
        ctx.rect(cx, cy, COLOR_PICKER_CELL_SIZE, COLOR_PICKER_CELL_SIZE)
        ctx.stroke()
        ctx.fill()
    }
}

ColorPicker.prototype.DrawButtons = function(ctx, x, y) {
    ctx.font = COLOR_PICKER_FONT

    for (let i = 0; i < this.buttons.length; i++) {
        let button = this.buttons[i]
        let xi = this.buttonsX + i * this.buttonWidth

        let isHover = xi <= x && x < xi + this.buttonWidth && this.buttonsY <= y && y <= this.buttonsY + COLOR_PICKER_BUTTONS_HEIGHT

        ctx.fillStyle = isHover ? COLOR_PICKER_BUTTONS_HOVER_BACKGROUND : COLOR_PICKER_BACKGROUND_COLOR
        ctx.strokeStyle = COLOR_PICKER_BORDER_COLOR
        ctx.beginPath()
        ctx.rect(xi, this.buttonsY, this.buttonWidth, COLOR_PICKER_BUTTONS_HEIGHT)
        ctx.fill()
        ctx.stroke()

        ctx.fillStyle = isHover ? COLOR_PICKER_BUTTONS_HOVER_COLOR : COLOR_PICKER_TEXT_COLOR
        ctx.fillText(button.text, xi + this.buttonWidth / 2, this.buttonsY + COLOR_PICKER_BUTTONS_HEIGHT / 2)
    }
}

ColorPicker.prototype.Draw = function(canvas, ctx, x, y) {
    ctx.strokeStyle = COLOR_PICKER_BORDER_COLOR
    ctx.fillStyle = COLOR_PICKER_BACKGROUND_COLOR
    ctx.lineWidth = 1
    ctx.beginPath()
    ctx.rect(this.x, this.y, COLOR_PICKER_WIDTH, COLOR_PICKER_HEIGHT)
    ctx.fill()
    ctx.stroke()

    this.DrawHeader(ctx)
    this.DrawGradient(ctx)
    this.DrawCurrentColor(ctx)
    this.DrawInfo(ctx, x, y)
    this.DrawColors(canvas, ctx, x, y)
    this.DrawButtons(ctx, x, y)

    if (this.IsMouseHoverCurrentTrack(x, y) || this.IsMouseHoverGradient(x, y))
        canvas.style.cursor = 'crosshair'
    else if (this.IsMouseHoverModeButton(x, y, true) || this.IsMouseHoverModeButton(x, y, false))
        canvas.style.cursor = 'pointer'
    else if (this.IsMouseHoverButtons(x, y))
        canvas.style.cursor = 'pointer'
}

