ExampleCreator.prototype.DrawExample=function(ctx,canvas,example,x0,y0){let ishover=this.IsExampleMouseHover(example,x0,y0)
if(ishover){ctx.strokeStyle=CREATING_EXAMPLE_HOVER_BORDER_COLOR
canvas.style.cursor='pointer'}else{ctx.strokeStyle=CREATING_EXAMPLE_BORDER_COLOR}ctx.lineWidth=1
ctx.beginPath()
ctx.rect(example.x,example.y,example.width,example.height)
ctx.stroke()
ctx.drawImage(example.image,example.x,example.y,example.width,example.width)
ctx.textAlign='center'
ctx.textBaseline='top'
ctx.font=CREATING_EXAMPLE_FONT_SIZE+CREATING_EXAMPLE_FONT
ctx.fillStyle=ishover?CREATING_TEXT_HOVER_COLOR:CREATING_TEXT_COLOR
let splited=SplitText(example.header,ctx,example.width)
for(let i=0;i<splited.texts.length;i++)ctx.fillText(splited.texts[i],example.x+example.width/2,example.y+example.width-(splited.texts.length-1-i)*CREATING_EXAMPLE_FONT_SIZE)}
ExampleCreator.prototype.DrawExamples=function(ctx,canvas,x,y,x0,y0,exampleWidth,exampleHeight,columns){let posX=x+CREATING_HORIZONTAL_PADDING
let posY=y+CREATING_VERTICAL_PADDING+CREATING_HEADER_HEIGHT
for(let i=0;i<this.examples.length;i++){this.examples[i].x=posX
this.examples[i].y=posY
this.examples[i].width=exampleWidth
this.examples[i].height=exampleHeight
this.DrawExample(ctx,canvas,this.examples[i],x0,y0)
posX+=exampleWidth+CREATING_EXAMPLE_PADDING
if(i%columns==columns-1){posX=x+CREATING_HORIZONTAL_PADDING
posY+=exampleHeight+CREATING_EXAMPLE_PADDING}}}
ExampleCreator.prototype.NeedScroll=function(){return this.realHeight>=this.height}
ExampleCreator.prototype.DrawScroll=function(ctx){if(!this.NeedScroll())return
let scrollHeight=this.height*this.height/this.realHeight
let start=this.height*(this.scrollHeight/this.realHeight)
ctx.fillStyle=CREATING_SCROLL_BACKGROUND_COLOR
ctx.beginPath()
ctx.rect(this.x+this.width-CREATING_SCROLL_WIDTH,this.y+start,CREATING_SCROLL_WIDTH,scrollHeight)
ctx.fill()}
ExampleCreator.prototype.Draw=function(ctx,canvas,x,y,width,height,x0,y0){ctx.fillStyle=CREATING_BACKGROUND_COLOR
ctx.fillRect(x,y,width,height)
let areaWidth=width-2*CREATING_HORIZONTAL_PADDING
let exampleWidth=Math.min(areaWidth,CREATING_EXAMPLE_WIDTH)
let columns=Math.floor((areaWidth+CREATING_EXAMPLE_PADDING)/(exampleWidth+CREATING_EXAMPLE_PADDING))
let realWidth=columns*(exampleWidth+CREATING_EXAMPLE_PADDING)-CREATING_EXAMPLE_PADDING
if(realWidth<areaWidth)exampleWidth*=areaWidth/realWidth
let exampleHeight=exampleWidth+CREATING_EXAMPLE_HEIGHT
let rows=Math.floor((this.examples.length+columns-1)/columns)
this.x=x
this.y=y
this.width=width
this.height=height
this.realHeight=rows*(exampleHeight+CREATING_EXAMPLE_PADDING)-CREATING_EXAMPLE_PADDING+2*CREATING_VERTICAL_PADDING+CREATING_HEADER_HEIGHT
this.scrollHeight=Math.max(0,Math.min(this.realHeight-this.height,this.scrollHeight))
ctx.fillStyle=CREATING_TEXT_COLOR
ctx.font=CREATING_HEADER_FONT
ctx.textAlign='left'
ctx.textBaseline='top'
ctx.fillText('Примеры графов',x+CREATING_HORIZONTAL_PADDING,y-this.scrollHeight+CREATING_VERTICAL_PADDING)
this.DrawClose(ctx,canvas,x,y-this.scrollHeight,width,x0,y0)
this.DrawScroll(ctx)
this.DrawExamples(ctx,canvas,x,y-this.scrollHeight,x0,y0,exampleWidth,exampleHeight,columns)}
ExampleCreator.prototype.Scroll=function(delta){this.scrollHeight=Math.max(0,Math.min(this.realHeight-this.height,this.scrollHeight+delta))}
