function IntroFrameGenerator(cursor=null){this.frames=[]
this.cursor=cursor==null?{x:Math.random(),y:0.95}:cursor
this.click=null
this.objects=[]
this.key2obj={}
this.sizes=[]}IntroFrameGenerator.prototype.GetCursorPoint=function(){return{x:this.cursor.x,y:this.cursor.y}}
IntroFrameGenerator.prototype.GetNextRandomPoint=function(){let p=this.GetCursorPoint()
while(Math.abs(p.x-this.cursor.x)+Math.abs(p.y-this.cursor.y)<0.5){p.x=0.1+Math.floor(Math.random()*9)/10
p.y=0.2+Math.floor(Math.random()*7)/10}return p}
IntroFrameGenerator.prototype.MoveCursor=function(p1,p2,steps){if(p1==null){p1=this.GetCursorPoint()}if(p2==null)p2=this.GetNextRandomPoint()
for(let i=0;i<steps;i++){let t=i/(steps-1)
let x=p1.x*(1-t)+p2.x*t
let y=p1.y*(1-t)+p2.y*t
this.frames.push({objects:[...JSON.parse(JSON.stringify(this.objects)),{type:INTRO_CURSOR,position:{x:x,y:y}}],time:INTRO_FRAMES_TIME})}this.cursor.x=p2.x
this.cursor.y=p2.y}
IntroFrameGenerator.prototype.DoubleClick=function(){this.sizes=[8,14,21,25,29,33]
this.click={type:INTRO_DOUBLE_CLICK,position:this.GetCursorPoint()}}
IntroFrameGenerator.prototype.Click=function(){this.sizes=[8,14,21,25,29]
this.click={type:INTRO_CLICK,position:this.GetCursorPoint()}}
IntroFrameGenerator.prototype.AddVertex=function(key,text,status,position=null,isEdit=false){let object={type:INTRO_VERTEX,text:text,position:position==null?this.GetCursorPoint():position,status:status,isEdit:isEdit}
this.AddObject(key,object)}
IntroFrameGenerator.prototype.AddKeys=function(key,values,pressed){let object={type:INTRO_KEYS,values:values,pressed:pressed}
this.AddObject(key,object)}
IntroFrameGenerator.prototype.AddEdge=function(key,v1,v2,weight,isDirected,status,isEdit=false){v1=this.GetObject(v1)
v2=this.GetObject(v2)
let object={type:INTRO_EDGE,v1:v1,v2:v2,weight:weight,isDirected:isDirected,status:status,isEdit:isEdit}
this.AddObject(key,object)}
IntroFrameGenerator.prototype.AddObject=function(key,object){this.objects.push(object)
this.key2obj[key]=object}
IntroFrameGenerator.prototype.RemoveObject=function(key){this.objects=this.objects.filter((object)=>object!=this.key2obj[key])
delete this.key2obj[key]}
IntroFrameGenerator.prototype.GetObject=function(key){return this.key2obj[key]}
IntroFrameGenerator.prototype.FinalizeFrame=function(frameTime,count=1){for(;count>0;count--){let objects=JSON.parse(JSON.stringify(this.objects))
if(this.sizes.length>0)objects.push({type:this.click.type,position:this.click.position,size:this.sizes.shift()})
objects.push({type:INTRO_CURSOR,position:this.GetCursorPoint()})
this.frames.push({objects:objects,time:frameTime})}}
