function Intro(onClose) {
    this.onClose = onClose

    this.actions = []
    this.actionIndex = 0

    this.checkBox = new CheckBox(INTRO_CHECK_BOX_TEXT, INTRO_CHECK_BOX_SIZE, true)
    this.gridSize = 7
    this.crossSize = INTRO_TOP_PADDING / 2.5

    this.buttons = [
        { text: 'Назад', onclick: () => this.Prev(), enabled: () => this.actionIndex > 0 },
        { text: 'Далее', onclick: () => this.Next(), enabled: () => this.actionIndex < this.actions.length - 1 },
        { text: 'Завершить', onclick: () => this.onClose(this.checkBox.IsChecked()), enabled: () => this.actionIndex == this.actions.length - 1 }
    ]

    this.prevTime = -1
    this.vertex = new Vertex(0, 0, '1', { radius: this.gridSize * 2 })
    this.v1 = new Vertex(0, 0, '', { radius: this.gridSize * 2 })
    this.v2 = new Vertex(0, 0, '', { radius: this.gridSize * 2 })
    this.edge = new Edge(this.v1, this.v2, '', false, 0)
}

Intro.prototype.AddAction = function(header, text, frames) {
    this.actions.push({ header: header, text: text, frames: frames })
    this.ResetFrames()
}

Intro.prototype.ResetFrames = function() {
    this.actions[this.actionIndex].frameIndex = 0
    this.prevTime = -1
}

Intro.prototype.Prev = function() {
    this.actionIndex--
    this.ResetFrames()
}

Intro.prototype.Next = function() {
    this.actionIndex++
    this.ResetFrames()
}

Intro.prototype.IsCrossHover = function(x, y) {
    return this.crossX <= x && x <= this.crossX + this.crossSize && this.crossY <= y && y <= this.crossY + this.crossSize
}

Intro.prototype.IsButtonHover = function(button, x, y) {
    return button.x <= x && x <= button.x + INTRO_BUTTON_WIDTH && button.y <= y && y <= button.y + INTRO_BUTTON_HEIGHT
}

Intro.prototype.MouseDown = function(x, y) {
    if (this.IsCrossHover(x, y)) {
        this.onClose(this.checkBox.IsChecked())
        return
    }

    if (this.checkBox.IsHover(x, y)) {
        this.checkBox.Check()
        return
    }

    for (let button of this.buttons) {
        if (button.enabled() && this.IsButtonHover(button, x, y)) {
            button.onclick()
            return
        }
    }
}

Intro.prototype.DrawCross = function(ctx, x, y) {
    ctx.strokeStyle = INTRO_CROSS_COLOR

    if (this.IsCrossHover(x, y)) {
        ctx.canvas.style.cursor = 'pointer'
        ctx.strokeStyle = INTRO_CROSS_HOVER_COLOR
    }

    ctx.beginPath()
    ctx.moveTo(this.crossX, this.crossY)
    ctx.lineTo(this.crossX + this.crossSize, this.crossY + this.crossSize)
    ctx.moveTo(this.crossX, this.crossY + this.crossSize)
    ctx.lineTo(this.crossX + this.crossSize, this.crossY)
    ctx.stroke()
}

Intro.prototype.DrawInfo = function(ctx) {
    ctx.font = INTRO_HEADER_FONT
    ctx.textAlign = 'left'
    ctx.textBaseline = 'top'

    let action = this.actions[this.actionIndex]

    ctx.fillStyle = INTRO_COLOR
    ctx.fillText(`${this.actionIndex + 1}/${this.actions.length}. ${action.header}`, this.x + INTRO_LR_PADDING, this.y + INTRO_TOP_PADDING)

    ctx.font = INTRO_TEXT_FONT
    let splited = SplitLineText(action.text, ctx, this.infoWidth)

    let y = this.y + INTRO_TOP_PADDING + INTRO_TEXT_OFFSET
    for (let line of splited.texts) {
        ctx.fillText(line, this.x + INTRO_LR_PADDING, y)
        y += INTRO_TEXT_LINE_HEIGHT
    }
}

Intro.prototype.DrawCheckBox = function(ctx, x, y) {
    ctx.font = INTRO_CHECK_BOX_FONT
    ctx.strokeStyle = INTRO_COLOR
    ctx.fillStyle = INTRO_COLOR

    this.checkBoxX = this.x + INTRO_LR_PADDING + this.infoWidth / 2
    this.checkBox.Draw(ctx, this.checkBoxX, this.checkBoxY, x, y)
}

Intro.prototype.DrawButtons = function(ctx, x, y) {
    ctx.font = INTRO_BUTTON_FONT
    ctx.textAlign = 'center'
    ctx.textBaseline = 'middle'
    ctx.lineWidth = 1

    let count = 0
    for (let button of this.buttons)
        if (button.enabled())
            count++

    let totalWidth = count * (INTRO_BUTTON_WIDTH + INTRO_BUTTONS_PADDING) - INTRO_BUTTONS_PADDING
    let startX = this.x + INTRO_LR_PADDING + this.infoWidth / 2 - totalWidth / 2

    for (let button of this.buttons) {
        if (!button.enabled())
            continue

        button.x = startX
        button.y = this.buttonsY

        let isHover = this.IsButtonHover(button, x, y)

        ctx.fillStyle = INTRO_BUTTON_BACKGROUND
        ctx.strokeStyle = INTRO_BUTTON_BORDER

        if (isHover) {
            ctx.fillStyle = INTRO_BUTTON_HOVER_BACKGROUND
            ctx.strokeStyle = INTRO_BUTTON_HOVER_BORDER
            ctx.canvas.style.cursor = 'pointer'
        }

        ctx.beginPath()
        ctx.rect(button.x, button.y, INTRO_BUTTON_WIDTH, INTRO_BUTTON_HEIGHT)
        ctx.fill()
        ctx.stroke()

        ctx.fillStyle = isHover ? INTRO_BUTTON_HOVER_COLOR : INTRO_BUTTON_COLOR
        ctx.fillText(button.text, button.x + INTRO_BUTTON_WIDTH / 2, button.y + INTRO_BUTTON_HEIGHT / 2)

        startX += INTRO_BUTTON_WIDTH + INTRO_BUTTONS_PADDING
    }
}

Intro.prototype.DrawLine = function(ctx, x1, y1, x2, y2, color) {
    ctx.strokeStyle = color
    ctx.beginPath()
    ctx.moveTo(x1, y1)
    ctx.lineTo(x2, y2)
    ctx.stroke()
}

Intro.prototype.DrawArea = function(ctx) {
    ctx.fillStyle = BACKGROUND_COLOR
    ctx.fillRect(this.areaX, this.areaY, this.areaWidth, this.areaHeight)

    ctx.lineWidth = 1

    let size = this.gridSize * 2
    let right = Math.floor(this.areaWidth / size)
    let bottom = Math.floor(this.areaHeight / size)

    for (let i = 0; i <= right; i++)
        this.DrawLine(ctx, this.areaX + i * size, this.areaY, this.areaX + i * size, this.areaY + this.areaHeight, Math.abs(i) % 5 == 0 ? MAJOR_GRID_COLOR : GRID_COLOR)

    for (let i = 0; i <= bottom; i++)
        this.DrawLine(ctx, this.areaX, this.areaY + i * size, this.areaX + this.areaWidth, this.areaY + i * size, Math.abs(i) % 5 == 0 ? MAJOR_GRID_COLOR : GRID_COLOR)
}

Intro.prototype.DrawCursor = function(ctx, tx, ty, size = 17) {
    let x = Math.floor(this.areaX + this.areaWidth * tx)
    let y = Math.floor(this.areaY + this.areaHeight * ty)

    ctx.fillStyle = '#fff'
    ctx.strokeStyle = '#000'
    ctx.lineWidth = 1
    ctx.beginPath()
    ctx.moveTo(x, y)
    ctx.lineTo(x, y + size)

    ctx.lineTo(x + size * 0.25, y + size * 0.8)
    ctx.lineTo(x + size * 0.44, y + size*1.2)
    ctx.lineTo(x + size * 0.58, y + size*1.12)

    ctx.lineTo(x + size * 0.38, y + size * 0.75)
    ctx.lineTo(x + size * 0.75, y + size * 0.75)


    ctx.closePath()
    ctx.fill()
    ctx.stroke()
}

Intro.prototype.DrawClick = function(ctx, tx, ty, count, size = 17) {
    if (count == 2) {
        ctx.font = INTRO_KEYS_FONT
        ctx.textAlign = 'center'
        ctx.textBaseline = 'top'
        ctx.fillStyle = '#2196f3'
        ctx.fillText('Двойной клик', this.areaX + this.areaWidth / 2, this.areaY + 10)
    }

    let x = Math.floor(this.areaX + this.areaWidth * tx)
    let y = Math.floor(this.areaY + this.areaHeight * ty)

    ctx.strokeStyle = '#aaa'
    ctx.beginPath()
    ctx.arc(x, y, size / 1.5 - 3, 0, Math.PI * 2)
    ctx.stroke()

    if (count == 2) {
        ctx.beginPath()
        ctx.arc(x, y, size / 1.5 + 3, 0, Math.PI * 2)
        ctx.stroke()
    }
}

Intro.prototype.DrawKeys = function(ctx, keys, pressed, padding = 5) {
    ctx.font = INTRO_KEYS_FONT
    ctx.textAlign = 'center'
    ctx.textBaseline = 'middle'
    ctx.lineWidth = 2

    let totalWidth = keys.length * (INTRO_KEYS_WIDTH + padding) - padding

    let x = this.areaX + this.areaWidth / 2 - totalWidth / 2
    let y = this.areaY + padding

    for (let i = 0; i < keys.length; i++) {
        ctx.fillStyle = pressed[i] ? INTRO_KEYS_HOVER_BACKGROUND : INTRO_KEYS_BACKGROUND
        ctx.strokeStyle = pressed[i] ? INTRO_KEYS_HOVER_BORDER : INTRO_KEYS_BORDER

        ctx.beginPath()
        ctx.rect(x, y, INTRO_KEYS_WIDTH, INTRO_KEYS_HEIGHT)
        ctx.fill()
        ctx.stroke()

        ctx.fillStyle = pressed[i] ? INTRO_KEYS_HOVER_COLOR : INTRO_KEYS_COLOR
        ctx.fillText(keys[i], x + INTRO_KEYS_WIDTH / 2, y + INTRO_KEYS_HEIGHT / 2, INTRO_KEYS_WIDTH - 4)
        x += INTRO_KEYS_WIDTH + padding
    }
}

Intro.prototype.DrawVertex = function(ctx, vertex) {
    if (vertex.isEdit) {
        this.vertex.SetText(vertex.text.substr(0, vertex.text.length - 1))
        this.vertex.StartEdit()

        if (vertex.text.length > 0) {
            this.vertex.KeyPress({ key: 'ArrowRight' })
            this.vertex.KeyPress({ key: vertex.text[vertex.text.length - 1] })
        }
    }
    else {
        this.vertex.EndEdit()
    }

    this.vertex.SetText(vertex.text)
    this.vertex.x = Math.floor(this.areaX + this.areaWidth * vertex.position.x)
    this.vertex.y = Math.floor(this.areaY + this.areaHeight * vertex.position.y)
    this.vertex.Draw(ctx, 0, 0, 1, vertex.status)
}

Intro.prototype.DrawEdge = function(ctx, edge) {
    this.edge.isDirected = edge.isDirected

    if (edge.isEdit) {
        this.edge.SetText(edge.weight.substr(0, edge.weight.length - 1))
        this.edge.StartEdit()

        if (edge.weight.length > 0) {
            this.edge.KeyPress({ key: 'ArrowRight' })
            this.edge.KeyPress({ key: edge.weight[edge.weight.length - 1] })
        }
    }
    else {
        this.edge.SetText(edge.weight)
        this.edge.EndEdit()
    }

    this.v1.x = Math.floor(this.areaX + this.areaWidth * edge.v1.position.x)
    this.v1.y = Math.floor(this.areaY + this.areaHeight * edge.v1.position.y)
    this.v1.SetText(edge.v1.text)

    this.v2.x = Math.floor(this.areaX + this.areaWidth * edge.v2.position.x)
    this.v2.y = Math.floor(this.areaY + this.areaHeight * edge.v2.position.y)
    this.v2.SetText(edge.v2.text)

    this.edge.Draw(ctx, 0, 0, 1, edge.status)
    this.v1.Draw(ctx, 0, 0, 1, COLOR_STATUS)
    this.v2.Draw(ctx, 0, 0, 1, COLOR_STATUS)
}

Intro.prototype.DrawAction = function(ctx, action) {
    let frame = action.frames[action.frameIndex]

    for (let object of frame.objects) {
        if (object.type == INTRO_CURSOR) {
            this.DrawCursor(ctx, object.position.x, object.position.y)
        }
        else if (object.type == INTRO_CLICK) {
            this.DrawClick(ctx, object.position.x, object.position.y, 1, object.size)
        }
        else if (object.type == INTRO_DOUBLE_CLICK) {
            this.DrawClick(ctx, object.position.x, object.position.y, 2, object.size)
        }
        else if (object.type == INTRO_VERTEX) {
            this.DrawVertex(ctx, object)
        }
        else if (object.type == INTRO_EDGE) {
            this.DrawEdge(ctx, object)
        }
        else if (object.type == INTRO_KEYS) {
            this.DrawKeys(ctx, object.values, object.pressed)
        }
    }

    let currTime = performance.now()

    if (currTime - this.prevTime >= frame.time) {
        if (this.prevTime > -1)
            action.frameIndex = (action.frameIndex + 1) % action.frames.length

        this.prevTime = currTime
    }
}

Intro.prototype.Draw = function(ctx, bbox, x0, y0) {
    this.width = INTRO_LR_PADDING * 3 + INTRO_AREA_MAX_WIDTH + INTRO_INFO_MAX_WIDTH
    this.height = INTRO_TOP_PADDING + INTRO_AREA_MAX_HEIGHT + INTRO_BOTTOM_PADDING

    this.areaWidth = INTRO_AREA_MAX_WIDTH
    this.areaHeight = INTRO_AREA_MAX_HEIGHT

    if (this.width > bbox.width) {
        this.areaWidth = Math.round((bbox.width - INTRO_LR_PADDING * 3) / (1 + INTRO_RATIO))
        this.width = bbox.width
    }

    if (this.height > bbox.height) {
        this.areaHeight = bbox.height - INTRO_TOP_PADDING - INTRO_BOTTOM_PADDING
        this.height = bbox.height
    }

    this.infoWidth = this.width - INTRO_LR_PADDING * 3 - this.areaWidth

    this.x = (bbox.xmin + bbox.xmax) / 2 - this.width / 2
    this.y = (bbox.ymin + bbox.ymax) / 2 - this.height / 2

    this.areaX = this.x + INTRO_LR_PADDING * 2 + this.infoWidth
    this.areaY = this.y + INTRO_TOP_PADDING

    this.crossX = this.x + this.width - this.crossSize - INTRO_LR_PADDING
    this.crossY = this.y + INTRO_TOP_PADDING / 2 - this.crossSize / 2

    this.buttonsY = this.y + this.height - INTRO_BOTTOM_PADDING - INTRO_BUTTON_HEIGHT
    this.checkBoxY = this.buttonsY - 10 - INTRO_CHECK_BOX_SIZE

    ctx.fillStyle = INTRO_BACKGROUND
    ctx.fillRect(this.x, this.y, this.width, this.height)

    this.DrawCross(ctx, x0, y0)
    this.DrawInfo(ctx)
    this.DrawCheckBox(ctx, x0, y0)
    this.DrawButtons(ctx, x0, y0)
    this.DrawArea(ctx)
    this.DrawAction(ctx, this.actions[this.actionIndex])
}
