function BezierCurve(x1, y1, x2, y2, x3, y3, arrow = null, eps = 1e-4) {
    this.p1 = {x: x1, y: y1}
    this.p2 = {x: x2, y: y2}
    this.p3 = {x: x3, y: y3}
    this.eps = eps
    this.arrow = arrow

    let tmax = 1

    if (arrow != null) {
        tmax = this.GetArrowPoint(arrow.distance + arrow.offset, this.eps)
        this.arrowPoint = this.GetPoint(tmax)

        let dx = this.p3.x - this.arrowPoint.x
        let dy = this.p3.y - this.arrowPoint.y

        this.angle = Math.atan2(dy, dx)
    }

    this.points = this.GetPoints(tmax)
}

// получение точки
BezierCurve.prototype.GetPoint = function(t) {
    let x = (1 - t) * (1 - t) * this.p1.x + 2*t*(1 - t) * this.p2.x + t*t * this.p3.x
    let y = (1 - t) * (1 - t) * this.p1.y + 2*t*(1 - t) * this.p2.y + t*t * this.p3.y

    return { x: x, y: y }
}

// получение ограничивающего прямоугольника
BezierCurve.prototype.GetBoundingBox = function() {
    let denx = this.p1.x - 2 * this.p2.x + this.p3.x
    let deny = this.p1.y - 2 * this.p2.y + this.p3.y

    let tx = Math.abs(denx) < this.eps ? 0.5 : Math.max(0, Math.min(1, (this.p1.x - this.p2.x) / denx))
    let ty = Math.abs(deny) < this.eps ? 0.5 : Math.max(0, Math.min(1, (this.p1.y - this.p2.y) / deny))

    let xc = (1 - tx) * (1 - tx) * this.p1.x + 2*tx*(1 - tx) * this.p2.x + tx*tx * this.p3.x
    let yc = (1 - ty) * (1 - ty) * this.p1.y + 2*ty*(1 - ty) * this.p2.y + ty*ty * this.p3.y

    let points = [
        { x: this.p1.x, y: this.p1.y },
        { x: xc, y: yc },
        { x: this.p3.x, y: this.p3.y }
    ]

    let bbox = {
        xmin: Infinity,
        ymin: Infinity,
        xmax: -Infinity,
        ymax: -Infinity
    }

    for (let p of points) {
        bbox.xmin = Math.min(bbox.xmin, Math.round(p.x / GRID_SIZE) * GRID_SIZE)
        bbox.ymin = Math.min(bbox.ymin, Math.round(p.y / GRID_SIZE) * GRID_SIZE)

        bbox.xmax = Math.max(bbox.xmax, Math.round(p.x / GRID_SIZE) * GRID_SIZE)
        bbox.ymax = Math.max(bbox.ymax, Math.round(p.y / GRID_SIZE) * GRID_SIZE)
    }

    return bbox
}

// получение расстояния между двумя точками
BezierCurve.prototype.GetPointDistance = function(p1, p2) {
    let dx = p1.x - p2.x
    let dy = p1.y - p2.y

    return Math.sqrt(dx*dx + dy*dy)
}

// получение расстояния от точки до окружности
BezierCurve.prototype.GetCircleDistance = function(p, center, radius) {
    return Math.abs(this.GetPointDistance(p, center) - radius)
}

// поиск расстояние от точки до кривой Безье
BezierCurve.prototype.GetDistance = function(p) {
    let a = 0
    let b = 1

    while (Math.abs(b - a) > this.eps) {
        let t = (a + b) / 2
        let f1 = this.GetPointDistance(this.GetPoint(t - this.eps), p)
        let f2 = this.GetPointDistance(this.GetPoint(t + this.eps), p)

        if (f1 >= f2)
            a = t
        else
            b = t
    }

    return this.GetPointDistance(this.GetPoint((a + b) / 2), p)
}

// поиск точки для отрисовки стрелки
BezierCurve.prototype.GetArrowPoint = function(radius) {
    let a = 0
    let b = 1

    while (Math.abs(b - a) > this.eps) {
        let t = (a + b) / 2
        let f1 = this.GetCircleDistance(this.GetPoint(t - this.eps), this.p3, radius)
        let f2 = this.GetCircleDistance(this.GetPoint(t + this.eps), this.p3, radius)

        if (f1 >= f2)
            a = t
        else
            b = t
    }

    return (a + b) / 2
}

BezierCurve.prototype.SplitLine = function(t1, t2, p1, p2, eps) {
    if (t2 - t1 < eps)
        return [p1, p2]

    let t = (t1 + t2) / 2
    let p = this.GetPoint(t)

    let dx1 = p.x - p1.x
    let dy1 = p.y - p1.y
    let norm1 = dx1*dx1 + dy1*dy1

    let dx2 = p2.x - p.x
    let dy2 = p2.y - p.y
    let norm2 = dx2*dx2 + dy2*dy2

    if (Math.abs((dx1 * dx2 + dy1 * dy2) - Math.sqrt(norm1 * norm2)) < eps)
        return [p1, p2]

    let left = this.SplitLine(t1, t, p1, p, eps)
    let right = this.SplitLine(t, t2, p, p2, eps)
    left.pop()

    return [...left, ...right]
}

BezierCurve.prototype.GetPoints = function(tmax) {
    return this.SplitLine(0, tmax, this.p1, this.GetPoint(tmax), 0.025)
}

// отрисовка стрелки
BezierCurve.prototype.DrawArrow = function(ctx, x0, y0, scale, needStroke) {
    ctx.save()
    ctx.translate(x0 + this.arrowPoint.x * scale, y0 + this.arrowPoint.y * scale)
    ctx.rotate(this.angle)

    ctx.beginPath()
    ctx.moveTo((this.arrow.offset - this.arrow.dy) * scale, -this.arrow.dx * scale)
    ctx.lineTo(this.arrow.offset * scale, 0)
    ctx.lineTo((this.arrow.offset - this.arrow.dy) * scale, this.arrow.dx * scale)
    ctx.closePath()
    ctx.fill()

    if (needStroke) {
        ctx.lineWidth = this.arrow.strokeWidth * scale
        ctx.stroke()
    }

    ctx.restore()
}

BezierCurve.prototype.Draw = function(ctx, x0, y0, scale, needStroke = false) {
    ctx.beginPath()
    ctx.moveTo(x0 + this.points[0].x * scale, y0 + this.points[0].y * scale)

    for (let i = 1; i < this.points.length; i++)
        ctx.lineTo(x0 + this.points[i].x * scale, y0 + this.points[i].y * scale)

    ctx.stroke()

    if (this.arrow != null)
        this.DrawArrow(ctx, x0, y0, scale, needStroke)
}

BezierCurve.prototype.ToSVG = function(lineWidth, color) {
    let svg = `    <path d="M ${this.points.map((p) => p.x + " " + p.y).join("L ")}" fill="none" stroke="${color}" stroke-width="${lineWidth}"></path>\n`

    if (this.arrow != null)
        svg += `    <path transform="translate(${this.arrowPoint.x} ${this.arrowPoint.y}) rotate(${this.angle / Math.PI * 180})" d="M${-this.arrow.dy + this.arrow.offset}, ${-this.arrow.dx} L ${this.arrow.offset} 0 L ${-this.arrow.dy + this.arrow.offset}, ${this.arrow.dx} z" fill="${color}"></path>\n`

    return svg
}
