function Animation(name, isLooped = false) {
    this.actions = []
    this.index = 0
    this.prevTime = 0
    this.name = name
    this.isLooped = isLooped
    this.isStopped = false
    this.speeds = [0.2, 0.5, 1, 2, 3, 5, 10, 25, 50, 100, 500]
    this.speedIndex = this.speeds.indexOf(1)

    this.saveInfo = null
}

// добавление действия
Animation.prototype.AddAction = function(name, args, time = 20) {
    this.actions.push({ name: name, args: args, time: time })
}

// запуск
Animation.prototype.Start = function() {
    this.index = 0
    this.Play()
}

// остановка
Animation.prototype.Stop = function() {
    this.isStopped = true
}

// можно ли назад
Animation.prototype.CanPrev = function() {
    return this.index > 0
}

// можно ли вперёд
Animation.prototype.CanNext = function() {
    return this.index < this.actions.length - 1
}

// переход на предыдущий кадр
Animation.prototype.Prev = function() {
    this.Stop()
    this.index = Math.max(this.index - 1, 0)
}

// переход на следующий кадр
Animation.prototype.Next = function() {
    this.Stop()
    this.index = Math.min(this.index + 1, this.actions.length - 1)
}

// переход в начало
Animation.prototype.Begin = function() {
    this.Stop()
    this.index = 0
}

// переход в конец
Animation.prototype.End = function() {
    this.Stop()
    this.index = this.actions.length - 1
}

// запуск с текущего места
Animation.prototype.Play = function() {
    if (this.index == this.actions.length - 1) {
        this.index = 0
    }

    this.prevTime = performance.now()
    this.isStopped = false
}

// изменение скорости анимации
Animation.prototype.ChangeSpeed = function(step) {
    if (!this.CanChangeSpeed(step))
        return

    this.speedIndex += step
}

// можно ли изменить скорость анимации
Animation.prototype.CanChangeSpeed = function(step) {
    return 0 <= this.speedIndex + step && this.speedIndex + step < this.speeds.length
}

// можно ли сохранять анимацию
Animation.prototype.CanSave = function(){
    return this.saveInfo != null
}

// получение скорости
Animation.prototype.GetSpeed = function() {
    return this.speeds[this.speedIndex]
}

// получение кадра анимации
Animation.prototype.GetAction = function() {
    return this.actions[this.index]
}

// вычисление максимальной координаты текстовой метки
Animation.prototype.GetActionMaxLabelCoordinate = function(action) {
    let xmax = -Infinity

    if (action.name != ANIMATE_GRAPH || !action.args.labels)
        return xmax

    let args = action.args

    for (let i = 0; i < args.vertices.length; i++) {
        let x = (args.vertices[i].x + args.vertices[i].radius)

        for (let line of args.labels[i].split('\n'))
            xmax = Math.max(xmax, x + line.length * (VERTEX_FONT_SIZE - 2) / 1.8)
    }

    return xmax
}

// установка информации для сохранения
Animation.prototype.SetSaveInfo = function(info) {
    this.saveInfo = info
}

Animation.prototype.GetSaveInfo = function() {
    return this.saveInfo
}

Animation.prototype.InitCanvas = function(bbox, scale) {
    let canvas = document.createElement('canvas')
    let ctx = canvas.getContext('2d')

    let paddingTop = ANIMATION_TEXT_FONT_SIZE * 3
    let paddingRight = 0

    for (let action of this.actions)
        paddingRight = Math.max(paddingRight, this.GetActionMaxLabelCoordinate(action))

    if (paddingRight > 0)
        paddingRight = (paddingRight - bbox.xmax + GRID_SIZE) * scale

    canvas.width = Math.round((bbox.xmax - bbox.xmin) * scale + paddingRight)
    canvas.height = Math.round((bbox.ymax - bbox.ymin) * scale + paddingTop)

    let x = (bbox.xmin + bbox.xmax) / 2
    let y = (bbox.ymin + bbox.ymax) / 2
    let x0 = (canvas.width - paddingRight) / 2 - x * scale
    let y0 = paddingTop + (canvas.height - paddingTop) / 2 - y * scale

    return { canvas, ctx, x0, y0 }
}

// рисуется ли объект в текущем кадре анимации
Animation.prototype.IsDrawing = function(object, action = null) {
    if (action == null)
        action = this.actions[this.index]

    if (action.name == ANIMATE_GRAPH) {
        for (let vertex of action.args.vertices)
            if (vertex == object)
                return true

        for (let edge of action.args.edges)
            if (edge == object)
                return true

        return false
    }

    return false
}

// отрисовка действия
Animation.prototype.DrawAction = function(action, ctx, x0, y0, scale, x, y, width) {
    let args = action.args

    if (action.name == ANIMATE_GRAPH) {
        for (let i = 0; i < args.edges.length; i++) {
            if (args.edgeLabels) {
                let text = args.edges[i].GetText()
                args.edges[i].SetText(args.edgeLabels[i])
                args.edges[i].Draw(ctx, x0, y0, scale, args.edgeStatuses ? args.edgeStatuses[i] : ANIMATED_STATUS)
                args.edges[i].SetText(text)
            }
            else {
                args.edges[i].Draw(ctx, x0, y0, scale, args.edgeStatuses ? args.edgeStatuses[i] : ANIMATED_STATUS)
            }
        }

        for (let i = 0; i < args.vertices.length; i++) {
            let status = args.statuses ? args.statuses[i] : ANIMATED_STATUS

            if (status == HSL_STATUS) {
                let maxColor = Math.max.apply(null, args.colors) + 1
                let part = maxColor < 12 ? args.colors[i] * 30 : args.colors[i] / maxColor * 360
                let color = `hsl(${part}, 100%, 80%)`
                args.vertices[i].Draw(ctx, x0, y0, scale, status, color)
            }
            else {
                args.vertices[i].Draw(ctx, x0, y0, scale, status)
            }

            if (args.labels) {
                let x = x0 + (args.vertices[i].x + args.vertices[i].radius) * scale
                let y = y0 + (args.vertices[i].y - args.vertices[i].radius - GRID_SIZE) * scale
                let text = args.labels[i]

                if (text != '') {
                    ctx.textAlign = 'left'
                    this.DrawText(ctx, x, y, args.vertices[i].radius * 8 * scale, text, (VERTEX_FONT_SIZE - 2) * scale, VERTEX_FONT)
                }
            }
        }
    }
    else if (action.name == ANIMATE_INPUT) {
        args.input.Draw(ctx, x0, y0, scale, -1, -1, canvas)
    }

    if (args.text != '') {
        ctx.textAlign = 'center'
        this.DrawText(ctx, x, y, width, args.text, ANIMATION_TEXT_FONT_SIZE, ANIMATION_TEXT_FONT)
    }
}

// отрисовка текста
Animation.prototype.DrawText = function(ctx, x, y, maxWidth, text, size, font) {
    ctx.textBaseline = 'top'
    ctx.font = size + font
    ctx.fillStyle = ANIMATION_TEXT_BACKGROUND_COLOR

    let lines = text.split('\n')
    let splitedAll = { texts: [], width: 0 }

    for (line of lines) {
        let splited = SplitText(line, ctx, maxWidth)
        splitedAll.texts = splitedAll.texts.concat(splited.texts)
        splitedAll.width = Math.max(splitedAll.width, splited.width)
    }

    let height = splitedAll.texts.length * size
    let dx = 0

    if (ctx.textAlign == 'center') {
        dx = -splitedAll.width / 2
    }
    else if (ctx.textAlign == 'right') {
        dx = -splitedAll.width
    }

    ctx.beginPath()
    ctx.fillRect(x + dx - ANIMATION_TEXT_PADDING, y - ANIMATION_TEXT_PADDING, splitedAll.width + ANIMATION_TEXT_PADDING * 2, height + ANIMATION_TEXT_PADDING * 2)

    ctx.fillStyle = ANIMATION_TEXT_COLOR

    for (let i = 0; i < splitedAll.texts.length; i++) {
        ctx.fillText(splitedAll.texts[i], x, y + i * size)
    }
}

// отрисовка анимаций
Animation.prototype.Draw = function(ctx, x0, y0, scale, x, y, width) {
    this.DrawAction(this.actions[this.index], ctx, x0, y0, scale, x, y, width)

    let time = performance.now()
    let needUpdate = (time - this.prevTime) * this.GetSpeed() >= this.actions[this.index].time

    if (needUpdate && !this.isStopped) {
        if (this.isLooped) {
            this.index = (this.index + 1) % this.actions.length
        }
        else {
            if (this.index == this.actions.length - 1)
                this.isStopped = true

            this.index = Math.min(this.actions.length - 1, this.index + 1)
        }

        this.prevTime = time
    }
}

// отрисовка информации о скорости
Animation.prototype.DrawInfo = function(ctx, width, height) {
    ctx.fillStyle = INFO_TEXT_COLOR
    ctx.font = '15px sans-serif'
    ctx.textAlign = 'center'
    ctx.textBaseline = 'middle'
    ctx.fillText(this.GetSpeed() + 'x', width - 230, height - 12)
}
