function RandomGraphForm() {
    this.crossSize = RANDOM_GRAPH_FORM_HEADER_HEIGHT / 2.5
    this.fontSize = 18
    this.onClose = () => false
    this.onGenerate = () => false

    this.verticesText = new TextField("5", this.fontSize, RANDOM_GRAPH_FORM_FONT, true, RANDOM_GRAPH_FORM_MAX_VERTICES_TEXT_LENGTH)
    this.edgesText = new TextField("9", this.fontSize, RANDOM_GRAPH_FORM_FONT, true, RANDOM_GRAPH_FORM_MAX_EDGES_TEXT_LENGTH)
    this.isWeighted = new CheckBox('Взвешенный граф', RANDOM_GRAPH_FORM_CHECK_BOX_SIZE)
    this.isDirected = new CheckBox('Ориентированный граф', RANDOM_GRAPH_FORM_CHECK_BOX_SIZE)
    this.editBlock = ''
}

RandomGraphForm.prototype.IsEdit = function() {
    return this.editBlock != ''
}

// обработка нажатия клавишы
RandomGraphForm.prototype.KeyPress = function(key) {
    if (this.editBlock == '' || key.code == 'Minus')
        return

    let textBox = this.editBlock == 'vertices' ? this.verticesText : this.edgesText

    if (key.code == 'ArrowUp') {
        textBox.IncrementNumber()
    }
    else if (key.code == 'ArrowDown') {
        textBox.IncrementNumber(-1, 0)
    }
    else {
        textBox.KeyPress(key)
    }
}

RandomGraphForm.prototype.IsCrossHover = function(x, y) {
    return this.crossX <= x && x <= this.crossX + this.crossSize && this.crossY <= y && y <= this.crossY + this.crossSize
}

RandomGraphForm.prototype.IsVericesTextHover = function(x, y) {
    return this.verticesTextX <= x && x <= this.verticesTextX + this.verticesTextWidth && this.verticesY - this.fontSize / 2 <= y && y <= this.verticesY + this.fontSize / 2
}

RandomGraphForm.prototype.IsEdgesTextHover = function(x, y) {
    return this.edgesTextX <= x && x <= this.edgesTextX + this.edgesTextWidth && this.edgesY - this.fontSize / 2 <= y && y <= this.edgesY + this.fontSize / 2
}

RandomGraphForm.prototype.IsButtonHover = function(x, y) {
    return this.buttonX <= x && x <= this.buttonX + RANDOM_GRAPH_FORM_BUTTON_WIDTH && this.buttonY <= y && y <= this.buttonY + RANDOM_GRAPH_FORM_BUTTON_HEIGHT
}

RandomGraphForm.prototype.MouseDown = function(ctx, x, y, shiftKey) {
    if (this.IsCrossHover(x, y)) {
        this.onClose()
        return true
    }

    this.editBlock = ''

    if (this.IsVericesTextHover(x, y)) {
        this.editBlock = 'vertices'
        this.verticesText.SetCursorPosition(ctx, x - this.verticesTextX, false, shiftKey ? 'shift' : 'clear')
        return
    }

    if (this.IsEdgesTextHover(x, y)) {
        this.editBlock = 'edges'
        this.edgesText.SetCursorPosition(ctx, x - this.edgesTextX, false, shiftKey ? 'shift' : 'clear')
        return
    }

    if (this.isWeighted.IsHover(x, y)) {
        this.isWeighted.Check()
        return
    }

    if (this.isDirected.IsHover(x, y)) {
        this.isDirected.Check()
        return
    }

    if (this.IsButtonHover(x, y)) {
        let vertices = +this.verticesText.GetText()
        let edges = +this.edgesText.GetText()
        let isWeighted = this.isWeighted.IsChecked()
        let isDirected = this.isDirected.IsChecked()

        this.onGenerate(vertices, edges, isWeighted, isDirected)
    }
}

RandomGraphForm.prototype.MouseMove = function(ctx, x, y, dx, dy) {
    if (this.editBlock == '')
        return

    let textBox = this.editBlock == 'vertices' ? this.verticesText : this.edgesText
    let x0 = this.editBlock == 'vertices' ? this.verticesTextX : this.edgesTextX

    if (!textBox.HaveSelection())
        textBox.StartSelection()

    textBox.SetCursorPosition(ctx, x + dx - x0, false)
    textBox.EndSelection()
}

RandomGraphForm.prototype.DrawHeader = function(ctx) {
    ctx.font = `${RANDOM_GRAPH_FORM_HEADER_HEIGHT / 2}${RANDOM_GRAPH_FORM_FONT}`
    ctx.textAlign = 'left'
    ctx.textBaseline = 'middle'

    ctx.fillStyle = RANDOM_GRAPH_FORM_HEADER_BACKGROUND
    ctx.fillRect(this.x, this.y, this.width, RANDOM_GRAPH_FORM_HEADER_HEIGHT)

    ctx.fillStyle = RANDOM_GRAPH_FORM_HEADER_COLOR
    ctx.fillText('Параметры случайного графа', this.x + RANDOM_GRAPH_FORM_PADDING, this.y + RANDOM_GRAPH_FORM_HEADER_HEIGHT / 2)
}

RandomGraphForm.prototype.DrawCross = function(ctx, x, y) {
    ctx.strokeStyle = RANDOM_GRAPH_FORM_CROSS_COLOR

    if (this.IsCrossHover(x, y)) {
        ctx.canvas.style.cursor = 'pointer'
        ctx.strokeStyle = RANDOM_GRAPH_FORM_CROSS_HOVER_COLOR
    }

    ctx.beginPath()
    ctx.moveTo(this.crossX, this.crossY)
    ctx.lineTo(this.crossX + this.crossSize, this.crossY + this.crossSize)
    ctx.moveTo(this.crossX, this.crossY + this.crossSize)
    ctx.lineTo(this.crossX + this.crossSize, this.crossY)
    ctx.stroke()
}

RandomGraphForm.prototype.DrawVertices = function(ctx, x, y) {
    ctx.font = `${this.fontSize}${RANDOM_GRAPH_FORM_FONT}`
    ctx.fillStyle = RANDOM_GRAPH_FORM_COLOR
    ctx.strokeStyle = RANDOM_GRAPH_FORM_COLOR
    ctx.lineWidth = 1

    let text = 'Количество вершин:'
    let width = ctx.measureText(text).width
    ctx.fillText(text, this.verticesX, this.verticesY)

    this.verticesTextX = this.verticesX + width + 5
    this.verticesText.fontSize = this.fontSize
    this.verticesTextWidth = Math.max(20, this.verticesText.GetLineWidth(ctx, this.fontSize))

    let isEdit = this.editBlock == 'vertices'
    let isHover = this.IsVericesTextHover(x, y)

    this.verticesText.Draw(ctx, this.verticesTextX, this.verticesY, 1, isEdit)

    if (isHover)
        ctx.canvas.style.cursor = isEdit ? 'text' : 'pointer'

    if (isHover || isEdit)
        ctx.strokeStyle = RANDOM_GRAPH_FORM_BORDER_HOVER

    ctx.lineWidth = 1
    ctx.beginPath()
    ctx.moveTo(this.verticesTextX, this.verticesY + this.fontSize / 2)
    ctx.lineTo(this.verticesTextX + this.verticesTextWidth, this.verticesY + this.fontSize / 2)
    ctx.stroke()
}

RandomGraphForm.prototype.DrawEdges = function(ctx, x, y) {
    ctx.font = `${this.fontSize}${RANDOM_GRAPH_FORM_FONT}`
    ctx.fillStyle = RANDOM_GRAPH_FORM_COLOR
    ctx.strokeStyle = RANDOM_GRAPH_FORM_COLOR
    ctx.lineWidth = 1

    let text = 'Количество рёбер:'
    let width = ctx.measureText(text).width
    ctx.fillText(text, this.edgesX, this.edgesY)

    this.edgesTextX = this.edgesX + width + 5
    this.edgesText.fontSize = this.fontSize
    this.edgesTextWidth = Math.max(20, this.edgesText.GetLineWidth(ctx, this.fontSize))

    let isEdit = this.editBlock == 'edges'
    let isHover = this.IsEdgesTextHover(x, y)

    this.edgesText.Draw(ctx, this.edgesTextX, this.edgesY, 1, isEdit)

    if (isHover)
        ctx.canvas.style.cursor = isEdit ? 'text' : 'pointer'

    if (isHover || isEdit)
        ctx.strokeStyle = RANDOM_GRAPH_FORM_BORDER_HOVER

    ctx.lineWidth = 1
    ctx.beginPath()
    ctx.moveTo(this.edgesTextX, this.edgesY + this.fontSize / 2)
    ctx.lineTo(this.edgesTextX + this.edgesTextWidth, this.edgesY + this.fontSize / 2)
    ctx.stroke()
}

RandomGraphForm.prototype.DrawButton = function(ctx, x, y) {
    let isHover = this.IsButtonHover(x, y)
    ctx.fillStyle = RANDOM_GRAPH_FORM_BUTTON_BACKGROUND
    ctx.strokeStyle = RANDOM_GRAPH_FORM_BUTTON_BORDER
    ctx.textAlign = 'center'
    ctx.lineWidth = 1

    if (isHover) {
        ctx.fillStyle = RANDOM_GRAPH_FORM_BUTTON_HOVER_BACKGROUND
        ctx.strokeStyle = RANDOM_GRAPH_FORM_BUTTON_HOVER_BORDER
        ctx.canvas.style.cursor = 'pointer'
    }

    ctx.beginPath()
    ctx.rect(this.buttonX, this.buttonY, RANDOM_GRAPH_FORM_BUTTON_WIDTH, RANDOM_GRAPH_FORM_BUTTON_HEIGHT)
    ctx.fill()
    ctx.stroke()

    ctx.fillStyle = isHover ? RANDOM_GRAPH_FORM_BUTTON_HOVER_COLOR : RANDOM_GRAPH_FORM_BUTTON_COLOR
    ctx.fillText('Сгенерировать', this.buttonX + RANDOM_GRAPH_FORM_BUTTON_WIDTH / 2, this.buttonY + RANDOM_GRAPH_FORM_BUTTON_HEIGHT / 2)
}

RandomGraphForm.prototype.DrawCheckBoxes = function(ctx, x, y) {
    let isWeightedY = this.edgesY + this.fontSize * 1.2
    let isDirectedY = isWeightedY + RANDOM_GRAPH_FORM_CHECK_BOX_SIZE * 1.8

    ctx.strokeStyle = RANDOM_GRAPH_FORM_COLOR
    ctx.fillStyle = RANDOM_GRAPH_FORM_COLOR
    this.isWeighted.Draw(ctx, this.x + RANDOM_GRAPH_FORM_PADDING, isWeightedY, x, y)
    this.isDirected.Draw(ctx, this.x + RANDOM_GRAPH_FORM_PADDING, isDirectedY, x, y)
}

RandomGraphForm.prototype.Draw = function(ctx, bbox, mx, my) {
    this.width = Math.min(RANDOM_GRAPH_FORM_WIDTH, bbox.width)
    this.height = Math.min(RANDOM_GRAPH_FORM_HEIGHT, bbox.height)
    this.x = (bbox.xmin + bbox.xmax - this.width) / 2
    this.y = (bbox.ymin + bbox.ymax - this.height) / 2

    this.crossX = this.x + this.width - this.crossSize - RANDOM_GRAPH_FORM_PADDING
    this.crossY = this.y + RANDOM_GRAPH_FORM_HEADER_HEIGHT / 2 - this.crossSize / 2

    this.verticesX = this.x + RANDOM_GRAPH_FORM_PADDING
    this.verticesY = this.y + RANDOM_GRAPH_FORM_HEADER_HEIGHT + RANDOM_GRAPH_FORM_TOP_PADDING

    this.edgesX = this.x + RANDOM_GRAPH_FORM_PADDING
    this.edgesY = this.verticesY + this.fontSize * 1.5

    this.buttonX = this.x + this.width / 2 - RANDOM_GRAPH_FORM_BUTTON_WIDTH / 2
    this.buttonY = this.y + this.height - RANDOM_GRAPH_FORM_PADDING - RANDOM_GRAPH_FORM_BUTTON_HEIGHT

    ctx.fillStyle = RANDOM_GRAPH_FORM_BACKGROUND
    ctx.strokeStyle = RANDOM_GRAPH_FORM_BORDER
    ctx.lineWidth = 1

    ctx.beginPath()
    ctx.rect(this.x, this.y, this.width, this.height)
    ctx.fill()
    ctx.stroke()

    this.DrawHeader(ctx)
    this.DrawCross(ctx, mx, my)
    this.DrawVertices(ctx, mx, my)
    this.DrawEdges(ctx, mx, my)
    this.DrawCheckBoxes(ctx, mx, my)
    this.DrawButton(ctx, mx, my)
}
