function SettingsForm() {
    this.sections = []
    this.onClose = () => true
    this.onApplyAll = () => true
    this.editSetting = null
    this.viewSection = 0

    this.leftBtn = new Button('❰', SETTINGS_ICON_STYLE, 0, 0, SETTINGS_ICON_WIDTH, SETTINGS_SECTION_HEIGHT, () => this.PrevSection())
    this.rightBtn = new Button('❱', SETTINGS_ICON_STYLE, 0, 0, SETTINGS_ICON_WIDTH, SETTINGS_SECTION_HEIGHT, () => this.NextSection())

    this.applyCheckBox = new CheckBox('Применить ко всему графу', SETTINGS_CHECKBOX_SIZE, true)

    this.buttons = []
    this.buttons.push(new Button('Отменить', SETTINGS_BUTTON_STYLE, 0, 0, SETTINGS_BUTTON_WIDTH, SETTINGS_BUTTON_HEIGHT, () => { this.Reset(); this.Close() }))
    this.buttons.push(new Button('Сбросить', SETTINGS_BUTTON_STYLE, 0, 0, SETTINGS_BUTTON_WIDTH, SETTINGS_BUTTON_HEIGHT, () => { settings.Reset(); this.Reset(); this.Close(true) }))
    this.buttons.push(new Button('Сохранить', SETTINGS_BUTTON_STYLE, 0, 0, SETTINGS_BUTTON_WIDTH, SETTINGS_BUTTON_HEIGHT, () => { this.Save(); this.Close(true) }))

    this.vertex = new Vertex(0.5, 0.5, '1')
    this.v1 = new Vertex(0, 0, '')
    this.v2 = new Vertex(0, 0, '')
    this.edge = new Edge(this.v1, this.v2, '', false)
    this.text = new Text(0.5, 0.5, 'text')
}

SettingsForm.prototype.AddSection = function(name, objects) {
    this.sections.push({ name: name, settings: [], x: 0, y: 0, objects: objects })
}

SettingsForm.prototype.AddNumberSetting = function(name, getValue, setValue, min = -Infinity, max = Infinity) {
    let section = this.sections[this.sections.length - 1]

    section.settings.push({
        name: `${name}:`,
        type: SETTING_NUMBER,
        getValue: getValue,
        setValue: setValue,
        min: min,
        max: max,
        textBox: new TextField(`${getValue()}`, SETTINGS_ITEM_FONT_SIZE, SETTINGS_ITEM_FONT, true, 3)
    })
}

SettingsForm.prototype.AddColorSetting = function(name, getColor, setColor) {
    let section = this.sections[this.sections.length - 1]
    let setting = { 
        name: `${name}:`,
        type: SETTING_COLOR,
        getValue: getColor,
        setValue: setColor,
        colorPicker: new ColorPicker(
            name,
            (color) => true,
            () => {this.editSetting.colorPicker.color = this.editSetting.colorPicker.prevColor; this.editSetting = null },
            () => {this.editSetting = null },
            'Применить'
        )
    }

    setting.colorPicker.SetColor(getColor())
    section.settings.push(setting)
}

SettingsForm.prototype.PrevSection = function() {
    this.viewSection = (this.viewSection - 1 + this.sections.length) % this.sections.length
}

SettingsForm.prototype.NextSection = function() {
    this.viewSection = (this.viewSection + 1) % this.sections.length
}

SettingsForm.prototype.IsEdit = function() {
    return this.editSetting != null && this.editSetting.type == SETTING_NUMBER
}

SettingsForm.prototype.IsColor = function() {
    return this.editSetting != null && this.editSetting.type == SETTING_COLOR
}

SettingsForm.prototype.IsCrossHover = function(x, y) {
    return this.crossX <= x && x <= this.crossX + SETTINGS_CROSS_SIZE && this.crossY <= y && y <= this.crossY + SETTINGS_CROSS_SIZE
}

SettingsForm.prototype.IsSettingHover = function(setting, x, y) {
    return setting.x <= x && x <= setting.x + setting.width && setting.y <= y && y <= setting.y + setting.height
}

SettingsForm.prototype.GetSectionMaxHeight = function() {
    let imax = 0

    for (let i = 1; i < this.sections.length; i++)
        if (this.sections[i].settings.length > this.sections[imax].settings.length)
            imax = i

    return this.sections[imax].settings.length * SETTINGS_ITEM_HEIGHT
}

SettingsForm.prototype.FixLimits = function(setting) {
    let min = setting.min
    let max = setting.max
    let value = +setting.textBox.GetText()

    setting.textBox.SetText(`${Math.min(max, Math.max(min, value))}`)
}

SettingsForm.prototype.Reset = function() {
    for (let section of this.sections) {
        for (let setting of section.settings) {
            if (setting.type == SETTING_NUMBER) {
                setting.textBox.SetText(`${setting.getValue()}`)
            }
            else if (setting.type == SETTING_COLOR) {
                setting.colorPicker.SetColor(`${setting.getValue()}`)
            }
        }
    }
}

SettingsForm.prototype.Save = function() {
    for (let section of this.sections) {
        for (let setting of section.settings) {
            if (setting.type == SETTING_NUMBER) {
                setting.setValue(+setting.textBox.GetText())
            }
            else if (setting.type == SETTING_COLOR) {
                setting.setValue(setting.colorPicker.color)
            }
        }
    }
}

SettingsForm.prototype.Close = function(needApply = false) {
    this.viewSection = 0

    if (needApply && this.applyCheckBox.IsChecked())
        this.onApplyAll()

    this.onClose()
}

SettingsForm.prototype.MouseDown = function(ctx, x, y, shiftKey) {
    if (this.IsColor() && this.editSetting.colorPicker.IsMouseHover(x, y)) {
        this.editSetting.colorPicker.MouseDown(x, y)
        return
    }

    if (this.IsEdit())
        this.FixLimits(this.editSetting)

    this.editSetting = null

    if (this.IsCrossHover(x, y)) {
        this.Close()
        return
    }

    for (let setting of this.sections[this.viewSection].settings) {
        if (!this.IsSettingHover(setting, x, y))
            continue

        if (setting.type == SETTING_COLOR) {
            setting.colorPicker.SetColor(setting.colorPicker.color)
        }
        else if (setting.type == SETTING_NUMBER) {
            setting.textBox.SetCursorPosition(ctx, x - setting.x, false, shiftKey ? 'shift' : 'clear')
        }

        this.editSetting = setting
        return
    }

    if (this.applyCheckBox.IsHover(x, y)) {
        this.applyCheckBox.Check()
        return
    }

    for (let button of this.buttons)
        if (button.MouseDown(x, y))
            return

    this.leftBtn.MouseDown(x, y)
    this.rightBtn.MouseDown(x, y)
}

SettingsForm.prototype.MouseMove = function(ctx, x, y, dx, dy) {
    if (this.IsColor()) {
        this.editSetting.colorPicker.MouseMove(x, y, dx, dy)
    }
    else if (this.IsEdit()) {
        if (!this.editSetting.textBox.HaveSelection())
            this.editSetting.textBox.StartSelection()

        this.editSetting.textBox.SetCursorPosition(ctx, x + dx - this.editSetting.x, false)
        this.editSetting.textBox.EndSelection()
    }
}

SettingsForm.prototype.KeyPress = function(key) {
    let textBox = this.editSetting.textBox

    if (key.code == 'ArrowUp') {
        textBox.IncrementNumber(1, this.editSetting.min, this.editSetting.max)
    }
    else if (key.code == 'ArrowDown') {
        textBox.IncrementNumber(-1, this.editSetting.min, this.editSetting.max)
    }
    else {
        textBox.KeyPress(key)
    }
}

SettingsForm.prototype.DrawBackground = function(ctx) {
    ctx.strokeStyle = SETTINGS_BORDER
    ctx.fillStyle = SETTINGS_BACKGROUND
    ctx.lineWidth = 1

    ctx.beginPath()
    ctx.rect(this.x, this.y, this.width, this.height)
    ctx.fill()
    ctx.stroke()
}

SettingsForm.prototype.DrawHeader = function(ctx) {
    ctx.font = SETTINGS_HEADER_FONT
    ctx.textAlign = 'left'
    ctx.textBaseline = 'middle'

    ctx.fillStyle = SETTINGS_HEADER_BACKGROUND
    ctx.fillRect(this.x, this.y, this.width, SETTINGS_HEADER_HEIGHT)

    ctx.fillStyle = SETTINGS_HEADER_COLOR
    ctx.fillText('Настройки редактора', this.x + SETTINGS_PADDING, this.y + SETTINGS_HEADER_HEIGHT / 2)
}

SettingsForm.prototype.DrawCross = function(ctx, x, y) {
    ctx.strokeStyle = SETTINGS_CROSS_COLOR

    if (this.IsCrossHover(x, y)) {
        ctx.canvas.style.cursor = 'pointer'
        ctx.strokeStyle = SETTINGS_CROSS_HOVER_COLOR
    }

    ctx.beginPath()
    ctx.moveTo(this.crossX, this.crossY)
    ctx.lineTo(this.crossX + SETTINGS_CROSS_SIZE, this.crossY + SETTINGS_CROSS_SIZE)
    ctx.moveTo(this.crossX, this.crossY + SETTINGS_CROSS_SIZE)
    ctx.lineTo(this.crossX + SETTINGS_CROSS_SIZE, this.crossY)
    ctx.stroke()
}

SettingsForm.prototype.DrawSetting = function(ctx, setting, x, y, mx, my) {
    ctx.font = `${SETTINGS_ITEM_FONT_SIZE}${SETTINGS_ITEM_FONT}`
    ctx.lineWidth = 1
    ctx.textAlign = 'left'
    ctx.textBaseline = 'middle'
    ctx.fillStyle = SETTINGS_COLOR

    let width = ctx.measureText(setting.name).width
    ctx.fillText(setting.name, x, y + SETTINGS_ITEM_HEIGHT / 2)

    setting.x = x + width + 5

    if (setting.type == SETTING_NUMBER) {
        let isEdit = this.editSetting == setting

        ctx.fillStyle = SETTINGS_COLOR
        ctx.strokeStyle = SETTINGS_COLOR
        setting.y = y
        setting.textBox.Draw(ctx, setting.x, setting.y + SETTINGS_ITEM_HEIGHT / 2, 1, isEdit)
        setting.width = setting.textBox.GetLineWidth(ctx, SETTINGS_ITEM_FONT_SIZE)
        setting.height = SETTINGS_ITEM_HEIGHT

        if (this.IsSettingHover(setting, mx, my)) {
            ctx.strokeStyle = SETTINGS_BORDER_HOVER
            ctx.canvas.style.cursor = isEdit ?'text' : 'pointer'
        }

        if (isEdit)
            ctx.strokeStyle = SETTINGS_BORDER_HOVER

        let lineWidth = Math.max(setting.width, 10)
        ctx.beginPath()
        ctx.moveTo(setting.x, setting.y + SETTINGS_ITEM_HEIGHT / 2 + SETTINGS_ITEM_FONT_SIZE / 2)
        ctx.lineTo(setting.x + lineWidth, setting.y + SETTINGS_ITEM_HEIGHT / 2 + SETTINGS_ITEM_FONT_SIZE / 2)
        ctx.stroke()
    }
    else if (setting.type == SETTING_COLOR) {
        setting.y = y + SETTINGS_ITEM_HEIGHT / 2 - SETTINGS_COLOR_HEIGHT / 2
        setting.width = SETTINGS_COLOR_WIDTH
        setting.height = SETTINGS_COLOR_HEIGHT

        ctx.strokeStyle = SETTINGS_COLOR_BORDER

        if (this.IsSettingHover(setting, mx, my)) {
            ctx.strokeStyle = SETTINGS_BORDER_HOVER
            ctx.canvas.style.cursor = 'pointer'
        }

        ctx.beginPath()
        ctx.fillStyle = setting.colorPicker.color
        ctx.rect(setting.x, setting.y, SETTINGS_COLOR_WIDTH, SETTINGS_COLOR_HEIGHT)
        ctx.fill()
        ctx.stroke()
    }
}

SettingsForm.prototype.DrawSection = function(ctx, section, mx, my) {
    ctx.font = SETTINGS_SECTION_FONT
    ctx.textAlign = 'center'

    let name = `${this.viewSection + 1}/${this.sections.length}. ${section.name}`
    let width = ctx.measureText(name).width
    ctx.fillStyle = SETTINGS_COLOR
    ctx.fillText(name, section.x + this.partWidth / 2, section.y + SETTINGS_SECTION_HEIGHT / 2)

    this.leftBtn.x = section.x + this.partWidth / 2 - SETTINGS_ICON_WIDTH - width / 2
    this.leftBtn.y = section.y

    this.rightBtn.x = section.x + this.partWidth / 2 + width / 2
    this.rightBtn.y = section.y

    this.leftBtn.Draw(ctx, mx, my)
    this.rightBtn.Draw(ctx, mx, my)

    let y = section.y + SETTINGS_SECTION_HEIGHT

    for (let setting of section.settings) {
        this.DrawSetting(ctx, setting, section.x, y, mx, my)
        y += SETTINGS_ITEM_HEIGHT
    }
}

SettingsForm.prototype.DrawLine = function(ctx, x1, y1, x2, y2, color) {
    ctx.strokeStyle = color
    ctx.beginPath()
    ctx.moveTo(x1, y1)
    ctx.lineTo(x2, y2)
    ctx.stroke()
}

SettingsForm.prototype.DrawView = function(ctx) {
    ctx.fillStyle = BACKGROUND_COLOR
    ctx.fillRect(this.viewX, this.viewY, this.partWidth, this.viewHeight)
    ctx.lineWidth = 1

    let size = (this.partWidth / 15)
    let right = Math.floor(this.partWidth / size)
    let bottom = Math.floor(this.viewHeight / size)

    for (let i = 0; i <= right; i++)
        this.DrawLine(ctx, this.viewX + i * size, this.viewY, this.viewX + i * size, this.viewY + this.viewHeight, Math.abs(i) % 5 == 0 ? MAJOR_GRID_COLOR : GRID_COLOR)

    for (let i = 0; i <= bottom; i++)
        this.DrawLine(ctx, this.viewX, this.viewY + i * size, this.viewX + this.partWidth, this.viewY + i * size, Math.abs(i) % 5 == 0 ? MAJOR_GRID_COLOR : GRID_COLOR)
}

SettingsForm.prototype.DrawObjects = function(ctx, objects) {
    ctx.save()
    ctx.rect(this.viewX, this.viewY, this.partWidth, this.viewHeight)
    ctx.clip()

    let backup = settings.ToLocalStorage()
    this.Save()
    this.vertex.SetParams(settings.vertex)
    this.v1.SetParams(settings.vertex)
    this.v2.SetParams(settings.vertex)
    this.edge.SetParams(settings.edge)
    this.text.SetParams(settings.text)
    settings.Restore(JSON.parse(backup))

    for (let object of objects) {
        if (object.type == SETTINGS_VERTEX) {
            this.vertex.x = Math.floor(object.x * this.partWidth)
            this.vertex.y = Math.floor(object.y * this.partWidth)
            this.vertex.SetText(object.name)
            this.vertex.Draw(ctx, this.viewX, this.viewY, 1, COLOR_STATUS)
        }
        else if (object.type == SETTINGS_EDGE) {
            this.v1.x = Math.floor(object.v1.x * this.partWidth)
            this.v1.y = Math.floor(object.v1.y * this.partWidth)
            this.v2.x = Math.floor(object.v2.x * this.partWidth)
            this.v2.y = Math.floor(object.v2.y * this.partWidth)
            this.edge.SetText(object.weight)
            this.edge.SetIsDirected(object.isDirected)
            this.edge.Draw(ctx, this.viewX, this.viewY, 1, COLOR_STATUS)
        }
        else if (object.type == SETTINGS_TEXT) {
            this.text.x = Math.floor(object.x * this.partWidth)
            this.text.y = Math.floor(object.y * this.partWidth)
            this.text.SetText(object.text)
            this.text.Draw(ctx, this.viewX, this.viewY, 1, COLOR_STATUS)
        }
    }
    ctx.restore()
}

SettingsForm.prototype.DrawCheckBox = function(ctx, mx, my) {
    ctx.fillStyle = SETTINGS_CHECKBOX_COLOR
    ctx.strokeStyle = SETTINGS_CHECKBOX_COLOR
    ctx.font = SETTINGS_CHECKBOX_FONT

    this.applyCheckBox.Draw(ctx, this.checkBoxX, this.y + this.height - SETTINGS_PADDING * 2 - SETTINGS_BUTTON_HEIGHT - SETTINGS_CHECKBOX_SIZE, mx, my)
}

SettingsForm.prototype.Draw = function(ctx, bbox, mx, my) {
    let isHorizontal = bbox.width * 1.5 > bbox.height

    if (isHorizontal) {
        this.width = SETTINGS_WIDTH
        this.height = SETTINGS_HEIGHT

        if (this.width > bbox.width)
            this.width = bbox.width

        this.partWidth = Math.round((this.width - SETTINGS_PADDING * 3) / 2)
    }
    else {
        this.width = 2 * SETTINGS_PADDING + SETTINGS_PARTS_WIDTH
        this.height = SETTINGS_HEADER_HEIGHT + 5 * SETTINGS_PADDING + SETTINGS_SECTION_HEIGHT + this.GetSectionMaxHeight() + this.partWidth + SETTINGS_CHECKBOX_SIZE + SETTINGS_BUTTON_HEIGHT

        if (this.width > bbox.width)
            this.width = bbox.width

        if (this.height > bbox.height)
            this.height = bbox.height

        this.partWidth = Math.round(this.width - 2 * SETTINGS_PADDING)
    }

    this.x = (bbox.xmin + bbox.xmax) / 2 - this.width / 2
    this.y = (bbox.ymin + bbox.ymax) / 2 - this.height / 2

    this.crossX = this.x + this.width - SETTINGS_PADDING - SETTINGS_CROSS_SIZE
    this.crossY = this.y + (SETTINGS_HEADER_HEIGHT - SETTINGS_CROSS_SIZE) / 2

    this.sections[this.viewSection].x = this.x + SETTINGS_PADDING
    this.sections[this.viewSection].y = this.y + SETTINGS_HEADER_HEIGHT + SETTINGS_PADDING

    if (isHorizontal) {
        this.viewX = this.x + 2 * SETTINGS_PADDING + this.partWidth
        this.viewY = this.y + SETTINGS_HEADER_HEIGHT + SETTINGS_PADDING
        this.viewHeight = this.height - 2 * SETTINGS_PADDING - SETTINGS_HEADER_HEIGHT
        this.checkBoxX = this.x + SETTINGS_PADDING + this.partWidth / 2
    }
    else {
        this.viewX = this.x + SETTINGS_PADDING
        this.viewY = this.y + SETTINGS_HEADER_HEIGHT + 2 * SETTINGS_PADDING + SETTINGS_SECTION_HEIGHT + this.GetSectionMaxHeight()
        this.viewHeight = this.y + this.height - this.viewY - SETTINGS_BUTTON_HEIGHT - SETTINGS_CHECKBOX_SIZE - SETTINGS_PADDING * 3
    }

    this.checkBoxX = this.x + this.partWidth / 2

    let buttonWidth = this.buttons.length * (SETTINGS_BUTTON_WIDTH + SETTINGS_PADDING) - SETTINGS_PADDING
    let buttonX = this.x + SETTINGS_PADDING + (this.partWidth - buttonWidth) / 2
    let buttonY = this.y + this.height - SETTINGS_PADDING - SETTINGS_BUTTON_HEIGHT

    for (let button of this.buttons) {
        button.x = buttonX
        button.y = buttonY
        button.Draw(ctx, mx, my)
        buttonX += SETTINGS_BUTTON_WIDTH + SETTINGS_PADDING
    }

    this.DrawBackground(ctx)
    this.DrawHeader(ctx)
    this.DrawCross(ctx, mx, my)
    this.DrawSection(ctx, this.sections[this.viewSection], mx, my)
    this.DrawView(ctx)
    this.DrawObjects(ctx, this.sections[this.viewSection].objects)
    this.DrawCheckBox(ctx, mx, my)

    for (let button of this.buttons)
        button.Draw(ctx, mx, my, !this.IsColor())

    if (this.IsColor()) {
        let x = Math.max(bbox.xmin, Math.min(bbox.xmax - COLOR_PICKER_WIDTH, this.editSetting.x + this.editSetting.width))
        let y = Math.max(bbox.ymin, Math.min(bbox.ymax - COLOR_PICKER_HEIGHT, this.editSetting.y))
        this.editSetting.colorPicker.SetCoordinates(x, y)
        this.editSetting.colorPicker.Draw(ctx.canvas, ctx, mx, my)
    }
}

;
function GraphRedactor(canvas, offset = 0) {
    this.canvas = canvas
    this.offset = offset
    this.canvas.style.marginTop = offset + 'px'
    this.ctx = canvas.getContext('2d')
    this.width = window.innerWidth
    this.height = window.innerHeight - this.offset
    this.isTouch = 'ontouchstart' in window

    this.Init()
    this.InitEvents()
    this.InitHotKeys()
    this.InitMenu()
    this.InitTips()
    this.InitIcons()
    this.InitSelections()
    this.InitKeyboard()
    this.InitColorPickers()
    this.InitRandomGraphForm()
    this.InitExampleCreator()

    this.WindowResize()
    this.RestoreFromLocalStorage()
    this.InitSettingsForm()
    this.InitIntro()

    this.ReDraw()
}

// инициализация
GraphRedactor.prototype.Init = function() {
    this.scales = SCALE_VALUES
    this.prevPoint = { x: 0, y: 0 }
    this.currPoint = { x: -1, y: -1 }
    this.currRealPoint = { x: -1, y: -1 }
    this.prevRealPoint = { x: -1, y: -1 }
    this.needDrawGrid = true // нужно ли отрисовывать сетку
    this.colorPicker = null // диалог выбора цвета

    this.ClearGraph()
}

// очистка графа
GraphRedactor.prototype.ClearGraph = function() {
    this.x0 = 0 // начальная точка по X
    this.y0 = 0 // начальная точка по Y
    this.scaleIndex = this.scales.indexOf(1)
    this.scale = 1 // масштаб

    this.vertices = new VerticesCollection() // вершины
    this.edges = [] // рёбра
    this.texts = [] // тексты
    this.undo = [] // буфер отмены
    this.redo = [] // буфер повтора

    this.activeObject = null // активный объект
    this.copy = null // буфер обмена
    this.ctrlKey = false // нажат ли контрол
    this.isDragAndDrop = false // выполняется ли перетаскивание
    this.placeStatus = PLACE_END_STATUS // никакого алгоритма размещения не запущено
}

// инициализация событий
GraphRedactor.prototype.InitEvents = function() {
    document.addEventListener('mousemove', (e) => { this.MouseMove(e) })
    document.addEventListener('mousedown', (e) => { this.MouseDown(e) })
    document.addEventListener('mouseup', (e) => { this.MouseUp(e) })
    document.addEventListener('wheel', (e) => { this.MouseWheel(e); e.preventDefault() }, { passive: false })
    document.addEventListener('keydown', (e) => { this.KeyDown(e) })
    document.addEventListener('keypress', (e) => { this.KeyPress(e) })
    document.addEventListener('copy', (e) => { this.CopyText(e) })
    document.addEventListener('cut', (e) => { this.CutText(e) })
    document.addEventListener('paste', (e) => { this.PasteText(e) })

    this.canvas.ondragover = (e) => { this.DragOver(e); return false }
    this.canvas.ondragleave = (e) => { this.DragLeave(e); return false }
    this.canvas.ondrop = (e) => { this.Drop(e); return false }

    window.onresize = () => this.WindowResize()

    if (SAVE_ON_RELOAD) {
        window.onbeforeunload = (e) => this.BeforeUnload()
    }

    if (this.isTouch) {
        let touchEvents = new TouchEvents(this)
    }
}

GraphRedactor.prototype.ReDraw = function() {
    this.Draw()
    window.requestAnimationFrame(() => this.ReDraw())
}

