    this.leftMenu.AddItem('Разместить граф', ICONS_BASE_URL + 'place/fruchterman-reingold.svg', ICONS_BASE_URL + 'place/fruchterman-reingold-hover.svg', () => { this.Escape(); placeMenu.SetVisible(true) }, () => placeMenu.IsVisible())
    this.leftMenu.AddItem('Действия', ACTIONS_ICONS_URL + 'action.svg', ACTIONS_ICONS_URL + 'action-hover.svg', () => { this.Escape(); actionsMenu.SetVisible(true) }, () => actionsMenu.IsVisible())
