    this.icons = {}
    this.icons['grid'] = new Icon(ICONS_BASE_URL + 'grid.svg', ICONS_BASE_URL + 'grid-hover.svg', { x: -30, y: -25 }, 'Показать сетку', () => !this.IsExampleCreator(this.activeObject) && !this.IsAnimation(this.activeObject) && !this.needDrawGrid, () => !this.isPressed, () => this.needDrawGrid = !this.needDrawGrid )
