    this.icons['zoom-out'] = new Icon(ICONS_BASE_URL + 'zoom-out.svg', ICONS_BASE_URL + 'zoom-out-hover.svg', { x: -96, y: -25 }, 'Уменьшить масштаб', () => !this.IsExampleCreator(this.activeObject) && !this.IsAnimation(this.activeObject), () => !this.isPressed && this.CanUpdateScale(-1), () => this.UpdateScale(-1, true))
    this.icons['redo'] = new Icon(ICONS_BASE_URL + 'redo.svg', ICONS_BASE_URL + 'redo-hover.svg', { x: -129, y: -25 }, 'Повторить', () => !this.IsExampleCreator(this.activeObject) && !this.IsAnimation(this.activeObject), () => !this.isPressed && this.redo.length > 0, () => this.Redo())
    this.icons['undo'] = new Icon(ICONS_BASE_URL + 'undo.svg', ICONS_BASE_URL + 'undo-hover.svg', { x: -162, y: -25 }, 'Отменить', () => !this.IsExampleCreator(this.activeObject) && !this.IsAnimation(this.activeObject), () => !this.isPressed && this.undo.length > 0, () => this.Undo())
    this.icons['find'] = new Icon(ICONS_BASE_URL + 'find-graph.svg', ICONS_BASE_URL + 'find-graph-hover.svg', { x: -195, y: -25 }, 'Найти ближайшую вершину', () => !this.IsExampleCreator(this.activeObject) && !this.IsAnimation(this.activeObject) && !this.vertices.IsEmpty(), () => !this.isPressed, () => this.FindNearestVertex())

    if (this.isTouch) {
        this.icons['copy'] = new Icon(ICONS_BASE_URL + 'copy.svg?v=2', ICONS_BASE_URL + 'copy-hover.svg?v=2', { icon: this.icons['find'], dx: -30, dy: 0 }, 'Копировать', () => this.CanCopy(), () => !this.isPressed, () => this.Copy())
        this.icons['paste'] = new Icon(ICONS_BASE_URL + 'paste.svg?v=2', ICONS_BASE_URL + 'paste-hover.svg?v=2', { icon: this.icons['copy'], dx: -30, dy: 0 }, 'Вставить', () => !this.IsExampleCreator(this.activeObject) && !this.IsAnimation(this.activeObject) && this.copy != null, () => !this.isPressed, () => this.Paste(true))
    }

    let dx = this.isTouch ? 0 : -33
    let first

    if (!this.isTouch) {
        this.icons['hotkey'] = new Icon(ICONS_BASE_URL + 'hotkey.svg', ICONS_BASE_URL + 'hotkey-hover.svg', {x: -32, y: 2}, 'Горячие клавишы', () => !this.IsAnimation(this.activeObject) && !this.IsInput(this.activeObject) && !this.IsExampleCreator(this.activeObject), () => !this.isPressed, () => this.hotkeys.SetVisible(!this.hotkeys.IsVisible()) )
        first = { icon: this.icons['hotkey'], dx: -30, dy: 3 }
    }
    else {
        first = { x: -30, y: 5}
    }

    this.icons['remove'] = new Icon(ICONS_BASE_URL + 'trash.svg', ICONS_BASE_URL + 'trash-hover.svg', first, 'Удалить', () => this.CanRemove(), () => !this.isPressed, () => this.Remove())
    this.icons['edit'] = new Icon(ICONS_BASE_URL + 'edit.svg', ICONS_BASE_URL + 'edit-hover.svg', { icon: this.icons['remove'], dx: -30, dy: 0 }, 'Редактировать', () => !this.IsAnimation(this.activeObject) && this.CanStartEdit() && !this.IsInput(this.activeObject) && !this.IsRandomGraphForm(this.activeObject), () => !this.isPressed, () => this.StartEdit())
    this.icons['fill'] = new Icon(ICONS_BASE_URL + 'fill.svg', ICONS_BASE_URL + 'fill-hover.svg', { icon: this.icons['edit'], dx: -30, dy: 0 }, 'Изменить цвет заливки', () => this.CanChangeBackground(), () => !this.isPressed && !this.IsEdit() && this.colorPicker != this.backgroundColorPicker, () => this.SwitchColorPicker(this.backgroundColorPicker, this.activeObject.GetBackground()))
    this.icons['color'] = new Icon(ICONS_BASE_URL + 'text-color.svg', ICONS_BASE_URL + 'text-color-hover.svg', { icon: this.icons['fill'], dx: -30, dy: 0 }, 'Изменить цвет текста', () => this.CanChangeColor(), () => !this.isPressed && !this.IsEdit() && this.colorPicker != this.textColorPicker, () => this.SwitchColorPicker(this.textColorPicker, this.activeObject.GetColor()))
    this.icons['border'] = new Icon(ICONS_BASE_URL + 'line-color.svg', ICONS_BASE_URL + 'line-color-hover.svg', { icon: this.icons['color'], dx: -30, dy: 0 }, 'Изменить цвет рамки', () => this.CanChangeBorder(), () => !this.isPressed && !this.IsEdit() && this.colorPicker != this.borderColorPicker, () => this.SwitchColorPicker(this.borderColorPicker, this.activeObject.GetBorder()))
    this.icons['swap-directed'] = new Icon(ICONS_BASE_URL + 'swap-direct.svg', ICONS_BASE_URL + 'swap-direct-hover.svg', { icon: this.icons['border'], dx: -30, dy: 0 }, 'Изменить ориентированность', () => this.IsEdge(this.activeObject) && this.CanChangeEdgeDirected(this.activeObject), () => !this.isPressed, () => this.ChangeEdgeDirected(this.activeObject))
