    this.icons['font-decrease'] = new Icon(ICONS_BASE_URL + 'font-decrease.svg', ICONS_BASE_URL + 'font-decrease-hover.svg', { icon: this.icons['font-increase'], dx: -30, dy: 0 }, 'Уменьшить размер шрифта', () => this.CanChangeFontSize(this.activeObject, 0), () => !this.isPressed && this.CanChangeFontSize(this.activeObject, -1), () => this.ChangeFontSize(this.activeObject, -1))

