// инициализация выбора вершин
GraphRedactor.prototype.InitSelections = function() {
    this.selections = {}
    this.selections[SELECT_NEW_EDGE] = new VerticesSelection(['Выберите начальную вершину для создания неориентированного ребра', 'Выберите конечную вершину для создания неориентированного ребра'], (vertices) => this.activeObject = this.CreateEdge(vertices[0], vertices[1], this.ctrlKey ? '1' : '', false))
    this.selections[SELECT_NEW_DIRECTED_EDGE] = new VerticesSelection(['Выберите начальную вершину для создания ориентированного ребра', 'Выберите конечную вершину для создания ориентированного ребра'], (vertices) => this.activeObject = this.CreateEdge(vertices[0], vertices[1], this.ctrlKey ? '1' : '', true))
    this.selections[SELECT_BFS] = new VerticesSelection(['Выберите начальную вершину для обхода в ширину'], (vertices) => this.BFS(vertices[0]))
    this.selections[SELECT_DFS] = new VerticesSelection(['Выберите начальную вершину для обхода в глубину'], (vertices) => this.DFS(vertices[0]))
    this.selections[SELECT_DIJKSTRA] = new VerticesSelection(['Выберите стартовую вершину для алгоритма Дейкстры', 'Выберите конечную вершину для алгоритма Дейкстры'], (vertices) => this.Dijkstra(vertices[0], vertices[1]))
    this.selections[SELECT_BELLMAN_FORD] = new VerticesSelection(['Выберите стартовую вершину для алгоритма Беллмана-Форда', 'Выберите конечную вершину для алгоритма Беллмана-Форда'], (vertices) => this.BellmanFord(vertices[0], vertices[1]))
    this.selections[SELECT_ALL_WAYS] = new VerticesSelection(['Выберите стартовую вершину для поиска всех путей', 'Выберите конечную вершину для поиска всех путей'], (vertices) => this.FindAllPaths(vertices[0], vertices[1]))
    this.selections[SELECT_MAX_FLOW] = new VerticesSelection(['Выберите исток', 'Выберите сток'], (vertices) => this.MaxFlowPreflowPush(vertices[0], vertices[1]))
    this.selections[SELECT_MAX_FLOW_DINIC] = new VerticesSelection(['Выберите исток', 'Выберите сток'], (vertices) => this.MaxFlowDinic(vertices[0], vertices[1]))

    this.selections[SELECT_ISOMORPHISM_CHECK] = new GraphsSelection(['Выберите первый граф', 'Выберите второй граф'], [RED_STATUS, BLUE_STATUS], (graphs) => this.IsomorphismCheck(graphs[0], graphs[1]))
}

// инициализация клавиатуры
GraphRedactor.prototype.InitKeyboard = function() {
    this.keyboard = new Keyboard()

    let keys = {}
    keys[KEYBOARD_RUSSIAN_MODE] = [
        'ё1234567890',
        'йцукенгшщзх',
        'фывапролджэ',
        [KEYBOARD_UPPERCASE, 'я', 'ч', 'с', 'м', 'и', 'т', 'ь', 'б', 'ю', KEYBOARD_BACKSPACE],
        [KEYBOARD_SWAP_TO_ENGLIGH_MODE, ',', ' ', '.', KEYBOARD_ENTER]
    ]

    keys[KEYBOARD_ENGLISH_MODE] = [
        '1234567890',
        'qwertyuiop',
        'asdfghjkl;',
        [KEYBOARD_UPPERCASE, 'z', 'x', 'c', 'v', 'b', 'n', 'm', ':', KEYBOARD_BACKSPACE],
        [KEYBOARD_SWAP_TO_SYMBOLS_MODE, ',', ' ', '.', KEYBOARD_ENTER]
    ]

    keys[KEYBOARD_SYMBOLS_MODE] = [
        '~1234567890',
        '@#&_()[]{}|',
        '"\':;+-*/^!?',
        ['<', '>', '=', '%', '`', '$', '€', '¥', '×', '\\', KEYBOARD_BACKSPACE],
        [KEYBOARD_SWAP_TO_RUSSIAN_MODE, ' ', ',', '.', KEYBOARD_ENTER]
    ]

    keys[KEYBOARD_NUMERIC_MODE] = [
        ['1', '2', '3', KEYBOARD_BACKSPACE],
        ['4', '5', '6', '-'],
        ['7', '8', '9', '.'],
        [KEYBOARD_LEFT, '0', KEYBOARD_RIGHT, KEYBOARD_ENTER]
    ]

    for (let mode of [KEYBOARD_RUSSIAN_MODE, KEYBOARD_ENGLISH_MODE, KEYBOARD_SYMBOLS_MODE, KEYBOARD_NUMERIC_MODE]) {
        for (let i = 0; i < keys[mode].length; i++) {
            this.keyboard.AddRow(mode)

            for (let key of keys[mode][i])
                this.keyboard.AddKey(mode, i, key)
        }
    }
}

// инициализация диалогов выбора цвета
