GraphRedactor.prototype.InitVertexIntro = function(intro) {
    let vertexText = "Сделайте двойной клик левой кнопкой мыши в пустом месте поля или нажмите клавишу V."
    let generator = new IntroFrameGenerator()

    generator.MoveCursor(null, null, 8)
    generator.DoubleClick()
    generator.FinalizeFrame(80, 4)

    generator.AddVertex("v1", "1", COLOR_STATUS)
    generator.FinalizeFrame(60)

    generator.GetObject("v1").status = ACTIVE_STATUS
    generator.FinalizeFrame(60)
    generator.FinalizeFrame(200)

    let p1 = generator.GetCursorPoint()
    let p2 = generator.GetNextRandomPoint()
    let t = 0.75
    let p = {
        x: p1.x * t + p2.x * (1 - t),
        y: p1.y * t + p2.y * (1 - t),
    }

    generator.MoveCursor(null, p, 2)

    generator.AddKeys("keys", ["V"], [false])
    generator.MoveCursor(null, p2, 6)

    generator.GetObject("keys").pressed[0] = true
    generator.GetObject("v1").status = COLOR_STATUS
    generator.AddVertex("v2", "2", ACTIVE_STATUS)
    generator.FinalizeFrame(200)

    generator.GetObject("keys").pressed[0] = false
    generator.FinalizeFrame(200)

    generator.RemoveObject("keys")
    generator.FinalizeFrame(900)

    intro.AddAction("Добавление вершины", vertexText, generator.frames)
}

