    generator.AddKeys("keys", ['Delete'], [true])
    generator.GetObject("e2").weight = generator.GetObject("e2").weight.substr(0, 1)
    generator.FinalizeFrame(100)

    generator.GetObject("keys").pressed[0] = false
    generator.FinalizeFrame(100)

    generator.GetObject("keys").pressed[0] = true
    generator.GetObject("e2").weight = ""
