    generator.RemoveObject("keys")
    generator.FinalizeFrame(900)

    generator.MoveCursor(null, { x: 0.4, y: 0.6 }, 4)
    generator.Click()
    generator.FinalizeFrame(60)

    generator.GetObject("e2").status = COLOR_STATUS
    generator.GetObject("e2").isEdit = false
    generator.FinalizeFrame(60, 4)
    generator.FinalizeFrame(1000)

    intro.AddAction("Редактирование ребра", editText, generator.frames)
