// инициализация обучающей формы
GraphRedactor.prototype.InitIntro = function() {
    if (this.isTouch)
        return

    let cookies = document.cookie.split('; ').filter((name) => name.startsWith(INTRO_COOKIE))

    if (cookies.length != 0 && cookies[0].split('=')[1] != 'yes')
        return

    let intro = new Intro((dontShowAgain) => this.CloseIntro(dontShowAgain))

    this.InitVertexIntro(intro)
    this.InitEdgesIntro(intro)
    this.InitEdgeEditIntro(intro)
    this.InitVertexEditIntro(intro)

    this.activeObject = intro
}

GraphRedactor.prototype.CloseIntro = function(dontShowAgain) {
    document.cookie = `${INTRO_COOKIE}=${dontShowAgain ? "no" : "yes"}`
    this.activeObject = null
}

// попытка объединить действий с предыдущим
GraphRedactor.prototype.JoinAction = function(name, args) {
    if (name == ACTION_EDIT && args.prevText == args.newText)
        return true

    if (this.undo.length == 0)
        return false

    let prev = this.undo[this.undo.length - 1]

    if (name == ACTION_END_BLOCK) {
        if (prev.name == ACTION_BEGIN_BLOCK) {
            this.undo.pop()
            return true
        }

        if (this.undo[this.undo.length - 2].name == ACTION_BEGIN_BLOCK) {
            let action = this.undo.pop()
            this.undo.pop()
            this.undo.push(action)
            return true
        }
    }

    if (prev.name != name)
        return false

    if (name == ACTION_MOVE && prev.args.object == args.object) {
        prev.args.dx += args.dx
        prev.args.dy += args.dy

        if (prev.args.dx == 0 && prev.args.dy == 0)
            this.undo.pop()

        return true
    }

    if (name == ACTION_EDIT && prev.args.object == args.object) {
        prev.args.newText = args.newText

        if (prev.args.prevText == prev.args.newText)
            this.undo.pop()

        return true
    }

    if (name == ACTION_CHANGE_EDGE_CONTROL_STEP && prev.args.edge == args.edge) {
        prev.args.step = args.step

        if (prev.args.prev == prev.args.step)
            this.undo.pop()

        return true
    }

    if ((name == ACTION_CHANGE_COLOR || name == ACTION_CHANGE_BACKGROUD || name == ACTION_CHANGE_BORDER) && prev.args.object == args.object) {
        prev.args.newColor = args.newColor

        if (prev.args.oldColor == prev.args.newColor)
            this.undo.pop()

        return true
    }

    if ((name == ACTION_CHANGE_FONT_SIZE || name == ACTION_INCREASE_DECREASE) && prev.args.object == args.object) {
        prev.args.step += args.step

        if (prev.args.step == 0)
            this.undo.pop()

        return true
    }

    return false
}

// добавление действия для отмены
GraphRedactor.prototype.AddAction = function(name, args) {
    this.redo = []

    if (!this.JoinAction(name, args)) {
        this.undo.push({ name: name, args: args })
    }
}

// создание новой вершины
GraphRedactor.prototype.CreateVertex = function(x, y, name = null, params = {}) {
    x = Math.round(x / GRID_SIZE) * GRID_SIZE
    y = Math.round(y / GRID_SIZE) * GRID_SIZE

    if (name == null)
        name = this.vertices.GetNewName()

    let vertex = new Vertex(x, y, name, params)
    this.AddVertex(vertex)
    this.activeObject = vertex

    return vertex
}

// создание новой вершины возле пункта меню
GraphRedactor.prototype.CreateObjectFromMenu = function(type, index) {
    let dx = this.leftMenu.width - this.currPoint.x + GRID_SIZE * 3 * this.scale
    let dy = (LEFT_MENU_TOP_OFFSET + (index + 0.5) * LEFT_MENU_ITEM_HEIGHT - this.currPoint.y - this.leftMenu.scrollHeight)

    let x = this.currRealPoint.x + dx / this.scale
    let y = this.currRealPoint.y + dy / this.scale

    if (type == 'vertex') {
        this.CreateVertex(x, y)
        this.tips[TIP_VERTEX_CREATE].Show()
    }
    else if (type == 'text') {
        this.CreateText(x, y)
    }

    this.isPressed = true
    this.prevPoint.x = this.currPoint.x + dx
    this.prevPoint.y = this.currPoint.y + dy
}

// создание выделения вершин
GraphRedactor.prototype.CreateVertexSelection = function(selectionName) {
    this.EndEdit()

    let selection = this.selections[selectionName]

    if (!this.IsVertex(this.activeObject)) {
        this.activeObject = selection
        return
    }

    if (!selection.AddVertex(this.activeObject)) {
        this.activeObject = selection
    }
}

// создание выделения графов
GraphRedactor.prototype.CreateGraphsSelection = function(selectionName) {
    this.EndEdit()

    let graphs = this.GetConnectedGraphs()
    let selection = this.selections[selectionName]

    selection.SetAvailableGraphs(graphs)

    if (!this.IsVertex(this.activeObject) && !this.IsEdge(this.activeObject)) {
        this.activeObject = selection
        return
    }

    if (this.IsVertex(this.activeObject) && !selection.AddVertex(this.activeObject)) {
        this.activeObject = selection
    }

    if (this.IsEdge(this.activeObject) && !selection.AddEdge(this.activeObject)) {
        this.activeObject = selection
    }
}

// запуск алгоритма Дейкстры
GraphRedactor.prototype.StartDijkstra = function() {
    if (this.HaveNegativeEdges()) {
        alert("Алгоритм Дейкстры не работает с рёбрами отрицательного веса")
        return
    }

    this.CreateVertexSelection(SELECT_DIJKSTRA)
}

// запуск алгоритма Дейкстры
GraphRedactor.prototype.StartMaxFlow = function(algorithm) {
    if (this.HaveNegativeEdges()) {
        alert("Поиск максимального потока не работает с рёбрами отрицательного веса")
        return
    }

    this.CreateVertexSelection(algorithm)
}

// запуск проверки на изоморфизм
GraphRedactor.prototype.StartIsomorphismCheck = function() {
    if (this.IsConnected()) {
        alert("Необходимо иметь хотя бы два несвязных графа")
        return
    }

    this.CreateGraphsSelection(SELECT_ISOMORPHISM_CHECK)
}

// есть ли уже такое ребро
GraphRedactor.prototype.HaveEdge = function(vertex1, vertex2, isDirected) {
    for (let edge of this.edges) {
        if (edge.vertex1 == vertex1 && edge.vertex2 == vertex2)
            return true

        if ((!edge.isDirected || !isDirected) && edge.vertex1 == vertex2 && edge.vertex2 == vertex1)
            return true
    }

    return false
}

// получение ребра по двум вершинам
GraphRedactor.prototype.GetEdgeByVertices = function(vertex1, vertex2) {
    for (let edge of this.edges)
        if (edge.vertex1 == vertex1 && edge.vertex2 == vertex2)
            return edge

    return null
}

// получение индекса ребра по двум вершинами
GraphRedactor.prototype.GetEdgeByVerticesIndex = function(vertex1, vertex2) {
    for (let i = 0; i < this.edges.length; i++) {
        if (this.edges[i].vertex1 == vertex1 && this.edges[i].vertex2 == vertex2)
            return i

        if (!this.edges[i].IsDirected() && this.edges[i].vertex1 == vertex2 && this.edges[i].vertex2 == vertex1)
            return i
    }

    return -1
}

// правка одного ребра при добавлении
GraphRedactor.prototype.FixEdge = function(edge) {
    if (!edge.IsDirected() || edge.IsLoop())
        return

    let inverseEdge = this.GetEdgeByVertices(edge.vertex2, edge.vertex1)

    if (inverseEdge == null)
        return

    if (edge.IsLined() && inverseEdge.IsLined()) {
        let prevStep = edge.GetControlStep()
        let prevInverseStep = inverseEdge.GetControlStep()

        inverseEdge.MakeArced()
        edge.MakeArced()

        this.AddAction(ACTION_CHANGE_EDGE_CONTROL_STEP, { edge: inverseEdge, prev: prevInverseStep, step: inverseEdge.GetControlStep() })
        this.AddAction(ACTION_CHANGE_EDGE_CONTROL_STEP, { edge: edge, prev: prevStep, step: edge.GetControlStep() })
    }
}

// фикс рёбер (инициализация в виде дуги или прямой)
GraphRedactor.prototype.FixEdges = function() {
    for (let edge of this.edges) {
        if (!edge.isDirected)
            continue

        let inverseEdge = this.GetEdgeByVertices(edge.vertex2, edge.vertex1)

        if (inverseEdge == null && edge.IsArced()) {
            edge.MakeLined()
        }
        else if (inverseEdge != null && edge.IsLined()) {
            edge.MakeArced()
        }
    }
}

// создание нового ребра
GraphRedactor.prototype.CreateEdge = function(vertex1, vertex2, weight = '1', isDirected = true, controlStep = 0, params = {}) {
    if (this.HaveEdge(vertex1, vertex2, isDirected))
        return

    if (vertex1 == vertex2 && isDirected)
        isDirected = false

    let edge = new Edge(vertex1, vertex2, weight, isDirected, controlStep, params)
    this.AddEdge(edge)
    return edge
}

// быстрое создание нового ребра
GraphRedactor.prototype.FastCreateEdge = function(vertex1, vertex2, weight = '1', isDirected = true, controlStep = 0, params = {}) {
    let edge = new Edge(vertex1, vertex2, weight, isDirected, controlStep, params)
    this.edges.push(edge)
    this.AddAction(ACTION_ADD_EDGE, { edge: edge })
    return edge
}

// создание нового текста
GraphRedactor.prototype.CreateText = function(x, y, value = 'text', params = {}) {
    x = Math.floor(x / GRID_SIZE) * GRID_SIZE
    y = Math.floor(y / GRID_SIZE) * GRID_SIZE

    let text = new Text(x, y, value, params)
    this.AddText(text)
    this.activeObject = text

    return text
}

// добавление вершины
GraphRedactor.prototype.AddVertex = function(vertex, addToUndo = true) {
    this.vertices.Add(vertex)

    if (addToUndo) {
        this.AddAction(ACTION_ADD_VERTEX, { vertex: vertex })
    }
}

// добавление ребра
GraphRedactor.prototype.AddEdge = function(edge, addToUndo = true) {
    this.edges.push(edge)

    if (addToUndo) {
        this.AddAction(ACTION_BEGIN_BLOCK, {})
        this.AddAction(ACTION_ADD_EDGE, { edge: edge })
        this.FixEdge(edge)
        this.AddAction(ACTION_END_BLOCK, {})
    }
}

// добавление ребра
GraphRedactor.prototype.AddText = function(text, addToUndo = true) {
    this.texts.push(text)

    if (addToUndo) {
        this.AddAction(ACTION_ADD_TEXT, { text: text })
    }
}

// можно ли сметить ориентированность ребра
GraphRedactor.prototype.CanChangeEdgeDirected = function(edge) {
    return !edge.IsLoop() && (!edge.IsDirected() || !this.HaveEdge(edge.vertex2, edge.vertex1, true))
}

// смена ориентированности ребра
GraphRedactor.prototype.ChangeEdgeDirected = function(edge, addToUndo = true) {
    edge.ToggleDirected()

    if (addToUndo) {
        this.AddAction(ACTION_DIRECT_EDGE, { edge: edge })
    }
}

// можно ли сменить направление ребра
GraphRedactor.prototype.CanChangeEdgeDirection = function(edge) {
    return edge.IsDirected() && !this.HaveEdge(edge.vertex2, edge.vertex1, true)
}

// смена направления ребра
GraphRedactor.prototype.ChangeEdgeDirection = function(edge, addToUndo = true) {
    edge.SwapVertices()

    if (addToUndo) {
        this.AddAction(ACTION_CHANGE_DIRECTION_EDGE, { edge: edge })
    }
}

// удаление вершины
GraphRedactor.prototype.RemoveVertex = function(vertex, addToUndo = true) {
    let edges = []

    for (let edge of this.edges)
        if (edge.vertex1 == vertex || edge.vertex2 == vertex)
            edges.push(edge)

    for (let edge of edges) {
        this.RemoveEdge(edge, false)
    }

    this.vertices.Remove(vertex)

    if (addToUndo) {
        this.AddAction(ACTION_REMOVE_VERTEX, { vertex: vertex, edges: edges })
    }
}

// удаление ребра
GraphRedactor.prototype.RemoveEdge = function(edge, addToUndo = true) {
    let index = this.edges.indexOf(edge)
    this.edges.splice(index, 1)

    if (addToUndo) {
        this.AddAction(ACTION_REMOVE_EDGE, { edge: edge })
    }
}

GraphRedactor.prototype.RemoveText = function(text, addToUndo = true) {
    let index = this.texts.indexOf(text)
    this.texts.splice(index, 1)

    if (addToUndo) {
        this.AddAction(ACTION_REMOVE_TEXT, { text: text })
    }
}

// удаление выделения
GraphRedactor.prototype.RemoveSelection = function(selection, addToUndo = true) {
    for (let edge of selection.edges)
        this.RemoveEdge(edge, false)

    for (let edge of selection.halfEdges)
        this.RemoveEdge(edge, false)

    for (let vertex of selection.vertices)
        this.RemoveVertex(vertex, false)

    for (let text of selection.texts)
        this.RemoveText(text, false)

    if (addToUndo) {
        this.AddAction(ACTION_REMOVE_SELECTION, { selection: selection })
    }
}

// переключение выбора цвета
GraphRedactor.prototype.SwitchColorPicker = function(colorPicker, color) {
    if (this.colorPicker == colorPicker) {
        this.CloseColorPicker()
    }
    else {
        this.CloseColorPicker()

        this.colorPicker = colorPicker
        this.colorPicker.SetColor(color)
        this.colorPicker.SetCoordinates(this.width + COLOR_PICKER_X, COLOR_PICKER_Y)
    }
}

GraphRedactor.prototype.ApplyStyleAll = function(change) {
    if (!confirm("Вы уверены, что хотите применить этот стиль ко всем схожим объектам?"))
        return

    this.AddAction(ACTION_BEGIN_BLOCK, {})

    if (this.IsVertex(this.activeObject))
        for (let vertex of this.vertices.Iterator())
            if (vertex != this.activeObject)
                change(vertex)

    if (this.IsText(this.activeObject))
        for (let text of this.texts)
            if (text != this.activeObject)
                change(text)

    if (this.IsEdge(this.activeObject))
        for (let edge of this.edges)
            if (edge != this.activeObject)
                change(edge)

    this.AddAction(ACTION_END_BLOCK, {})
}

GraphRedactor.prototype.CloseColorPicker = function() {
    if (this.colorPicker != null)
        this.colorPicker.Close()

    this.colorPicker = null
}

// изменение цвета фона
GraphRedactor.prototype.ChangeBackground = function(object, color, addToUndo = true) {
    if (addToUndo) {
        this.AddAction(ACTION_CHANGE_BACKGROUD, { object: object, oldColor: object.GetBackground(), newColor: color })
    }

    object.SetBackground(color)
}

// изменение цвета текста
GraphRedactor.prototype.ChangeColor = function(object, color, addToUndo = true) {
    if (addToUndo) {
        this.AddAction(ACTION_CHANGE_COLOR, { object: object, oldColor: object.GetColor(), newColor: color })
    }

    object.SetColor(color)
}

// изменение цвета рамки
GraphRedactor.prototype.ChangeBorder = function(object, color, addToUndo = true) {
    if (addToUndo) {
        this.AddAction(ACTION_CHANGE_BORDER, { object: object, oldColor: object.GetBorder(), newColor: color })
    }

    object.SetBorder(color)
}

// можно ли менять цвет фона
GraphRedactor.prototype.CanChangeBackground = function() {
    return this.IsVertex(this.activeObject) || this.IsEdge(this.activeObject) || this.IsText(this.activeObject) || this.IsCreatedSelection(this.activeObject)
}

// можно ли менять цвет текста
GraphRedactor.prototype.CanChangeColor = function() {
    return this.IsVertex(this.activeObject) || this.IsEdge(this.activeObject) || this.IsText(this.activeObject) || this.IsCreatedSelection(this.activeObject)
}

// можно ли менять цвет границы
GraphRedactor.prototype.CanChangeBorder = function() {
    if (this.IsCreatedSelection(this.activeObject))
        return this.activeObject.HaveVerticesOrTexts()

    return this.IsVertex(this.activeObject) || this.IsText(this.activeObject)
}

// можно ли уменьшить или увеличить
GraphRedactor.prototype.CanIncreaseDecrease = function(object, step) {
    if (this.IsVertex(object))
        return object.CanChangeRadius(step)

    if (this.IsEdge(object))
        return object.CanChangeLineWidth(step)

    if (this.IsCreatedSelection(this.activeObject)) {
        for (let vertex of object.vertices)
            if (this.CanIncreaseDecrease(vertex, step))
                return true

        for (let edge of object.edges)
            if (this.CanIncreaseDecrease(edge, step))
                return true

        return false
    }

    return false
}

// уменьшение или увеличение
GraphRedactor.prototype.IncreaseDecrease = function(object, step, addToUndo = true) {
    if (this.IsVertex(object)) {
        object.ChangeRadius(step)
    }
    else if (this.IsText(object)) {
        object.ChangeFontSize(step)
    }
    else if (this.IsEdge(object)) {
        object.ChangeLineWidth(step)
    }
    else if (this.IsCreatedSelection(object)) {
        object.Finalize()

        if (!addToUndo)
            return

        this.AddAction(ACTION_BEGIN_BLOCK, { object: object })
        this.AddAction(ACTION_INCREASE_DECREASE, { object: object, step: step })

        for (let vertex of object.vertices)
            if (vertex.CanChangeRadius(step))
                this.IncreaseDecrease(vertex, step, addToUndo)

        for (let edge of object.edges)
            if (edge.CanChangeLineWidth(step))
                this.IncreaseDecrease(edge, step, addToUndo)

        for (let text of object.texts)
            if (text.CanChangeFontSize(step))
                this.IncreaseDecrease(text, step, addToUndo)

        this.AddAction(ACTION_END_BLOCK, {})
        return
    }

    if (addToUndo) {
        this.AddAction(ACTION_INCREASE_DECREASE, { object: object, step: step })
    }
}

// можно ли изменять размер шрифта
GraphRedactor.prototype.CanChangeFontSize = function(object, step) {
    if (this.IsVertex(object) || this.IsText(object))
        return object.CanChangeFontSize(step)

    if (this.IsEdge(object))
        return object.IsWeighted() && object.CanChangeFontSize(step)

    if (this.IsCreatedSelection(this.activeObject)) {
        for (let vertex of object.vertices)
            if (this.CanChangeFontSize(vertex, step))
                return true

        for (let edge of object.edges)
            if (this.CanChangeFontSize(edge, step))
                return true

        for (let text of object.texts)
            if (this.CanChangeFontSize(text, step))
                return true

        return false
    }

    return false
}

// изменение размера шрифта
GraphRedactor.prototype.ChangeFontSize = function(object, step, addToUndo = true) {
    if (this.IsCreatedSelection(object)) {
        object.Finalize()

        if (!addToUndo)
            return

        this.AddAction(ACTION_BEGIN_BLOCK, { object: object })
        this.AddAction(ACTION_CHANGE_FONT_SIZE, { object: object, step: step })

        for (let vertex of object.vertices)
            if (vertex.CanChangeFontSize(step))
                this.ChangeFontSize(vertex, step, addToUndo)

        for (let edge of object.edges)
            if (edge.CanChangeFontSize(step))
                this.ChangeFontSize(edge, step, addToUndo)

        for (let text of object.texts)
            if (text.CanChangeFontSize(step))
                this.ChangeFontSize(text, step, addToUndo)

        this.AddAction(ACTION_END_BLOCK, {})
        return
    }

    object.ChangeFontSize(step)

    if (addToUndo) {
        this.AddAction(ACTION_CHANGE_FONT_SIZE, { object: object, step: step })
    }
}

// перемещение объекта
GraphRedactor.prototype.Move = function(object, dx, dy, addToUndo = true) {
    if (!this.CanMove(object, dx, dy)) {
        this.prevPoint.x -= dx * this.scale
        this.prevPoint.y -= dy * this.scale
        return
    }

    if (this.IsInput(object)) {
        dx *= this.scale
        dy *= this.scale

        let bbox = this.GetViewAreaBoundingBox()
        let x1 = object.x + dx
        let x2 = object.x + dx + object.GetWidth()
        let y1 = object.y + dy
        let y2 = object.y + dy + object.GetHeight()

        if (x1 < bbox.xmin || x2 > bbox.xmax) {
            dx = 0
        }

        if (y1 < bbox.ymin || y2 > bbox.ymax) {
            dy = 0
        }

        if (dx == 0 && dy == 0)
            return
    }

    object.Move(dx, dy)

    if (this.IsSelection(object) && !object.IsCreated())
        return

    if (this.IsInput(object))
        return

    if (addToUndo) {
        this.AddAction(ACTION_MOVE, { object: object, dx: dx, dy: dy })
    }
}

GraphRedactor.prototype.IsIntro = function(object) {
    return object instanceof Intro
}

// является ли объект вершиной
GraphRedactor.prototype.IsVertex = function(object) {
    return object instanceof Vertex
}

// является ли объект ребром
GraphRedactor.prototype.IsEdge = function(object) {
    return object instanceof Edge
}

// является ли объект текстом
GraphRedactor.prototype.IsText = function(object) {
    return object instanceof Text
}

// является ли объект выделением
GraphRedactor.prototype.IsSelection = function(object) {
    return object instanceof Selection
}

GraphRedactor.prototype.IsCreatedSelection = function(object) {
    return this.IsSelection(object) && object.IsCreated()
}

// является ли объект полем ввода
GraphRedactor.prototype.IsInput = function(object) {
    return object instanceof Input
}

// является ли объект анимацией
GraphRedactor.prototype.IsAnimation = function(object) {
    return object instanceof Animation
}

// является ли объект созданием примера
GraphRedactor.prototype.IsExampleCreator = function(object) {
    return object instanceof ExampleCreator
}

// является ли объект выбором вершин
GraphRedactor.prototype.IsVerticesSelection = function(object) {
    return object instanceof VerticesSelection
}

// является ли объект выбором графов
GraphRedactor.prototype.IsGraphsSelection = function(object) {
    return object instanceof GraphsSelection
}

GraphRedactor.prototype.IsRandomGraphForm = function(object) {
    return object instanceof RandomGraphForm
}

GraphRedactor.prototype.IsSettingsForm = function(object) {
    return object instanceof SettingsForm
}

// удаление объекта
GraphRedactor.prototype.Remove = function() {
    if (!this.CanRemove())
        return

    this.EndEdit()

    if (this.IsVertex(this.activeObject)) {
        this.RemoveVertex(this.activeObject)
    }
    else if (this.IsEdge(this.activeObject)) {
        this.RemoveEdge(this.activeObject)
    }
    else if (this.IsText(this.activeObject)) {
        this.RemoveText(this.activeObject)
    }
    else if (this.IsSelection(this.activeObject)) {
        this.RemoveSelection(this.activeObject)
    }

    this.activeObject = null
}

// копирование объекта
GraphRedactor.prototype.Copy = function() {
    if (!this.CanCopy())
        return

    this.copy = this.activeObject.Copy()
}

// вырезание объекта
GraphRedactor.prototype.Cut = function() {
    if (!this.CanCopy() || !this.CanRemove())
        return

    this.copy = this.activeObject.Copy()
    this.Remove()
}

// вставка выделения
GraphRedactor.prototype.PasteSelection = function(selection, addToUndo = true) {
    for (let vertex of selection.vertices) {
        this.AddVertex(vertex, false)
    }

    for (let edge of selection.edges) {
        this.AddEdge(edge, false)
    }

    for (let edge of selection.halfEdges) {
        this.AddEdge(edge, false)
    }

    for (let text of selection.texts) {
        this.AddText(text, false)
    }

    if (addToUndo) {
        this.AddAction(ACTION_PASTE_SELECTION, { selection: selection })
    }
}

// вставка объекта
GraphRedactor.prototype.Paste = function(toCenter = false) {
    if (this.copy == null)
        return

    let object = this.copy.Copy()
    let point = this.currRealPoint

    if (toCenter) {
        let bbox = this.GetViewAreaBoundingBoxReal()
        point.x = (bbox.xmin + bbox.xmax) / 2
        point.y = (bbox.ymin + bbox.ymax) / 2

        if (this.IsSelection(object)) {
            point.x -= object.width / 2
            point.y -= object.height / 2
        }
    }

    let x = Math.floor((point.x - object.x) / GRID_SIZE) * GRID_SIZE
    let y = Math.floor((point.y - object.y) / GRID_SIZE) * GRID_SIZE

    this.Move(object, x, y, false)

    if (this.IsVertex(object)) {
        this.AddVertex(object)
    }
    else if (this.IsText(object)) {
        this.AddText(object)
    }
    else if (this.IsSelection(object)) {
        this.PasteSelection(object)
    }

    this.activeObject = object
}

// получение ребра в точке
GraphRedactor.prototype.GetEdgeAt = function(point) {
    for (let edge of this.edges)
        if (edge.IsMouseHover(point.x, point.y))
            return edge

    return null   
}

// получение текста в точке
GraphRedactor.prototype.GetTextAt = function(point) {
    for (let i = this.texts.length - 1; i >= 0; i--)
        if (this.texts[i].IsMouseHover(point.x, point.y))
            return this.texts[i]

    return null
}

// получение объекта в точке
GraphRedactor.prototype.GetObjectAt = function(createSelection = true, ignoreSelection = false) {
    if (!ignoreSelection && this.IsSelection(this.activeObject) && this.activeObject.IsMouseHover(this.currRealPoint.x, this.currRealPoint.y)) {
        this.tips[TIP_SELECTION_ACTIONS].Show()
        return this.activeObject
    }

    if (this.IsInput(this.activeObject) && this.activeObject.IsMouseHover(this.currPoint.x, this.currPoint.y)) {
        return this.activeObject
    }

    let text = this.GetTextAt(this.currRealPoint)

    if (text != null)
        return text

    let vertex = this.vertices.GetAt(this.currRealPoint)

    if (vertex != null) {
        if (this.vertices.Count() > 1) {
            this.tips[TIP_EDGE_CREATE].Show()

            if (this.tips[TIP_EDGE_CREATE].IsShow()) {
                this.tips[TIP_VERTEX_EDIT].Show()
            }
        }

        return vertex
    }

    let edge = this.GetEdgeAt(this.currRealPoint)

    if (edge != null) {
        this.tips[TIP_EDGE_EDIT].Show()
        return edge
    }

    this.tips[TIP_VERTEX_CREATE].Show()

    if (createSelection)
        return new Selection(this.currRealPoint.x, this.currRealPoint.y)

    return null
}

// отмена последнего действия
GraphRedactor.prototype.Undo = function() {
    if (this.undo.length == 0)
        return

    if (!this.IsInput(this.activeObject)) {
        this.Escape()
    }
    else if (this.undo[this.undo.length - 1].name != ACTION_EDIT || this.undo[this.undo.length - 1].args.object != this.activeObject) {
        return
    }

    let action = this.undo.pop()

    if (action.name == ACTION_ADD_VERTEX) {
        this.RemoveVertex(action.args.vertex, false)
        this.activeObject = null
    }
    else if (action.name == ACTION_REMOVE_VERTEX) {
        this.AddVertex(action.args.vertex, false)

        for (let edge of action.args.edges) {
            this.AddEdge(edge, false)
        }

        this.activeObject = action.args.vertex
    }
    else if (action.name == ACTION_CHANGE_BACKGROUD) {
        this.ChangeBackground(action.args.object, action.args.oldColor, false)
        this.activeObject = action.args.object
    }
    else if (action.name == ACTION_CHANGE_COLOR) {
        this.ChangeColor(action.args.object, action.args.oldColor, false)
        this.activeObject = action.args.object
    }
    else if (action.name == ACTION_CHANGE_BORDER) {
        this.ChangeBorder(action.args.object, action.args.oldColor, false)
        this.activeObject = action.args.object
    }
    else if (action.name == ACTION_ADD_EDGE) {
        this.RemoveEdge(action.args.edge, false)
        this.activeObject = null
    }
    else if (action.name == ACTION_ADD_TEXT) {
        this.RemoveText(action.args.text, false)
        this.activeObject = null
    }
    else if (action.name == ACTION_REMOVE_EDGE) {
        this.AddEdge(action.args.edge, false)
        this.activeObject = action.args.edge
    }
    else if (action.name == ACTION_REMOVE_TEXT) {
        this.AddText(action.args.text, false)
        this.activeObject = action.args.text
    }
    else if (action.name == ACTION_DIRECT_EDGE) {
        this.ChangeEdgeDirected(action.args.edge, false)
        this.activeObject = action.args.edge
    }
    else if (action.name == ACTION_CHANGE_DIRECTION_EDGE) {
        this.ChangeEdgeDirection(action.args.edge, false)
        this.activeObject = action.args.edge
    }
    else if (action.name == ACTION_CHANGE_EDGE_CONTROL_STEP) {
        action.args.edge.SetControlStep(action.args.prev)
        this.activeObject = action.args.edge
    }
    else if (action.name == ACTION_REMOVE_SELECTION) {
        this.PasteSelection(action.args.selection, false)
        this.activeObject = action.args.selection
    }
    else if (action.name == ACTION_PASTE_SELECTION) {
        this.RemoveSelection(action.args.selection, false)
        this.activeObject = null
    }
    else if (action.name == ACTION_MOVE) {
        this.Move(action.args.object, -action.args.dx, -action.args.dy, false)
        this.activeObject = action.args.object
    }
    else if (action.name == ACTION_EDIT) {
        action.args.object.SetText(action.args.prevText)
        this.activeObject = action.args.object
    }
    else if (action.name == ACTION_PLACE) {
        for (let movement of action.args.movements) {
            this.Move(movement.vertex, -movement.dx, -movement.dy, false)
        }

        this.activeObject = null
    }
    else if (action.name == ACTION_CHANGE_FONT_SIZE) {
        this.ChangeFontSize(action.args.object, -action.args.step, false)
        this.activeObject = action.args.object
    }
    else if (action.name == ACTION_INCREASE_DECREASE) {
        this.IncreaseDecrease(action.args.object, -action.args.step, false)
        this.activeObject = action.args.object
    }
    else if (action.name == ACTION_CHANGE_SETTINGS) {
        this.ChangeSettings(action.args.object, action.args.prevParams, false)
    }
    else if (action.name == ACTION_END_BLOCK) {
        this.redo.push(action)

        while (this.undo[this.undo.length - 1].name != ACTION_BEGIN_BLOCK)
            this.Undo()

        this.redo.push(this.undo.pop())
        this.activeObject = this.redo[this.redo.length - 1].args.object || null
        return
    }

    this.redo.push(action)
}

// повтор отменённого действия
GraphRedactor.prototype.Redo = function() {
    if (this.redo.length == 0)
        return

    let action = this.redo.pop()

    if (action.name == ACTION_ADD_VERTEX) {
        this.AddVertex(action.args.vertex, false)
        this.activeObject = action.args.vertex
    }
    else if (action.name == ACTION_REMOVE_VERTEX) {
        this.RemoveVertex(action.args.vertex, false)
        this.activeObject = null
    }
    else if (action.name == ACTION_CHANGE_BACKGROUD) {
        this.ChangeBackground(action.args.object, action.args.newColor, false)
        this.activeObject = action.args.object
    }
    else if (action.name == ACTION_CHANGE_COLOR) {
        this.ChangeColor(action.args.object, action.args.newColor, false)
        this.activeObject = action.args.object
    }
    else if (action.name == ACTION_CHANGE_BORDER) {
        this.ChangeBorder(action.args.object, action.args.newColor, false)
        this.activeObject = action.args.object
    }
    else if (action.name == ACTION_ADD_EDGE) {
        this.AddEdge(action.args.edge, false)
        this.activeObject = action.args.edge
    }
    else if (action.name == ACTION_ADD_TEXT) {
        this.AddText(action.args.text, false)
        this.activeObject = action.args.text
    }
    else if (action.name == ACTION_REMOVE_EDGE) {
        this.RemoveEdge(action.args.edge, false)
        this.activeObject = null
    }
    else if (action.name == ACTION_REMOVE_TEXT) {
        this.RemoveText(action.args.text, false)
        this.activeObject = null
    }
    else if (action.name == ACTION_DIRECT_EDGE) {
        this.ChangeEdgeDirected(action.args.edge, false)
        this.activeObject = action.args.edge
    }
    else if (action.name == ACTION_CHANGE_DIRECTION_EDGE) {
        this.ChangeEdgeDirection(action.args.edge, false)
        this.activeObject = action.args.edge
    }
    else if (action.name == ACTION_CHANGE_EDGE_CONTROL_STEP) {
        action.args.edge.SetControlStep(action.args.step)
        this.activeObject = action.args.edge
    }
    else if (action.name == ACTION_REMOVE_SELECTION) {
        this.RemoveSelection(action.args.selection, false)
        this.activeObject = null
    }
    else if (action.name == ACTION_PASTE_SELECTION) {
        this.PasteSelection(action.args.selection, false)
        this.activeObject = action.args.selection
    }
    else if (action.name == ACTION_MOVE) {
        this.Move(action.args.object, action.args.dx, action.args.dy, false)
        this.activeObject = action.args.object
    }
    else if (action.name == ACTION_EDIT) {
        action.args.object.SetText(action.args.newText)
        this.activeObject = action.args.object
    }
    else if (action.name == ACTION_PLACE) {
        for (let movement of action.args.movements) {
            this.Move(movement.vertex, movement.dx, movement.dy, false)
        }

        this.activeObject = null
    }
    else if (action.name == ACTION_CHANGE_FONT_SIZE) {
        this.ChangeFontSize(action.args.object, action.args.step, false)
        this.activeObject = action.args.object
    }
    else if (action.name == ACTION_INCREASE_DECREASE) {
        this.IncreaseDecrease(action.args.object, action.args.step, false)
        this.activeObject = action.args.object
    }
    else if (action.name == ACTION_CHANGE_SETTINGS) {
        this.ChangeSettings(action.args.object, action.args.params, false)
    }
    else if (action.name == ACTION_BEGIN_BLOCK) {
        this.undo.push(action)

        while (this.redo[this.redo.length - 1].name != ACTION_END_BLOCK)
            this.Redo()

        this.undo.push(this.redo.pop())
        this.activeObject = action.args.object || null
        return
    }

    this.undo.push(action)
}

// создание нового объекта
GraphRedactor.prototype.MakeNewObject = function(ctrlKey = false, altKey = false) {
    let object = this.GetObjectAt()

    if (this.IsText(object))
        return object

    if (!this.IsVertex(object)) {
        if (!this.vertices.IsEmpty()) {
            this.tips[TIP_EDGE_CREATE].Show()
        }

        let prevVertex = this.IsVertex(this.activeObject) ? this.activeObject : null
        let vertex = this.CreateVertex(this.currRealPoint.x, this.currRealPoint.y)

        if (prevVertex != null) {
            this.CreateEdge(prevVertex, vertex, ctrlKey ? '1' : '', altKey)
        }

        return vertex
    }
    
    if (this.IsVertex(this.activeObject)) {
        this.tips[TIP_EDGE_WEIGHTED_CREATE].Show()
        return this.CreateEdge(this.activeObject, object, ctrlKey ? '1' : '', altKey)
    }

    return object
}

// можно ли скопировать активный компонент
GraphRedactor.prototype.CanCopy = function() {
    return this.IsVertex(this.activeObject) || this.IsText(this.activeObject) || this.IsCreatedSelection(this.activeObject)
}

// можно ли перемещать объект
GraphRedactor.prototype.CanMove = function(object, dx, dy) {
    if (this.IsSelection(object))
        return object.CanMove()

    if (this.IsVertex(object)) {
        let dst = this.leftMenu.width - this.x0 - object.x * this.scale
        return dst > 0 && dx > 0 || dst - dx * this.scale <= 0
    }

    if (this.IsText(object)) {
        let dst = this.leftMenu.width - this.x0 - object.x * this.scale
        return dst > 0 && dx > 0 || dst - dx * this.scale <= 0
    }

    return this.IsEdge(object) || this.IsInput(object)
}

// можно ли удалить активный компонент
GraphRedactor.prototype.CanRemove = function() {
    return this.IsVertex(this.activeObject) || this.IsEdge(this.activeObject) || this.IsText(this.activeObject) || this.IsCreatedSelection(this.activeObject)
}

// можно ли редактировать активный компонент
GraphRedactor.prototype.CanEdit = function() {
    return this.IsVertex(this.activeObject) || this.IsEdge(this.activeObject) || this.IsText(this.activeObject) || this.IsInput(this.activeObject) || this.IsRandomGraphForm(this.activeObject) || this.IsSettingsForm(this.activeObject)
}

// можно ли начать редактировать
GraphRedactor.prototype.CanStartEdit = function() {
    return this.IsVertex(this.activeObject) || this.IsEdge(this.activeObject) || this.IsText(this.activeObject) || this.IsInput(this.activeObject)
}

// редактируется ли активный объект
GraphRedactor.prototype.IsEdit = function() {
    return this.CanEdit() && this.activeObject.IsEdit()
}

// начало редактирования
GraphRedactor.prototype.StartEdit = function() {
    if (!this.CanStartEdit())
        return

    this.activeObject.StartEdit()
    this.isPressed = false
    this.CloseColorPicker()

    if (this.isTouch) {
        this.keyboard.SetMode(this.IsEdge(this.activeObject) ? KEYBOARD_NUMERIC_MODE : KEYBOARD_RUSSIAN_MODE)
    }
}

// завершение редактирования
GraphRedactor.prototype.EndEdit = function() {
    if (!this.CanStartEdit())
        return

    this.activeObject.EndEdit()
}

// нужно ли проверять наведение мыши у элементов
GraphRedactor.prototype.NeedCheckObjectHover = function() {
    if (this.isPressed)
        return false

    for (let icon of Object.values(this.icons))
        if (icon.IsMouseHover(this.width, this.height, this.currPoint.x, this.currPoint.y))
            return false

    if (this.leftMenu.IsMouseHover(this.currPoint.x, this.currPoint.y))
        return false

    for (let menu of this.menus)
        if (menu.IsVisible() && menu.IsMouseHover(this.currPoint.x, this.currPoint.y))
            return false

    if (this.hotkeys.IsVisible())
        return false

    if (this.IsInput(this.activeObject) || this.IsAnimation(this.activeObject) || this.IsIntro(this.activeObject) || this.IsRandomGraphForm(this.activeObject) || this.IsSettingsForm(this.activeObject))
        return false

    if (this.NeedKeyboard() && this.keyboard.IsMouseHover(this.currPoint.x, this.currPoint.y))
        return false

    return true
}

// нужна ли клавиатурв
GraphRedactor.prototype.NeedKeyboard = function() {
    return this.isTouch && this.IsEdit()
}

// нужно ли отрисовывать совет
GraphRedactor.prototype.NeedDrawTip = function(tip) {
    if (!this.isTouch)
        return true

    return [this.tips[TIP_EDGE_CREATE], this.tips[TIP_EDGE_WEIGHTED_CREATE], this.tips[TIP_SELECT_ALL]].indexOf(tip) == -1
}

// запуск ввода матрицы смежности
GraphRedactor.prototype.StartMatrixInput = function(writeCurrentGraph = true) {
    this.Escape()
    let text = []

    if (writeCurrentGraph) {
        for (let row of this.GetAdjacencyMatrix())
            text.push(row.join(', '))
    }

    let bbox = this.GetViewAreaBoundingBox()
    let x = (bbox.xmin + bbox.xmax) / 2
    let y = (bbox.ymin + bbox.ymax) / 2
    let width = Math.min(INPUT_MIN_WIDTH, bbox.width)
    let height = Math.min(INPUT_MIN_HEIGHT, bbox.height)

    let matrixInput = new Input('Матрица смежности', x, y, width, height)
    matrixInput.SetText(text.join('\n'))
    matrixInput.AddButton('Сохранить', () => { this.TryCreateFromMatrix(!writeCurrentGraph) })
    matrixInput.AddButton('Отменить', () => { this.Escape() })
    matrixInput.Move(0, -matrixInput.input.GetHeight() / 2)

    this.activeObject = matrixInput
    this.StartEdit()
}

// запуск ввода матрицы инцидентности
GraphRedactor.prototype.StartIncidenceMatrixInput = function(writeCurrentGraph = true) {
    this.Escape()
    let text = []

    if (writeCurrentGraph) {
        for (let row of this.GetIncidenceMatrix())
            text.push(row.join(', '))
    }

    let bbox = this.GetViewAreaBoundingBox()
    let x = (bbox.xmin + bbox.xmax) / 2
    let y = (bbox.ymin + bbox.ymax) / 2
    let width = Math.min(INPUT_MIN_WIDTH, bbox.width)
    let height = Math.min(INPUT_MIN_HEIGHT, bbox.height)

    let matrixInput = new Input('Матрица инцидентности', x, y, width, height)
    matrixInput.AddButton('Сохранить', () => { this.TryCreateFromIncidenceMatrix(!writeCurrentGraph) })
    matrixInput.AddButton('Отменить', () => { this.Escape() })
    matrixInput.SetText(text.join('\n'))
    matrixInput.Move(0, -matrixInput.input.GetHeight() / 2)

    this.activeObject = matrixInput
    this.StartEdit()
}

// запуск ввода списка связности
GraphRedactor.prototype.StartConnectivityListInput = function(writeCurrentGraph = true) {
    this.Escape()
    let text = []

    if (writeCurrentGraph) {
        let list = this.GetConnectivityList()

        for (let i = 0; i < this.vertices.Count(); i++) {
            let line = this.vertices.Get(i).GetName() + ': ';
            let names = []

            for (let node of list[i])
                names.push(this.vertices.Get(node.vertex).GetName())

            text.push(line + names.join(', '))
        }
    }

    let bbox = this.GetViewAreaBoundingBox()
    let x = (bbox.xmin + bbox.xmax) / 2
    let y = (bbox.ymin + bbox.ymax) / 2
    let width = Math.min(INPUT_MIN_WIDTH, bbox.width)
    let height = Math.min(INPUT_MIN_HEIGHT, bbox.height)

    let listInput = new Input('Список связности', x, y, width, height)
    listInput.AddButton('Сохранить', () => { this.TryCreateFromConnectivityList(!writeCurrentGraph) })
    listInput.AddButton('Отменить', () => { this.Escape() })
    listInput.SetText(text.join('\n'))
    listInput.Move(0, -listInput.input.GetHeight() / 2)

    this.activeObject = listInput
    this.StartEdit()
}

// запуск ввода матрицы
GraphRedactor.prototype.StartEdgeListInput = function(writeCurrentGraph = true) {
    this.Escape()
    let text = []

    if (writeCurrentGraph) {
        for (let edge of this.GetEdgeList()) {
            if (edge.vertex1.indexOf(' ') > -1)
                edge.vertex1 = '"' + edge.vertex1 + '"'

            if (edge.vertex2.indexOf(' ') > -1)
                edge.vertex2 = '"' + edge.vertex2 + '"'

            let edgeString = `${edge.vertex1} ${edge.isDirected ? '->' : '--'} ${edge.vertex2}`

            if (edge.weight != '')
                edgeString += ` ${edge.weight}`

            text.push(edgeString)
        }
    }

    let bbox = this.GetViewAreaBoundingBox()
    let x = (bbox.xmin + bbox.xmax) / 2
    let y = (bbox.ymin + bbox.ymax) / 2
    let width = Math.min(INPUT_MIN_WIDTH, bbox.width)
    let height = Math.min(INPUT_MIN_HEIGHT, bbox.height)

    let edgeListInput = new Input('Список рёбер', x, y, width, height)
    edgeListInput.SetText(text.join('\n'))
    edgeListInput.AddButton('Сохранить', () => { this.TryCreateFromEdgeList(!writeCurrentGraph) })
    edgeListInput.AddButton('Отменить', () => { this.Escape() })
    edgeListInput.Move(0, -edgeListInput.input.GetHeight() / 2)

    this.activeObject = edgeListInput
    this.StartEdit()
}

// закрытие активного поля ввода
GraphRedactor.prototype.CloseInput = function() {
    while (this.undo.length > 0 && this.undo[this.undo.length - 1].args.object == this.activeObject)
        this.undo.pop()

    while (this.redo.length > 0 && this.redo[this.redo.length - 1].args.object == this.activeObject)
        this.redo.pop()

    this.activeObject = null
}

// проверка текста на пустоту
GraphRedactor.prototype.CheckEmptyInputText = function(text, message) {
    if (text != '')
        return false

    if (!this.vertices.IsEmpty()) {
        if (!confirm(message + " Вы уверены, что хотите очистить граф?\nОтменить данное действие будет невозможно"))
            return true

        this.ClearGraph()
    }

    this.CloseInput()
    return true
}

// попытка создать граф из матрицы смежности
GraphRedactor.prototype.TryCreateFromMatrix = function(create = false) {
    let text = this.activeObject.GetText()

    if (this.CheckEmptyInputText(text, 'Матрица смежности пуста.'))
        return

    let result = this.ValidateMatrixInput(text)

    if (result.matrix == null) {
        alert(result.message)
        return
    }

    if (!create) {
        let currMatrix = this.GetAdjacencyMatrix()

        if (currMatrix.length == result.matrix.length) {
            this.UpdateFromMatrix(result.matrix)
            this.CloseInput()
            return
        }
    }

    if (!confirm("Вы уверены, что хотите создать граф из этой матрицы смежности?\nОтменить данное действие будет невозможно"))
        return

    this.CreateFromMatrix(result.matrix)
}

// получение ребра по имени вершин
GraphRedactor.prototype.GetEdgeByVerticesNames = function(name1, name2) {
    for (let edge of this.edges)
        if (edge.vertex1.GetText() == name1 && edge.vertex2.GetText() == name2)
            return edge

    return null
}

// попытка создать граф из списка рёбер
GraphRedactor.prototype.TryCreateFromEdgeList = function(create = false) {
    let text = this.activeObject.GetText()

    if (this.CheckEmptyInputText(text, 'Список рёбер пуст.'))
        return

    let result = this.ValidateEdgeListInput(text)

    if (result.edges == null) {
        alert(result.message)
        return
    }

    this.CloseInput()

    if (create) {
        if (!confirm("Вы уверены, что хотите создать граф из этого списка рёбер?\nОтменить данное действие будет невозможно"))
            return

        this.CreateFromEdges(result.edges)
    }
    else {
        this.UpdateFromEdges(result.edges)
    }
}

// попытка создать граф из матрицы инцидентности
GraphRedactor.prototype.TryCreateFromIncidenceMatrix = function(create = false) {
    let text = this.activeObject.GetText()

    if (this.CheckEmptyInputText(text, 'Матрица инцидентности пуста.'))
        return

    let result = this.ValidateIncidenceMatrixInput(text)

    if (result.matrix == null) {
        alert(result.message)
        return
    }

    if (!create && this.vertices.Count() == result.matrix.length) {
        this.UpdateFromIncidenceMatrix(result.matrix)
        this.CloseInput()
        return
    }

    if (!confirm("Вы уверены, что хотите создать граф из этой матрицы инцидентности?\nОтменить данное действие будет невозможно"))
        return

    this.CreateFromIncidenceMatrix(result.matrix)
}

// попытка создать граф из списка смежности
GraphRedactor.prototype.TryCreateFromConnectivityList = function(create = false) {
    let text = this.activeObject.GetText()

    if (this.CheckEmptyInputText(text, 'Список связности пуст.'))
        return

    let result = this.ValidateConnectivityListInput(text)

    if (result.list == null) {
        alert(result.message)
        return
    }

    if (!confirm("Вы уверены, что хотите создать граф из этого списка связности?\nОтменить данное действие будет невозможно"))
        return

    this.CreateFromConnectivityList(result.list)
}

// выделение всех объектов
GraphRedactor.prototype.SelectAll = function() {
    if (this.vertices.IsEmpty() && this.texts.length == 0)
        return

    let selection = new Selection(0, 0)

    for (let vertex of this.vertices.Iterator())
        selection.AddVertex(vertex)

    for (let edge of this.edges)
        selection.AddEdge(edge, true)

    for (let text of this.texts)
        selection.AddText(text)

    selection.Finalize()
    this.activeObject = selection
}

// получение аргументов перемещения по клавише
GraphRedactor.prototype.GetMoveArgsByKeys = function(key) {
    let dx = 0
    let dy = 0

    if (key == 'ArrowLeft') {
        dx = -GRID_SIZE
    }
    else if (key == 'ArrowRight') {
        dx = GRID_SIZE
    }
    else if (key == 'ArrowDown') {
        dy = GRID_SIZE
    }
    else if (key == 'ArrowUp') {
        dy = -GRID_SIZE
    }

    return { dx: dx, dy: dy }
}

// закрытие всех меню
GraphRedactor.prototype.CloseMenus = function() {
    for (let menu of this.menus) {
        menu.SetVisible(false)
    }

    this.hotkeys.SetVisible(false)
}

// обработка клавишы escape
GraphRedactor.prototype.Escape = function() {
    this.EndEdit()

    if (this.IsInput(this.activeObject)) {
        this.CloseInput()
    }
    else if (this.IsExampleCreator(this.activeObject)) {
        this.activeObject.ResetScroll()
    }
    else if (this.IsVerticesSelection(this.activeObject) || this.IsGraphsSelection(this.activeObject)) {
        this.activeObject.Clear()
    }

    this.CloseMenus()
    this.CloseColorPicker()

    this.activeObject = null
    this.isPressed = false
}

// изменение отображения левого меню
GraphRedactor.prototype.ToggleLeftMenu = function() {
    if (this.IsInput(this.activeObject))
        return

    if (this.leftMenu.isFull || this.width > MIN_WIDTH_FOR_FULL_WIDTH_LEFT_MENU)
        this.leftMenu.Toggle()
}

// переход на следующую вершину
GraphRedactor.prototype.GoToNextVertex = function(dir) {
    if (this.IsInput(this.activeObject) || this.IsRandomGraphForm(this.activeObject) || this.IsSettingsForm(this.activeObject))
        return

    if (this.vertices.IsEmpty())
        return

    this.EndEdit()
    this.activeObject = this.vertices.GetNext(this.IsVertex(this.activeObject) ? this.activeObject : null, dir)

    let bbox = this.GetViewAreaBoundingBox()
    let x0 = this.activeObject.x * this.scale + this.x0
    let y0 = this.activeObject.y * this.scale + this.y0

    if (x0 < bbox.xmin) {
        this.x0 = bbox.xmin + (this.activeObject.radius + GRID_SIZE - this.activeObject.x) * this.scale
    }
    else if (x0 > bbox.xmax) {
        this.x0 = bbox.xmax - (this.activeObject.radius + GRID_SIZE + this.activeObject.x) * this.scale
    }

    if (y0 < bbox.ymin) {
        this.y0 = bbox.ymin + (this.activeObject.radius + GRID_SIZE - this.activeObject.y) * this.scale
    }
    else if (y0 > bbox.ymax) {
        this.y0 = bbox.ymax - (this.activeObject.radius + GRID_SIZE + this.activeObject.y) * this.scale
    }
}

// поиск ближайшей вершины
GraphRedactor.prototype.FindNearestVertex = function() {
    if (this.IsInput(this.activeObject))
        return

    if (this.vertices.IsEmpty())
        return

    this.Escape()
    let bbox = this.GetViewAreaBoundingBox()
    let x0 = (bbox.xmin + bbox.xmax) / 2
    let y0 = (bbox.ymin + bbox.ymax) / 2

    let x = (x0 - this.x0) / this.scale
    let y = (y0 - this.y0) / this.scale

    this.activeObject = this.vertices.GetNearest(x, y)
    this.x0 = x0 - this.activeObject.x * this.scale
    this.y0 = y0 - this.activeObject.y * this.scale
}

// масштабирование к графу
GraphRedactor.prototype.ScaleToGraph = function() {
    if (this.vertices.IsEmpty() && this.texts.length == 0) {
        this.SetScale(1)
        this.x0 = 0
        this.y0 = 0
        return
    }

    let graphBbox = this.GetBoundingBox()
    let realBbox = this.GetViewAreaBoundingBox()

    let scaleX = realBbox.width / this.scale / graphBbox.width
    let scaleY = realBbox.height / this.scale / graphBbox.height
    let scale = Math.min(scaleX, scaleY)

    if (scale < 1) {
        this.SetScale(Round(this.scale * scale, 1000))
    }

    let realX0 = (realBbox.xmin + realBbox.xmax) / 2
    let realY0 = (realBbox.ymin + realBbox.ymax) / 2

    let graphX0 = (graphBbox.xmin + graphBbox.xmax) / 2
    let graphY0 = (graphBbox.ymin + graphBbox.ymax) / 2

    this.x0 = realX0 - graphX0 * this.scale
    this.y0 = realY0 - graphY0 * this.scale
}

// можно ли обновить масштаб
GraphRedactor.prototype.CanUpdateScale = function(step) {
    return this.scaleIndex + step >= 0 && this.scaleIndex + step < this.scales.length
}

// изменение индекса масштабирования
GraphRedactor.prototype.UpdateScaleIndex = function(step) {
    if (this.scale != this.scales[this.scaleIndex]) {
        if (step < 0) {
            this.scaleIndex = 0

            while (this.scaleIndex < this.scales.length - 1 && this.scales[this.scaleIndex + 1] < this.scale)
                this.scaleIndex++
        }
        else {
            this.scaleIndex = this.scales.length - 1

            while (this.scaleIndex > 0 && this.scales[this.scaleIndex - 1] > this.scale)
                this.scaleIndex--
        }
    }
    else {
        this.scaleIndex += step
    }
}

// обновление масштабирования
GraphRedactor.prototype.UpdateScale = function(step, toCenter = false) {
    if (!this.CanUpdateScale(step))
        return

    let x = this.currPoint.x
    let y = this.currPoint.y

    if (x < 0 || y < 0 || x >= this.width || y >= this.height || toCenter) {
        x = this.width / 2
        y = this.height / 2
    }

    let dw = (x - this.x0) / this.scale
    let dh = (y - this.y0) / this.scale

    this.UpdateScaleIndex(step)

    let index = 0
    let scale = Math.pow(this.scales[this.scaleIndex] / this.scale, 1 / SCALE_TRANSITION_ITERATIONS)

    if (this.interval)
        clearInterval(this.interval)

    this.interval = setInterval(() => {
        this.scale = index < SCALE_TRANSITION_ITERATIONS ? this.scale * scale : this.scales[this.scaleIndex]
        this.x0 = x - dw * this.scale
        this.y0 = y - dh * this.scale
        index++

        if (index > SCALE_TRANSITION_ITERATIONS)
            clearInterval(this.interval)
    }, SCALE_TRANSITION_PERIOD)
}

// установка масштаба
GraphRedactor.prototype.SetScale = function(scale) {
    let x = this.currPoint.x
    let y = this.currPoint.y

    if (x < 0 || y < 0 || x >= this.width || y >= this.height) {
        x = this.width / 2
        y = this.height / 2
    }

    let dw = (x - this.x0) / this.scale
    let dh = (y - this.y0) / this.scale

    this.scale = Math.max(SCALE_VALUES[0], Math.min(SCALE_VALUES[SCALE_VALUES.length - 1], scale))
    this.x0 = x - dw * this.scale
    this.y0 = y - dh * this.scale
}

// переход на инструкцию
GraphRedactor.prototype.GoToInstruction = function() {
    let link = document.createElement("a")
    link.href = INSTRUCTION_LINK
    link.target = '_blank'
    link.click()
}

GraphRedactor.prototype.ChangeSettings = function(object, params, addToUndo = true) {
    let prevParams = object.GetParams()

    if (JSON.stringify(params) == JSON.stringify(prevParams))
        return

    object.SetParams(params)

    if (addToUndo) {
        this.AddAction(ACTION_CHANGE_SETTINGS, { object: object, prevParams: prevParams, params: object.GetParams() })
    }
}

GraphRedactor.prototype.ApplySettings = function() {
    this.AddAction(ACTION_BEGIN_BLOCK, {})

    for (let vertex of this.vertices.Iterator())
        this.ChangeSettings(vertex, settings.vertex)

    for (let edge of this.edges)
        this.ChangeSettings(edge, settings.edge)

    for (let text of this.texts)
        this.ChangeSettings(text, settings.text)

    this.AddAction(ACTION_END_BLOCK, {})
}
