// восстановление пути
function RestoreWay(finish, parents) {
    let way = [] // выделяем память под массив для пути

    for (let v = finish; v != -1; v = parents[v])
        way.push(v)

    return way.reverse()
}

// получение ребра по списку смежности
function GetEdge(vertex1, vertex2, list) {
    for (let node of list[vertex1])
        if (node.vertex == vertex2)
            return node.edge

    return null
}

// наличие рёбер отрицательного веса
GraphRedactor.prototype.HaveNegativeEdges = function() {
    for (let edge of this.edges)
        if (edge.GetWeight() < 0)
            return true

    return false
}

GraphRedactor.prototype.Dijkstra = function(startVertex, finishVertex) {
    let animation = new Animation("dijkstra.gif")
    let list = this.GetConnectivityList()
    let start = this.vertices.IndexOf(startVertex)
    let finish = this.vertices.IndexOf(finishVertex)
    let names = []

    let distances = [] // расстояния от вершины start до любой другой
    let parents = [] // массив предков всех вершин
    let visited = [] // массив флагов посещённости вершин
    let statuses = []
    let labels = []
    let vertices = this.vertices.ToArray()

    for (let i = 0; i < vertices.length; i++) {
        distances[i] = Infinity // изначально все расстояния бесконечны
        parents[i] = -1 // ни у кого нет родителя
        visited[i] = false // изначально ни одна вершина не была использована
        names[i] = vertices[i].GetName()
        statuses[i] = DEFAULT_STATUS
        labels[i] = '∞'
    }

    animation.AddAction(ANIMATE_GRAPH, {
        vertices: vertices,
        edges: [],
        labels: labels.slice(),
        statuses: statuses.slice(),
        text: ''
    }, ALGORITHMS_ANIMATION_TIME)

    distances[start] = 0 // расстояние от start до start равно нулю
    labels[start] = '0'
    statuses[start] = SELECTED_STATUS
    statuses[start] = HOT_STATUS
    statuses[finish] = HOT_STATUS

    for (let i = 0; i < vertices.length; i++) {
        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: [],
            labels: labels.slice(),
            statuses: statuses.slice(),
            text: 'Ищем непосещённую вершину с наименьшей меткой'
        }, ALGORITHMS_ANIMATION_TIME)

        let v = -1

        // ищем вершину с наименьшим расстоянием
        for (let j = 0; j < vertices.length; j++)
            if (!visited[j] && (v == -1 || distances[j] < distances[v]))
                v = j

        // если расстояние бесконечно, значит пути быть не может
        if (distances[v] == Infinity)
            break

        visited[v] = true // помечаем вершину как посещённую
        statuses[v] = ANIMATED_STATUS

        // проходимся по всем смежным с v вершинам
        for (let j = 0; j < list[v].length; j++) {
            text = 'Проверяем все смежные с ' + vertices[v].GetName() + ' вершины: '
            animation.AddAction(ANIMATE_GRAPH, {
                vertices: vertices,
                edges: [list[v][j].edge],
                labels: labels.slice(),
                statuses: statuses.slice(),
                text: text
            }, ALGORITHMS_ANIMATION_TIME)

            if (distances[v] + list[v][j].edge.GetWeight() < distances[list[v][j].vertex]) {
                labels[list[v][j].vertex] = labels[v] + '+' + list[v][j].edge.GetWeight() + '<' + labels[list[v][j].vertex]
                animation.AddAction(ANIMATE_GRAPH, {
                    vertices: vertices,
                    edges: [list[v][j].edge],
                    labels: labels.slice(),
                    statuses: statuses.slice(),
                    text: 'Обновляем метку у вершины ' + vertices[list[v][j].vertex].GetName()
                }, ALGORITHMS_ANIMATION_TIME)

                distances[list[v][j].vertex] = distances[v] + list[v][j].edge.GetWeight() // обновляем расстояния
                parents[list[v][j].vertex] = v // обновляем родителя

                labels[list[v][j].vertex] = distances[list[v][j].vertex] + ''
                text = 'Кратчайшие расстояния: ' + labels.join(', ')

                animation.AddAction(ANIMATE_GRAPH, {
                    vertices: vertices,
                    edges: [list[v][j].edge],
                    labels: labels.slice(),
                    statuses: statuses.slice(),
                    text: text
                }, ALGORITHMS_ANIMATION_TIME)
            }
        }

        statuses[v] = VISITED_STATUS
        statuses[start] = HOT_STATUS
        statuses[finish] = HOT_STATUS
    }

    // если нет родителя конечной вершины, значит пути нет
    if (distances[finish] == Infinity) {
        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: [],
            labels: labels.slice(),
            statuses: statuses.slice(),
            text: `Путь между вершинами ${startVertex.GetName()} и ${finishVertex.GetName()} отсутствует`
        }, ALGORITHMS_ANIMATION_TIME)
    }
    else { // иначе восстанавливаем путь до конечной вершины
        let wayNames = []
        let way = RestoreWay(finish, parents)

        for (let v of way) {
            wayNames.push(names[v])
            statuses[v] = ANIMATED_STATUS
        }

        let edges = []

        for (let i = 1; i < way.length; i++)
            edges.push(GetEdge(way[i - 1], way[i], list))

        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: edges.slice(),
            labels: labels.slice(),
            statuses: statuses.slice(),
            text: `Кратчайший путь: ${wayNames.join(', ')}, длина: ${distances[finish]}`
        }, ALGORITHMS_ANIMATION_TIME)

        animation.SetSaveInfo({ vertices: vertices.filter((v, i) => statuses[i] == ANIMATED_STATUS), edges: edges.slice() })
    }

    animation.Start()
    this.activeObject = animation
}
;
