GraphRedactor.prototype.FindAllPaths = function(startVertex, finishVertex) {
    let start = this.vertices.IndexOf(startVertex)
    let finish = this.vertices.IndexOf(finishVertex)
    let list = this.GetConnectivityList()
    let animation = new Animation("find_all_paths.gif")

    let paths = []
    let vertices = this.vertices.ToArray()
    let visited = vertices.map((v) => false)

    this.FindAllPathsRecursive(list, start, finish, visited, [], paths)
    paths.sort((a, b) => a.length - b.length)
    
    for (let i = 0; i < paths.length; i++) {
        let path = paths[i]

        let edges = []
        let statuses = []
        let edgeStatuses = []

        for (let j = 0; j < vertices.length; j++)
            statuses[j] = VISITED_STATUS

        for (let j = 0; j < path.length - 1; j++) {
            edges.push(GetEdge(path[j], path[j + 1], list))
            edgeStatuses[j] = ANIMATED_STATUS
        }

        for (let v of path)
            statuses[v] = ANIMATED_STATUS

        statuses[start] = HOT_STATUS
        statuses[finish] = HOT_STATUS

        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: edges,
            statuses: statuses,
            edgeStatuses: edgeStatuses,
            text: `Количество путей из ${startVertex.GetName()} в ${finishVertex.GetName()}: ${paths.length}\nПуть ${i + 1}: ${path.map((v) => vertices[v].GetName()).join(" → ")}`
        }, ALGORITHMS_ANIMATION_TIME)
    }

    if (paths.length == 0) {
        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: this.edges,
            statuses: vertices.map((v) => VISITED_STATUS),
            edgeStatuses: this.edges.map((v) => VISITED_STATUS),
            text: `Нет путей из ${startVertex.GetName()} в ${finishVertex.GetName()}`
        }, ALGORITHMS_ANIMATION_TIME)
    }

    animation.Start()
    this.activeObject = animation
}

GraphRedactor.prototype.FindAllPathsRecursive = function(list, start, finish, visited, path, paths) {
    visited[start] = true
    path.push(start)

    if (start == finish) {
        paths.push(path.slice())
    }
    else {
        for (let node of list[start])
            if (!visited[node.vertex])
                this.FindAllPathsRecursive(list, node.vertex, finish, visited, path, paths)
    }

    path.pop()
    visited[start] = false
}
;
GraphRedactor.prototype.MatrixToText = function(matrix) {
    let text = []

    for (let i = 0; i < matrix.length; i++) {
        let row = []

        for (let j = 0; j < matrix[i].length; j++)
            if (matrix[i][j] == Infinity) {
                row.push('∞')
            }
            else {
                row.push(matrix[i][j])
            }

        text.push(row.join(', '))
    }

    return text.join('\n')
}

GraphRedactor.prototype.FloydWarshall = function() {
    let bbox = this.GetViewAreaBoundingBox()
    let x = (bbox.xmin + bbox.xmax) / 2
    let y = (bbox.ymin + bbox.ymax) / 2
    let width = Math.min(INPUT_MIN_WIDTH, bbox.width)
    let height = Math.min(INPUT_MIN_HEIGHT, bbox.height)

    let animation = new Animation("floyd_warshall.gif")
    let vertices =this.vertices.ToArray()

    let distances = [] // матрица длин путей

    for (let i = 0; i < vertices.length; i++) {
        distances[i] = []

        for (let j = 0; j < vertices.length; j++)
            distances[i][j] = Infinity // изначально путей нет

        distances[i][i] = 0
    }

    for (let edge of this.edges) {
        let v1 = this.vertices.IndexOf(edge.vertex1)
        let v2 = this.vertices.IndexOf(edge.vertex2)
        let weight = edge.GetWeight()

        distances[v1][v2] = weight // запоминаем расстояние

        if (!edge.IsDirected()) {
            distances[v2][v1] = weight // запоминаем расстояние
        }
    }

    let input = new Input('Матрица расстояний', x, y, width, height, true)
    input.SetText(this.MatrixToText(distances))
    input.Move(0, -input.input.GetHeight() / 2)
    animation.AddAction(ANIMATE_INPUT, { input: input, text: 'Формируем начальную матрицу расстояний' }, ALGORITHMS_ANIMATION_TIME)

    // выполняем алгоритм Флойда-Уоршаллла
    for (let k = 0; k < vertices.length; k++) {
        for (let i = 0; i < vertices.length; i++) {
            for (let j = 0; j < vertices.length; j++) {
                if (distances[i][j] > distances[i][k] + distances[k][j]) {
                    let text = `Проверяем расстояние между ${vertices[i].GetName()} и ${vertices[j].GetName()}\n${distances[i][k]}+${distances[k][j]}<${(distances[i][j] == Infinity ? '∞' : distances[i][j])}\nОбновляем расстояние`
                    input = new Input('Матрица расстояний', x, y, width, height, true)
                    input.SetText(this.MatrixToText(distances))
                    input.Move(0, -input.input.GetHeight() / 2)
                    animation.AddAction(ANIMATE_INPUT, { input: input, text: text }, ALGORITHMS_ANIMATION_TIME)

                    distances[i][j] = distances[i][k] + distances[k][j]
                }
            }
        }
    }

    input = new Input('Матрица расстояний', x, y, width, height, true)
    input.SetText(this.MatrixToText(distances))
    input.Move(0, -input.input.GetHeight() / 2)
    animation.AddAction(ANIMATE_INPUT, { input: input, text: 'Расстояния между вершинами' }, ALGORITHMS_ANIMATION_TIME)

    animation.Start()
    this.activeObject = animation
    console.log(distances.map(row => row.join(", ")).join("\n"))
}
;
GraphRedactor.prototype.Kruskal=function(){if(!this.IsConnected()){alert("Граф не является связным. Минимальное остовное дерево можно строить только у связногых графов")
return}let animation=new Animation("kruskal_algorithm.gif")
let edges=[]
for(let edge of this.edges)edges.push(edge)
edges.sort((a,b)=>{return a.GetWeight()-b.GetWeight()})
let length=0
let treeId=[]
let labels=[]
let statuses=[]
let vertices=this.vertices.ToArray()
for(let i=0;i<vertices.length;i++){treeId[i]=i
labels[i]=(i+1)+''
statuses[i]=DEFAULT_STATUS}animation.AddAction(ANIMATE_GRAPH,{vertices:vertices,edges:[],statuses:statuses.slice(),labels:labels,text:'Сортируем рёбра по убыванию веса, помечаем каждую вершину уникальной меткой'},ALGORITHMS_ANIMATION_TIME)
let tree=[]
let edgeStatuses=[]
for(let edge of edges){let v1=this.vertices.IndexOf(edge.vertex1)
let v2=this.vertices.IndexOf(edge.vertex2)
let name=edge.GetName()
animation.AddAction(ANIMATE_GRAPH,{vertices:vertices,edges:tree.slice().concat([edge]),labels:labels.slice(),statuses:statuses.slice(),edgeStatuses:edgeStatuses.slice().concat([SELECTED_STATUS]),text:'Проверяем ребро '+name},ALGORITHMS_ANIMATION_TIME)
if(treeId[v1]!=treeId[v2]){tree.push(edge)
statuses[v1]=ANIMATED_STATUS
statuses[v2]=ANIMATED_STATUS
edgeStatuses.push(ANIMATED_STATUS)
animation.AddAction(ANIMATE_GRAPH,{vertices:vertices,edges:tree.slice(),labels:labels.slice(),statuses:statuses.slice(),edgeStatuses:edgeStatuses.slice(),text:'Добавляем ребро '+name+' в дерево и обновляем метки'},ALGORITHMS_ANIMATION_TIME)
length+=edge.GetWeight()
let oldId=treeId[v2]
let newId=treeId[v1]
for(let i=0;i<vertices.length;i++){if(treeId[i]==oldId){treeId[i]=newId
labels[i]=(newId+1)+''}}}}let text='Вес минимального остовного дерева: '+length
if(this.IsDirected())text+='\nОриентация дуг была проигнорирована, так как остовное дерево можно строить только для неориентированных графов'
animation.AddAction(ANIMATE_GRAPH,{vertices:vertices,edges:tree.slice(),statuses:statuses,text:text},0)
animation.Start()
animation.SetSaveInfo({vertices:vertices,edges:tree.slice()})
this.activeObject=animation}
;
// минимальное остовное дерево
GraphRedactor.prototype.Prim = function() {
    if (!this.IsConnected()) {
        alert("Граф не является связным. Минимальное остовное дерево можно строить только у связногых графов")
        return
    }

    let animation = new Animation("prim_algorithm.gif")
    let list = this.GetConnectivityList(true)

    let visited = [] // массив флагов посещения вершин
    let minEdge = [] // массив минимальных длин рёбер
    let endEdge = [] // массив концов вершин в остовном дереве
    let statuses = []
    let labels = []
    let vertices = this.vertices.ToArray()

    for (let i = 0; i < this.vertices.Count(); i++) {
        visited[i] = false // ни одна вершина не была посещена
        minEdge[i] = Infinity // минимальная длина равна бесконечности
        endEdge[i] = -1 // ни одного конца нет
        statuses[i] = DEFAULT_STATUS
        labels[i] = '∞'
    }

    let edgeStatuses = []

    for (let i = 0; i < this.edges.length; i++)
        edgeStatuses[i] = DEFAULT_STATUS

    length = 0 // длина остовного дерева
    minEdge[0] = 0 // начинаем с нулевой вершины
    labels[0] = '0'
    let tree = []

    for (let i = 0; i < vertices.length; i++) {
        animation.AddAction(ANIMATE_GRAPH, { vertices: vertices, edges: this.edges, labels: labels.slice(), statuses: statuses.slice(), edgeStatuses: edgeStatuses.slice(), text: 'Ищем непосещённую вершину с наименьшей меткой' }, ALGORITHMS_ANIMATION_TIME)
        let v = -1

        // ищем непосещённую вершину с минимальным весом
        for (let j = 0; j < vertices.length; j++)
            if (!visited[j] && (v == -1 || minEdge[j] < minEdge[v]))
                v = j

        visited[v] = true // помечаем её как посещённую
        statuses[v] = ANIMATED_STATUS

        if (endEdge[v] != -1) {
            length += minEdge[v] // наращиваем длину остовного дерева

            let edge = GetEdge(endEdge[v], v, list)
            tree.push(edge)
            edgeStatuses[this.edges.indexOf(edge)] = ANIMATED_STATUS
            animation.AddAction(ANIMATE_GRAPH, { vertices: vertices, edges: this.edges, labels: labels.slice(), statuses: statuses.slice(), edgeStatuses: edgeStatuses.slice(), text: `Добавляем ребро ${edge.GetName()}` }, ALGORITHMS_ANIMATION_TIME)
        }

        for (let j = 0; j < list[v].length; j++) {
            let weight = list[v][j].edge.GetWeight()
            let edgeIndex = this.edges.indexOf(list[v][j].edge)

            let status = statuses[list[v][j].vertex]
            statuses[list[v][j].vertex] = SELECTED_STATUS

            if (edgeStatuses[edgeIndex] != ANIMATED_STATUS)
                edgeStatuses[edgeIndex] = SELECTED_STATUS

            animation.AddAction(ANIMATE_GRAPH, { vertices: vertices, edges: this.edges, labels: labels.slice(), statuses: statuses.slice(), edgeStatuses: edgeStatuses.slice(), text: 'Проверяем все смежные с ' + vertices[v].GetName() + ' вершины: ' }, ALGORITHMS_ANIMATION_TIME)

            if (weight < minEdge[list[v][j].vertex]) { // если нашли ребро с меньшим весом
                labels[list[v][j].vertex] = weight + '<' + labels[list[v][j].vertex]
                animation.AddAction(ANIMATE_GRAPH, { vertices: vertices, edges: this.edges, labels: labels.slice(), statuses: statuses.slice(), edgeStatuses: edgeStatuses.slice(), text: 'Обновляем метку' }, ALGORITHMS_ANIMATION_TIME)

                minEdge[list[v][j].vertex] = weight; // обновляем минимальный вес
                endEdge[list[v][j].vertex] = v; // запоминаем конец
                labels[list[v][j].vertex] = weight + ''
                animation.AddAction(ANIMATE_GRAPH, { vertices: vertices, edges: this.edges, labels: labels.slice(), statuses: statuses.slice(), edgeStatuses: edgeStatuses.slice(), text: 'Обновляем метку' }, ALGORITHMS_ANIMATION_TIME)
            }

            statuses[list[v][j].vertex] = status

            if (edgeStatuses[edgeIndex] != ANIMATED_STATUS)
                edgeStatuses[edgeIndex] = DEFAULT_STATUS
        }

        statuses[v] = VISITED_STATUS
    }

    for (let edge of tree) {
        statuses[this.vertices.IndexOf(edge.vertex1)] = ANIMATED_STATUS
        statuses[this.vertices.IndexOf(edge.vertex2)] = ANIMATED_STATUS
    }

    let text = 'Вес минимального остовного дерева: ' + length

    if (this.IsDirected())
        text += '\nОриентация дуг была проигнорирована, так как остовное дерево можно строить только для неориентированных графов'

    animation.AddAction(ANIMATE_GRAPH, { vertices: vertices, edges: tree.slice(), statuses: statuses, text: text }, 0)
    animation.Start()
    animation.SetSaveInfo({ vertices: vertices, edges: tree.slice() })

    this.activeObject = animation
}
;
// обход в глубину для поиска компонент связности
GraphRedactor.prototype.ConnectivityComponentsDFS = function(u, vertices, list, visited, component, animation, names, labels, statuses, edgeStatuses, label) {
    visited[u] = true // помечаем вершину как посещённую
    component.push(u)
    names.push(vertices[u].GetText())

    // проходимся по смежным с u вершинам
    for (let i = 0; i < list[u].length; i++) {
        if (visited[list[u][i].vertex]) // если вершина была посещена
            continue

        labels[list[u][i].vertex] = label
        statuses[list[u][i].vertex] = ANIMATED_STATUS
        edgeStatuses[this.edges.indexOf(list[u][i].edge)] = ANIMATED_STATUS

        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: this.edges,
            labels: labels.slice(),
            statuses: statuses.slice(),
            edgeStatuses: edgeStatuses.slice(),
            text: 'Текушая компонента связости: ' + names.join(', ')
        }, ALGORITHMS_ANIMATION_TIME)

        this.ConnectivityComponentsDFS(list[u][i].vertex, vertices, list, visited, component, animation, names, labels, statuses, edgeStatuses, label) // посещаем её
    }
}

// компоненты связности
GraphRedactor.prototype.ConnectivityComponents = function() {
    let list = this.GetConnectivityList(true)
    let vertices = this.vertices.ToArray()

    let animation = new Animation("connectivity_components.gif")
    let visited = [] // выделяем память для массива флагов посещения вершин
    let components = []
    let statuses = []
    let edgeStatuses = []

    for (let i = 0; i < vertices.length; i++) {
        visited[i] = false // ни одна вершина ещё не была посещена
        components[i] = ''
        statuses[i] = DEFAULT_STATUS
    }

    for (let i = 0; i < this.edges.length; i++)
        edgeStatuses[i] = DEFAULT_STATUS

    let componentCount = 0

    for (let i = 0; i < vertices.length; i++) {
        if (visited[i]) // если вершина уже посещена
            continue; // идём дальше

        componentCount++
        components[i] = componentCount + ''
        statuses[i] = ANIMATED_STATUS

        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: this.edges,
            statuses: statuses.slice(),
            edgeStatuses: edgeStatuses.slice(),
            labels: components.slice(),
            text: `Запускаем обход в глубину из вершины ${vertices[i].GetName()}`
        }, ALGORITHMS_ANIMATION_TIME)

        let names = []
        let component = []
        this.ConnectivityComponentsDFS(i, vertices, list, visited, component, animation, names, components, statuses, edgeStatuses, componentCount + '')

        for (let i = 0; i < this.edges.length; i++) {
            let v1 = this.vertices.IndexOf(this.edges[i].vertex1)
            let v2 = this.vertices.IndexOf(this.edges[i].vertex2)

            if (component.indexOf(v1) > -1 || component.indexOf(v2) > -1)
                edgeStatuses[i] = ANIMATED_STATUS
        }

        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: this.edges,
            statuses: statuses.slice(),
            edgeStatuses: edgeStatuses.slice(),
            labels: components.slice(),
            text: 'Компонента слабой связности ' + componentCount + ': ' + component.map((v) => vertices[v].GetName()).join(", ")
        }, ALGORITHMS_ANIMATION_TIME)
    }

    animation.AddAction(ANIMATE_GRAPH, {
        vertices: vertices,
        edges: this.edges,
        text: `Компоненты слабой связости (${componentCount})`,
        labels: components,
        edgeStatuses: edgeStatuses
    }, ALGORITHMS_ANIMATION_TIME)
    animation.Start()

    this.activeObject = animation
}
;
