GraphRedactor.prototype.IsomorphismCheckVertices = function(graph1, graph2, animation, statuses, edgeStatuses, vertices) {
    let checkVertex = graph1.vertices.size == graph2.vertices.size

    animation.AddAction(ANIMATE_GRAPH, {
        vertices: vertices,
        edges: this.edges,
        statuses: statuses,
        edgeStatuses: edgeStatuses,
        text: checkVertex ? 'Количество вершин совпадает, проверяем количество рёбер' : `Количество вершин не совпадает (${graph1.vertices.size} ≠ ${graph2.vertices.size}).\nГрафы неизоморфны`
    }, ALGORITHMS_ANIMATION_TIME)

    if (checkVertex)
        return true

    animation.Start()
    this.activeObject = animation
    return false
}

GraphRedactor.prototype.IsomorphismCheckEdges = function(graph1, graph2, animation, statuses, edgeStatuses, vertices) {
    let checkEdges = graph1.edges.size == graph2.edges.size

    animation.AddAction(ANIMATE_GRAPH, {
        vertices: vertices,
        edges: this.edges,
        statuses: statuses,
        edgeStatuses: edgeStatuses,
        text: checkEdges ? 'Количество рёбер совпадает, проверяем степени вершин' : `Количество рёбер не совпадает (${graph1.edges.size} ≠ ${graph2.edges.size}).\nГрафы неизоморфны`
    }, ALGORITHMS_ANIMATION_TIME)

    if (checkEdges)
        return true
    
    animation.Start()
    this.activeObject = animation
    return false
}

GraphRedactor.prototype.IsomorphismCheckGetDegrees = function(graphs, statuses, graphStatuses) {
    let degrees = [[], []]
    let allDegrees = []
    let isDirected = [false, false]
    let vertices = this.vertices.ToArray()

    for (let i = 0; i < vertices.length; i++) {
        if (statuses[i] == VISITED_STATUS) {
            allDegrees[i] = null
            continue
        }

        let graphIndex = graphStatuses.indexOf(statuses[i])
        let graph = graphs[graphIndex]
        let degree = {in: 0, out: 0, vertexIndex: i, graphIndex: graphIndex}

        for (let edge of graph.edges) {
            if (edge.vertex1 == vertices[i] || edge.vertex2 == vertices[i] && !edge.IsDirected())
                degree.out++

            if (edge.vertex2 == vertices[i] || edge.vertex1 == vertices[i] && !edge.IsDirected())
                degree.in++

            if (edge.IsDirected())
                isDirected[graphIndex] = true
        }

        degrees[graphIndex].push(degree)
        allDegrees[i] = degree
    }

    for (let degree of degrees)
        degree.sort((a, b) => a.in != b.in ? a.in - b.in : a.out - b.out)

    return {degrees, allDegrees, isDirected}
}

GraphRedactor.prototype.IsomorphismCheckDegrees = function(graph1, graph2, animation, statuses, edgeStatuses, graphStatuses, vertices) {
    let graphs = [graph1, graph2]
    let {degrees, allDegrees, isDirected} = this.IsomorphismCheckGetDegrees(graphs, statuses, graphStatuses)

    if (isDirected[0] != isDirected[1]) {
        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: this.edges,
            statuses: statuses,
            edgeStatuses: edgeStatuses,
            labels: allDegrees.map((v) => v == null ? '' : !isDirected[v.graphIndex] ? `deg=${v.in}` : `in:${v.in}, out:${v.out}`),
            text: `Первый граф ${isDirected[0] ? '' : 'не'}ориентирован, а второй ${isDirected[1] ? '' : 'не'}ориентирован.\nГрафы неизоморфны`
        }, ALGORITHMS_ANIMATION_TIME)

        return null
    }

    let checkDegrees = true
    let conform = []

    for (let i = 0; i < degrees[0].length && checkDegrees; i++) {
        checkDegrees &= degrees[0][i].in == degrees[1][i].in && degrees[0][i].out == degrees[1][i].out

        let deg1 = degrees[0][i]
        let deg2 = degrees[1][i]

        if (i == 0 || degrees[0][i].in != degrees[0][i - 1].in || degrees[0][i].out != degrees[0][i - 1].out)
            conform.push({ in: degrees[0][i].in, out: degrees[0][i].out, first: [], second: []})

        conform[conform.length - 1].first.push(deg1.vertexIndex)
        conform[conform.length - 1].second.push(deg2.vertexIndex)
    }

    animation.AddAction(ANIMATE_GRAPH, {
        vertices: vertices,
        edges: this.edges,
        statuses: statuses,
        edgeStatuses: edgeStatuses,
        labels: allDegrees.map((v) => v == null ? '' : !isDirected[v.graphIndex] ? `deg=${v.in}` : `in:${v.in}, out:${v.out}`),
        text: checkDegrees ? 'Степени совпадают, ищем соответствие' : `Степени вершин не совпадают.\nГрафы неизоморфны`
    }, ALGORITHMS_ANIMATION_TIME)

    if (!checkDegrees)
        return null

    return conform
}

GraphRedactor.prototype.IsomorphismCheckGetMatrix = function(graph, vertices) {
    let matrix = []

    for (let i = 0; i < vertices.length; i++) {
        matrix[i] = []

        for (let j = 0; j < vertices.length; j++)
            matrix[i][j] = 0
    }

    for (let edge of graph.edges) {
        let v1 = vertices.indexOf(edge.vertex1)
        let v2 = vertices.indexOf(edge.vertex2)

        matrix[v1][v2] = 1

        if (!edge.IsDirected())
            matrix[v2][v1] = 1
    }

    return matrix
}

GraphRedactor.prototype.IsomorphismCheckIsMatrixEquals = function(matrix1, matrix2) {
    for (let i = 0; i < matrix1.length; i++)
        for (let j = 0; j < matrix1[i].length; j++)
            if (matrix1[i][j] != matrix2[i][j])
                return false

    return true
}

GraphRedactor.prototype.IsomorphismCheckConforms = function(conform, graph1, graph2, animation, statuses, edgeStatuses, graphStatuses, vertices) {
    let vertices1 = []
    let vertices2 = []
    let restrictions = []

    for (let part of conform) {
        vertices1 = vertices1.concat(part.first.map((v) => this.vertices.Get(v)))
        vertices2 = vertices2.concat(part.second.map((v) => this.vertices.Get(v)))
        restrictions.push(part.second.length)
    }

    let permutations = GetPermutationsWithRestrictions(restrictions)
    let matrix1 = this.IsomorphismCheckGetMatrix(graph1, vertices1)

    for (let permutation of permutations) {
        let testVertices = permutation.map((v) => vertices2[v])
        let matrix = this.IsomorphismCheckGetMatrix(graph2, testVertices)

        if (!this.IsomorphismCheckIsMatrixEquals(matrix1, matrix))
            continue

        let edges = []
        let parts = []
        let labels = new Array(this.vertices.Count()).fill('')

        for (let edge of this.edges)
            edges.push(edge)

        for (let i = 0; i < testVertices.length; i++) {
            let edge = new Edge(vertices1[i], testVertices[i], '', false)
            edges.push(edge)
            edgeStatuses.push(DOTTED_STATUS)
            parts.push(`${vertices1[i].GetName()} → ${testVertices[i].GetName()}`)

            labels[this.vertices.IndexOf(vertices1[i])] = testVertices[i].GetName()
            labels[this.vertices.IndexOf(testVertices[i])] = vertices1[i].GetName()
        }

        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: edges,
            statuses: statuses,
            edgeStatuses: edgeStatuses,
            labels: labels,
            text: `Соответствие найдено:${parts.join(', ')}\nГрафы изоморфны`
        }, ALGORITHMS_ANIMATION_TIME)

        return
    }

    animation.AddAction(ANIMATE_GRAPH, {
        vertices: vertices,
        edges: this.edges,
        statuses: statuses,
        edgeStatuses: edgeStatuses,
        text: `Не удалось найти соответствие вершин.\nГрафы неизоморфны`
    }, ALGORITHMS_ANIMATION_TIME)
}

GraphRedactor.prototype.IsomorphismCheck = function(graph1, graph2) {
    let animation = new Animation("isomorphism_check.gif")

    let statuses = []
    let edgeStatuses = []
    let graphStatuses = [RED_STATUS, BLUE_STATUS]
    let vertices = this.vertices.ToArray()

    for (let vertex of vertices) {
        if (graph1.vertices.has(vertex))
            statuses.push(graphStatuses[0])
        else if (graph2.vertices.has(vertex))
            statuses.push(graphStatuses[1])
        else
            statuses.push(VISITED_STATUS)
    }

    for (let edge of this.edges) {
        if (graph1.edges.has(edge))
            edgeStatuses.push(graphStatuses[0])
        else if (graph2.edges.has(edge))
            edgeStatuses.push(graphStatuses[1])
        else
            edgeStatuses.push(VISITED_STATUS)
    }

    if (!this.IsomorphismCheckVertices(graph1, graph2, animation, statuses, edgeStatuses, vertices))
        return

    if (!this.IsomorphismCheckEdges(graph1, graph2, animation, statuses, edgeStatuses, vertices))
        return

    let conform = this.IsomorphismCheckDegrees(graph1, graph2, animation, statuses, edgeStatuses, graphStatuses, vertices)

    if (conform != null)
        this.IsomorphismCheckConforms(conform, graph1, graph2, animation, statuses, edgeStatuses, graphStatuses, vertices)

    animation.Start()
    this.activeObject = animation
}
;
GraphRedactor.prototype.SplitIntoTwoParts = function() {
    let animation = new Animation("split_into_two_parts.gif")
    let list = this.GetConnectivityList()
    let vertices = this.vertices.ToArray()

    let part = [] // доли вершин
    let labels = []
    let statuses = []
    let queue = [] // выделяем память для очереди

    for (let i = 0; i < vertices.length; i++) {
        part[i] = -1 // изначально доли неизвестны
        labels[i] = ''
        statuses[i] = DEFAULT_STATUS
    }

    let isBipartite = true // двудольный ли граф

    for (let i = 0; i < vertices.length && isBipartite; i++) {
        if (part[i] != -1) // если доля уже определена
            continue; // идём дальше

        let queueStart = 0 // начало очереди
        let queueEnd = 0 // конец очереди

        queue[queueEnd++] = i // добавляем вершину в очередь
        part[i] = 0 // кладём вершину в первую долю
        labels[i] = '1'
        statuses[i] = BLUE_STATUS

        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: [],
            statuses: statuses.slice(),
            labels: labels.slice(),
            text: `Добавляем вершину ${vertices[i].GetName()} в очередь\nОчередь: ${queue.slice(queueStart, queueEnd).map((v) => vertices[v].GetName()).join(',')}`
        }, ALGORITHMS_ANIMATION_TIME)

        while (queueStart < queueEnd && isBipartite) {
            let v = queue[queueStart++]; // извлекаем вершину из очереди

            statuses[v] = GREEN_STATUS
            animation.AddAction(ANIMATE_GRAPH, {
                vertices: vertices,
                edges: [],
                statuses: statuses.slice(),
                labels: labels.slice(),
                text: `Извлекаем вершину из очереди (${vertices[v].GetName()}) и проверяем смежные с ней вершины\nОчередь: ${queue.slice(queueStart, queueEnd).map((v) => vertices[v].GetName()).join(',')}`
            }, ALGORITHMS_ANIMATION_TIME)

            for (let j = 0; j < list[v].length && isBipartite; j++) {
                if (part[list[v][j].vertex] == -1) { // если доля не задана для вершины
                    part[list[v][j].vertex] = !part[v] // то задаём противоположную долю
                    labels[list[v][j].vertex] = (part[list[v][j].vertex] + 1) + ''
                    statuses[list[v][j].vertex] = part[list[v][j].vertex] ? RED_STATUS : BLUE_STATUS
                    queue[queueEnd++] = list[v][j].vertex // и кладём смежную вершину в очередь
                    
                    animation.AddAction(ANIMATE_GRAPH, {
                        vertices: vertices,
                        edges: [list[v][j].edge],
                        statuses: statuses.slice(),
                        labels: labels.slice(),
                        text: `Обновляем долю вершины ${vertices[list[v][j].vertex].GetName()} и помещаем её в очередь\nОчередь: ${queue.slice(queueStart, queueEnd).map((v) => vertices[v].GetName()).join(',')}`
                    }, ALGORITHMS_ANIMATION_TIME)
                }
                else if (part[list[v][j].vertex] == part[v]) {
                    isBipartite = false

                    statuses[list[v][j].vertex] = RED_STATUS

                    animation.AddAction(ANIMATE_GRAPH, {
                        vertices: vertices,
                        edges: [list[v][j].edge],
                        statuses: statuses.slice(),
                        labels: labels.slice(),
                        text: `Доли смежных вершин совпадают, граф невозможно разбить на две доли`
                    }, ALGORITHMS_ANIMATION_TIME)
                }
            }

            statuses[v] = part[v] ? RED_STATUS : BLUE_STATUS
        }
    }

    if (isBipartite) {
        let names1 = []
        let names2 = []
        let resultVertices = []
        let edges = []

        for (let i = 0; i < vertices.length; i++) {
            if (part[i] == 0) {
                names1.push(vertices[i].GetName())
            }
            else {
                names2.push(vertices[i].GetName())
            }

            let vertex = vertices[i].Copy()

            vertex.SetBackground(VERTEX_BACKGROUND_COLOR[statuses[i]])
            vertex.SetBorder(VERTEX_BORDER_COLOR[statuses[i]])
            vertex.SetColor(VERTEX_TEXT_COLOR[statuses[i]])
            resultVertices.push(vertex)
        }

        for (let edge of this.edges) {
            let copy = edge.Copy()
            copy.vertex1 = resultVertices[this.vertices.IndexOf(edge.vertex1)]
            copy.vertex2 = resultVertices[this.vertices.IndexOf(edge.vertex2)]
            edges.push(copy)
        }

        animation.AddAction(ANIMATE_GRAPH, {
            vertices: resultVertices,
            edges: [],
            statuses: statuses,
            labels: labels,
            text: `Полученные доли: {${names1.join(', ')}} и {${names2.join(', ')}}`
        }, ALGORITHMS_ANIMATION_TIME)

        animation.SetSaveInfo({ vertices: resultVertices, edges: edges })
    }

    animation.Start()

    this.activeObject = animation
}
;
// центр графа
GraphRedactor.prototype.Center = function() {
    if (!this.IsConnected()) {
        alert("Граф не связный. Для поиска центра граф должен быть связным")
        return
    }

    let distances = this.GetFloydWarshall()

    let e = [] // выделяем память под эксцентриситеты
    let radius = Infinity
    let diameter = 0
    let labels = []
    let names = []
    let statuses = []
    let vertices = this.vertices.ToArray()

    for (let i = 0; i < vertices.length; i++) {
        labels[i] = ''
        statuses[i] = DEFAULT_STATUS
    }

    let animation = new Animation("center_radius_diameter.gif")

    for (let i = 0; i < vertices.length; i++) {
        e[i] = 0

        statuses[i] = ACTIVE_STATUS
        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: [],
            statuses: statuses.slice(),
            labels: labels.slice(),
            text: `Текущий радиус: ${FloatToStr(radius)}\nТекущий диаметр: ${FloatToStr(diameter)}\nВычисляем эксцентриситет вершины ${vertices[i].GetName()}`
        }, ALGORITHMS_ANIMATION_TIME)
        
        // расчитываем эксцентриситет вершины i
        for (let j = 0; j < vertices.length; j++)
            if (distances[i][j] > e[i])
                e[i] = distances[i][j];

        diameter = Math.max(diameter, e[i])
        labels[i] = 'e=' + FloatToStr(e[i]) + ''
        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: [],
            statuses: statuses.slice(),
            labels: labels.slice(),
            text: `Текущий радиус: ${FloatToStr(radius)}\nТекущий диаметр: ${FloatToStr(diameter)}\nЭксцентриситет вершины ${vertices[i].GetName()} = ${e[i]}`
        }, ALGORITHMS_ANIMATION_TIME)

        statuses[i] = DEFAULT_STATUS

        if (e[i] < radius) { // если эксцентриситет меньше радиуса
           radius = e[i] // обновляем радиус
        }
    }

    // выводим центр
    for (let i = 0; i < vertices.length; i++) {
        if (e[i] == radius) {
            animation.AddAction(ANIMATE_GRAPH, {
                vertices: vertices,
                edges: [],
                statuses: statuses.slice(),
                labels: labels.slice(),
                text: `Помечаем вершины с эксцентриситетом равным ${FloatToStr(radius)}`
            }, ALGORITHMS_ANIMATION_TIME)
            names.push(vertices[i].GetName())
            statuses[i] = ANIMATED_STATUS
        }
    }

    for (let i = 0; i < vertices.length; i++)
        if (e[i] != radius)
            statuses[i] = VISITED_STATUS

    let text = 'Радиус: ' +FloatToStr(radius) + '\nДиаметр: ' + FloatToStr(diameter) + '\nЦентр: ' + names.join(', ')
    animation.AddAction(ANIMATE_GRAPH, { vertices: vertices, edges: [], labels: labels, statuses: statuses, text: text }, ALGORITHMS_ANIMATION_TIME)
    animation.Start()

    this.activeObject = animation
}
;
GraphRedactor.prototype.FindLoopDFS=function(v,vertices,list,colors,parents,loop,isDirected,animation,statuses,edgeStatuses){colors[v]=1
statuses[v]=SELECTED_STATUS
for(let i=0;i<list[v].length;i++){let to=list[v][i].vertex
if(colors[to]==0||(colors[to]==1&&(isDirected||parents[v]!=to))){statuses[to]=SELECTED_STATUS
edgeStatuses[this.edges.indexOf(list[v][i].edge)]=SELECTED_STATUS
let text=''
if(colors[to]==1&&(isDirected||parents[v]!=to)){text='Обнаружен цикл из вершины '+vertices[to].GetName()+' в вершину '+vertices[v].GetName()}else{text='Запускаем обход в глубину из вершины '+vertices[to].GetName()}animation.AddAction(ANIMATE_GRAPH,{vertices:vertices,edges:this.edges,statuses:statuses.slice(),edgeStatuses:edgeStatuses.slice(),text:text},ALGORITHMS_ANIMATION_TIME)}if(colors[to]==0){parents[to]=v
if((isDirected||parents[v]!=to)&&this.FindLoopDFS(to,vertices,list,colors,parents,loop,isDirected,animation,statuses,edgeStatuses))return true}else if(colors[to]==1&&(isDirected||parents[v]!=to)){loop.end=v
loop.start=to
return true}}colors[v]=2
statuses[v]=VISITED_STATUS
if(parents[v]>-1){edgeStatuses[this.edges.indexOf(GetEdge(v,parents[v],list))]=DEFAULT_STATUS
edgeStatuses[this.edges.indexOf(GetEdge(parents[v],v,list))]=DEFAULT_STATUS}let vertex=0;while(vertex<vertices.length&&colors[vertex]==2)vertex++
if(vertex<vertices.length){animation.AddAction(ANIMATE_GRAPH,{vertices:vertices,edges:this.edges,statuses:statuses.slice(),edgeStatuses:edgeStatuses.slice(),text:'Помечаем вершину '+vertices[v].GetName()},ALGORITHMS_ANIMATION_TIME)}return false}
GraphRedactor.prototype.FindLoop=function(){let isDirected=this.IsDirected()
let list=this.GetConnectivityList()
let parents=[]
let colors=[]
let vertices=this.vertices.ToArray()
for(let i=0;i<vertices.length;i++){parents[i]=-1
colors[i]=0}let animation=new Animation("find_loop.gif")
let loop={start:-1,end:-1,vertices:[]}
let statuses=[]
let edgeStatuses=[]
for(let i=0;i<vertices.length;i++){statuses[i]=DEFAULT_STATUS}for(let i=0;i<vertices.length;i++){if(colors[i]==2)continue
for(let i=0;i<this.edges.length;i++)edgeStatuses[i]=DEFAULT_STATUS
statuses[i]=SELECTED_STATUS
animation.AddAction(ANIMATE_GRAPH,{vertices:vertices,edges:this.edges,statuses:statuses.slice(),edgeStatuses:edgeStatuses.slice(),text:'Запускаем обход в глубину из вершины '+vertices[i].GetName()},ALGORITHMS_ANIMATION_TIME)
if(this.FindLoopDFS(i,vertices,list,colors,parents,loop,isDirected,animation,statuses,edgeStatuses))break}if(loop.start==-1){animation.AddAction(ANIMATE_GRAPH,{vertices:[],edges:[],text:'Граф ацикличен'},ALGORITHMS_ANIMATION_TIME)}else{loop.vertices.push(loop.start)
for(let v=loop.end;v!=loop.start;v=parents[v])loop.vertices.push(v)
loop.vertices.push(loop.start)
loop.vertices.reverse()
for(let i=0;i<vertices.length;i++)statuses[i]=DEFAULT_STATUS
for(let i=0;i<this.edges.length;i++)edgeStatuses[i]=DEFAULT_STATUS
for(let v of loop.vertices)statuses[v]=ANIMATED_STATUS
for(let i=1;i<loop.vertices.length;i++){let v1=loop.vertices[i-1]
let v2=loop.vertices[i]
let edge=GetEdge(v1,v2,list)
edgeStatuses[this.edges.indexOf(edge)]=ANIMATED_STATUS}let text='Граф содержит цикл: '+loop.vertices.map((v)=>vertices[v].GetName()).join(', ')
animation.AddAction(ANIMATE_GRAPH,{vertices:vertices,edges:this.edges,statuses:statuses.slice(),edgeStatuses:edgeStatuses.slice(),text:text},ALGORITHMS_ANIMATION_TIME)
animation.SetSaveInfo({vertices:loop.vertices.map((v)=>vertices[v]),edges:this.edges.filter((edge,i)=>edgeStatuses[i]==ANIMATED_STATUS)})}animation.Start()
this.activeObject=animation}
;
// обход в глубину для поиска мостов
GraphRedactor.prototype.FindBridgesDFS = function(v, p, vertices, visited, list, timer, bridges, animation, statuses, labels, edgeStatuses, names) {
    visited[v] = true
    timer.tin[v] = timer.value
    timer.fup[v] = timer.value
    timer.value++

    labels[v] = `tin: ${timer.tin[v]}, fup:${timer.fup[v]}`

    for (let i = 0; i < list[v].length; i++) {
        let to = list[v][i].vertex
        let edge = list[v][i].edge

        if (to == p)
            continue

        statuses[to] = SELECTED_STATUS

        if (visited[to]) {
            if (timer.fup[v] > timer.tin[to]) {
                timer.fup[v] = timer.tin[to]
                labels[v] = `tin:${timer.tin[v]}, fup:${timer.fup[v]}`
                statuses[v] = ANIMATED_STATUS

                animation.AddAction(ANIMATE_GRAPH, {
                    vertices: vertices,
                    edges: this.edges,
                        labels: labels.slice(),
                    statuses: statuses.slice(),
                    edgeStatuses: edgeStatuses.slice(),
                    text: `Вершина ${vertices[to].GetName()} уже посещена. Обновляем метку fup у вершины ${vertices[v].GetName()}`
                }, ALGORITHMS_ANIMATION_TIME)
                
                statuses[v] = SELECTED_STATUS
            }
        }
        else {
            names.push(vertices[to].GetName())

            edgeStatuses[this.edges.indexOf(edge)] = SELECTED_STATUS
            animation.AddAction(ANIMATE_GRAPH, {
                vertices: vertices,
                edges: this.edges,
                    labels: labels.slice(),
                statuses: statuses.slice(),
                edgeStatuses: edgeStatuses.slice(),
                text: 'Обход в глубину из вершины ' + names[0] + ': ' + names.join(', ')
            }, ALGORITHMS_ANIMATION_TIME)

            this.FindBridgesDFS(to, v, vertices, visited, list, timer, bridges, animation, statuses, labels, edgeStatuses, names)
            
            if (timer.fup[v] > timer.fup[to]) {
                timer.fup[v] = timer.fup[to]
                labels[v] = `tin:${timer.tin[v]}, fup:${timer.fup[v]}`
            
                animation.AddAction(ANIMATE_GRAPH, {
                    vertices: vertices,
                    edges: this.edges,
                    labels: labels.slice(),
                    statuses: statuses.slice(),
                    edgeStatuses: edgeStatuses.slice(),
                    text: `Обновляем метку fup у вершины ${vertices[v].GetName()}`
                }, ALGORITHMS_ANIMATION_TIME)
            }

            if (timer.fup[to] > timer.tin[v]) {
                edgeStatuses[this.edges.indexOf(edge)] = ANIMATED_STATUS

                animation.AddAction(ANIMATE_GRAPH, {
                    vertices: vertices,
                    edges: this.edges,
                    labels: labels.slice(),
                    statuses: statuses.slice(),
                    edgeStatuses: edgeStatuses.slice(),
                    text: `fup[${vertices[to].GetName()}] > tin[${vertices[v].GetName()}]. Помечаем ребро как мост`
                }, ALGORITHMS_ANIMATION_TIME)

                bridges.push({ edge: edge, start: v, end: to })
            }
            else {
                edgeStatuses[this.edges.indexOf(edge)] = DEFAULT_STATUS
            }
        }
    }

    statuses[v] = DEFAULT_STATUS

    if (p > -1) {
        edgeStatuses[this.edges.indexOf(GetEdge(p, v, list))] = DEFAULT_STATUS
    }

    animation.AddAction(ANIMATE_GRAPH, {
        vertices: vertices,
        edges: this.edges,
            labels: labels.slice(),
        statuses: statuses.slice(),
        edgeStatuses: edgeStatuses.slice(),
        text: 'Обход в глубину из вершины ' + names[0] + ': ' + names.join(', ')
    }, ALGORITHMS_ANIMATION_TIME)
}

// поиск мостов
GraphRedactor.prototype.FindBridges = function() {
    if (this.IsDirected()) {
        alert("Граф ориентирован. Поиск мостов доступен только для неориентированных графов")
        return
    }

    let animation = new Animation("bridges.gif")
    let timer = { value: 0, tin: [], fup: [] }
    let list = this.GetConnectivityList()
    let vertices = this.vertices.ToArray()

    let visited = []
    let bridges = []
    let statuses = []
    let edgeStatuses = []
    let labels = []

    for (let i = 0; i < vertices.length; i++) {
        visited[i] = false
        statuses[i] = DEFAULT_STATUS
        labels[i] = ''
    }

    for (let i = 0; i < this.edges.length; i++)
        edgeStatuses[i] = DEFAULT_STATUS

    for (let i = 0; i < vertices.length; i++) {
        if (visited[i])
            continue

        statuses[i] = SELECTED_STATUS
        let names = [vertices[i].GetName()]

        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: this.edges,
            labels: labels.slice(),
            statuses: statuses.slice(),
            edgeStatuses: edgeStatuses.slice(),
            text: 'Запускаем обход в глубину из вершины ' + names[0]
        }, ALGORITHMS_ANIMATION_TIME)

        this.FindBridgesDFS(i, -1, vertices, visited, list, timer, bridges, animation, statuses, labels, edgeStatuses, names)
    }

    for (let i = 0; i < vertices.length; i++) {
        labels[i] = ''
        statuses[i] = DEFAULT_STATUS
    }

    for (let i = 0; i < this.edges.length; i++)
        if (edgeStatuses[i] != ANIMATED_STATUS)
            edgeStatuses[i] = DEFAULT_STATUS

    let text = bridges.length == 0 ? 'Мостов не обнаружено' : 'В графе обнаружены мосты (' + bridges.length + ')'
    
    animation.AddAction(ANIMATE_GRAPH, {
        vertices: vertices,
        edges: this.edges,
        labels: labels.slice(),
        statuses: statuses.slice(),
        edgeStatuses: edgeStatuses.slice(),
        text: text
    }, ALGORITHMS_ANIMATION_TIME)

    animation.Start()
    this.activeObject = animation
}
;
// обход в глубину для поиска точек сочленения
GraphRedactor.prototype.FindArticulationPointsDFS = function(v, p, vertices, visited, list, timer, points, animation, statuses, labels, edgeStatuses, names) {
    visited[v] = true
    timer.tin[v] = timer.value
    timer.fup[v] = timer.value
    timer.value++

    labels[v] = `tin:${timer.tin[v]}, fup:${timer.fup[v]}`
    let children = 0

    for (let i = 0; i < list[v].length; i++) {
        let to = list[v][i].vertex
        let edge = list[v][i].edge

        if (to == p)
            continue

        if (visited[to]) {
            if (timer.tin[to] < timer.fup[v]) {
                if (statuses[to] != ANIMATED_STATUS)
                    statuses[to] = SELECTED_STATUS

                timer.fup[v] = timer.tin[to]

                labels[v] = `tin:${timer.tin[v]}, fup:${timer.fup[v]}`

                animation.AddAction(ANIMATE_GRAPH, {
                    vertices: vertices,
                    edges: this.edges,
                        labels: labels.slice(),
                    statuses: statuses.slice(),
                    edgeStatuses: edgeStatuses.slice(),
                    text: `Вершина ${vertices[to].GetName()} уже посещена. Обновляем метку fup у вершины ${vertices[v].GetName()}`
                }, ALGORITHMS_ANIMATION_TIME)
            }
        }
        else {
            if (statuses[to] != ANIMATED_STATUS)
                statuses[to] = SELECTED_STATUS

            names.push(vertices[to].GetName())

            edgeStatuses[this.edges.indexOf(edge)] = SELECTED_STATUS
            animation.AddAction(ANIMATE_GRAPH, {
                vertices: vertices,
                edges: this.edges,
                labels: labels.slice(),
                statuses: statuses.slice(),
                edgeStatuses: edgeStatuses.slice(),
                text: 'Обход в глубину из вершины ' + names[0] + ': ' + names.join(', ')
            }, ALGORITHMS_ANIMATION_TIME)

            this.FindArticulationPointsDFS(to, v, vertices, visited, list, timer, points, animation, statuses, labels, edgeStatuses, names)

            if (timer.fup[to] < timer.fup[v]) {
                timer.fup[v] = timer.fup[to]

                labels[v] = 'tin:' + timer.tin[v] + ', fup:' + timer.fup[v]
            
                animation.AddAction(ANIMATE_GRAPH, {
                    vertices: vertices,
                    edges: this.edges,
                    labels: labels.slice(),
                    statuses: statuses.slice(),
                    edgeStatuses: edgeStatuses.slice(),
                    text: `Обновляем метку fup у вершины ${vertices[v].GetName()}`
                }, ALGORITHMS_ANIMATION_TIME)
            }

            if (timer.fup[to] >= timer.tin[v] && p != -1 && points.indexOf(v) == -1) {
                points.push(v)
                statuses[v] = ANIMATED_STATUS

                animation.AddAction(ANIMATE_GRAPH, {
                    vertices: vertices,
                    edges: this.edges,
                    labels: labels.slice(),
                    statuses: statuses.slice(),
                    edgeStatuses: edgeStatuses.slice(),
                    text: `fup[${vertices[to].GetName()}] >= tin[${vertices[v].GetName()}]. Помечаем вершину ${vertices[v].GetName()} как точку сочленения`
                }, ALGORITHMS_ANIMATION_TIME)
            }

            children++
        }
    }

    if (statuses[v] != ANIMATED_STATUS)
        statuses[v] = DEFAULT_STATUS

    if (p > -1) {
        edgeStatuses[this.edges.indexOf(GetEdge(p, v, list))] = DEFAULT_STATUS
    }

    animation.AddAction(ANIMATE_GRAPH, {
        vertices: vertices,
        edges: this.edges,
            labels: labels.slice(),
        statuses: statuses.slice(),
        edgeStatuses: edgeStatuses.slice(),
        text: `Обход в глубину из вершины ${names[0]}: ${names.join(', ')}`
    }, ALGORITHMS_ANIMATION_TIME)

    if (p == -1 && children > 1 && points.indexOf(v) == -1) {
        points.push(v)

        statuses[v] = ANIMATED_STATUS

        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: this.edges,
            labels: labels.slice(),
            statuses: statuses.slice(),
            edgeStatuses: edgeStatuses.slice(),
            text: `Помечаем вершину ${vertices[v].GetName()} как точку сочленения`
        }, ALGORITHMS_ANIMATION_TIME)
    }
}

// поиск точек сочленения
GraphRedactor.prototype.FindArticulationPoints = function() {
    if (this.IsDirected()) {
        alert("Граф ориентирован. Поиск точек сочленения доступен только для неориентированных графов")
        return
    }

    let animation = new Animation("articulation_points.gif")
    let timer = { value: 0, tin: [], fup: [] }
    let list = this.GetConnectivityList()
    let visited = []
    let points = []
    let statuses = []
    let edgeStatuses = []
    let labels = []
    let vertices = this.vertices.ToArray()

    for (let i = 0; i < vertices.length; i++) {
        visited[i] = false
        statuses[i] = DEFAULT_STATUS
        labels[i] = ''
    }

    for (let i = 0; i < this.edges.length; i++)
        edgeStatuses[i] = DEFAULT_STATUS

    for (let i = 0; i < vertices.length; i++) {
        if (visited[i])
            continue

        statuses[i] = SELECTED_STATUS
        let names = [vertices[i].GetName()]

        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: this.edges,
            labels: labels.slice(),
            statuses: statuses.slice(),
            edgeStatuses: edgeStatuses.slice(),
            text: `Запускаем обход в глубину из вершины ${names[0]}`
        }, ALGORITHMS_ANIMATION_TIME)

        this.FindArticulationPointsDFS(i, -1, vertices, visited, list, timer, points, animation, statuses, labels, edgeStatuses, names)
    }

    for (let i = 0; i < vertices.length; i++) {
        labels[i] = ''

        if (statuses[i] != ANIMATED_STATUS)
            statuses[i] = DEFAULT_STATUS
    }

    for (let i = 0; i < this.edges.length; i++)
        edgeStatuses[i] = DEFAULT_STATUS

    let text = points.length == 0 ? 'Точек сочленения не обнаружено' : 'В графе обнаружены точки сочленения (' + points.length + ')'
    
    animation.AddAction(ANIMATE_GRAPH, {
        vertices: vertices,
        edges: this.edges,
        labels: labels.slice(),
        statuses: statuses.slice(),
        edgeStatuses: edgeStatuses.slice(),
        text: text
    }, ALGORITHMS_ANIMATION_TIME)

    animation.Start()
    this.activeObject = animation
}
;
GraphRedactor.prototype.CalculateDegrees = function() {
    let isDirected = this.IsDirected()
    let animation = new Animation("vertex_degrees.gif")
    let list = this.GetConnectivityList()

    let statuses = []
    let labels = []
    let edgeStatuses = []
    let vertices = this.vertices.ToArray()

    for (let i = 0; i < vertices.length; i++) {
        statuses[i] = DEFAULT_STATUS
        labels[i] = ''
    }

    for (let i = 0; i < this.edges.length; i++) {
        edgeStatuses[i] = DEFAULT_STATUS
    }

    let maxDegreeIn = 0
    let maxDegreeOut = 0

    let minDegreeIn = Infinity
    let minDegreeOut = Infinity

    for (let i = 0; i < vertices.length; i++) {
        labels[i] = isDirected ? 'in=0, out=0' : 'deg=0'
        statuses[i] = ANIMATED_STATUS

        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: this.edges,
            statuses: statuses.slice(),
            labels: labels.slice(),
            edgeStatuses: edgeStatuses.slice(),
            text: 'Расчитываем ' + (isDirected ? 'полустепени исхода и захода' : 'степень') + ' для вершины ' + vertices[i].GetName()
        }, ALGORITHMS_ANIMATION_TIME)

        let degreeIn = 0
        let degreeOut = 0

        for (let j = 0; j < this.edges.length; j++) {
            if (this.edges[j].vertex1 != vertices[i] && this.edges[j].vertex2 != vertices[i])
                continue

            if (this.edges[j].vertex1 == vertices[i] || (!this.edges[j].IsDirected() && this.edges[j].vertex2 == vertices[i])) {
                degreeOut++
                edgeStatuses[j] = SELECTED_STATUS
            }

            if (this.edges[j].vertex2 == vertices[i] || (!this.edges[j].IsDirected() && this.edges[j].vertex1 == vertices[i])) {
                edgeStatuses[j] = SELECTED_STATUS
                degreeIn++
            }

            if (!isDirected && this.edges[j].IsLoop()) {
                degreeIn++
                degreeOut++
            }

            labels[i] = isDirected ? 'in=' + degreeIn + ', out=' + degreeOut : 'deg=' + degreeIn

            animation.AddAction(ANIMATE_GRAPH, {
                vertices: vertices,
                edges: this.edges,
                statuses: statuses.slice(),
                labels: labels.slice(),
                edgeStatuses: edgeStatuses.slice(),
                text: `Расчитываем ${(isDirected ? 'полустепени исхода и захода' : 'степень')} для вершины ${vertices[i].GetName()}: ${labels[i]}`
            }, ALGORITHMS_ANIMATION_TIME)
            
            edgeStatuses[j] = DEFAULT_STATUS
        }

        maxDegreeIn = Math.max(maxDegreeIn, degreeIn)
        maxDegreeOut = Math.max(maxDegreeOut, degreeOut)

        minDegreeIn = Math.min(minDegreeIn, degreeIn)
        minDegreeOut = Math.min(minDegreeOut, degreeOut)

        statuses[i] = DEFAULT_STATUS
    }

    let minText = isDirected ? `Минимальная полустепень исхода: ${minDegreeOut}\nМинимальная полустепень захода: ${minDegreeIn}` : `Минимальная степень: ${minDegreeIn}`
    let maxText = isDirected ? `Максимальная полустепень исхода: ${maxDegreeOut}\nМаксимальная полустепень захода: ${maxDegreeIn}` : `Максимальная степень: ${maxDegreeIn}`

    animation.AddAction(ANIMATE_GRAPH, {
        vertices: vertices,
        edges: this.edges,
        statuses: statuses,
        labels: labels,
        edgeStatuses: edgeStatuses,
        text: `${minText}\n${maxText}`
    }, ALGORITHMS_ANIMATION_TIME)

    animation.Start()
    this.activeObject = animation
}
;
// обход в глубину для топологической сортировки
GraphRedactor.prototype.TopologicalSortDFS = function(v, vertices, visited, parents, list, answer, animation, statuses, labels, edgeStatuses, names) {
    visited[v] = true

    for (let i = 0; i < list[v].length; i++) {
        if (visited[list[v][i].vertex])
            continue

        parents[list[v][i].vertex] = v
        edgeStatuses[this.edges.indexOf(list[v][i].edge)] = ANIMATED_STATUS
        statuses[list[v][i].vertex] = ANIMATED_STATUS
        names.push(vertices[list[v][i].vertex].GetName())

        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: this.edges,
            statuses: statuses.slice(),
            edgeStatuses: edgeStatuses.slice(),
            labels: labels.slice(),
            text: `Обход в глубину из вершины ${names[0]}: ${names.join(', ')}`
        }, ALGORITHMS_ANIMATION_TIME)

        this.TopologicalSortDFS(list[v][i].vertex, vertices, visited, parents, list, answer, animation, statuses, labels, edgeStatuses, names)
    }

    statuses[v] = VISITED_STATUS

    if (parents[v] > -1) {
        edgeStatuses[this.edges.indexOf(GetEdge(v, parents[v], list))] = DEFAULT_STATUS
        edgeStatuses[this.edges.indexOf(GetEdge(parents[v], v, list))] = DEFAULT_STATUS
    }

    animation.AddAction(ANIMATE_GRAPH, {
        vertices: vertices,
        edges: this.edges,
        statuses: statuses.slice(),
        edgeStatuses: edgeStatuses.slice(),
        labels: labels.slice(),
        text: `Обход в глубину из вершины ${names[0]}: ${names.join(', ')}\nВыходим из вершины ${vertices[v].GetName()}`
    }, ALGORITHMS_ANIMATION_TIME)

    answer.push(v)
}

// топологическая сортировка
GraphRedactor.prototype.TopologicalSort = function() {
    if (!this.IsAcyclic()) {
        alert("Граф содержит цикл. Топологическая сортировка не существует")
        return
    }

    let animation = new Animation("topological_sort.gif")
    let list = this.GetConnectivityList()
    let visited = []
    let parents = []
    let answer = []
    let statuses = []
    let labels = []
    let edgeStatuses = []
    let vertices = this.vertices.ToArray()

    for (let i = 0; i < vertices.length; i++) {
        visited[i] = false
        parents[i] = -1
        statuses[i] = DEFAULT_STATUS
        labels[i] = ''
    }

    for (let i = 0; i < this.edges.length; i++)
        edgeStatuses[i] = DEFAULT_STATUS

    for (let i = 0; i < vertices.length; i++) {
        if (visited[i])
            continue

        statuses[i] = ANIMATED_STATUS
        let names = [vertices[i].GetName()]

        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: this.edges,
            statuses: statuses.slice(),
            edgeStatuses: edgeStatuses.slice(),
            labels: labels.slice(),
            text: 'Обход в глубину из вершины ' + names[0]
        }, ALGORITHMS_ANIMATION_TIME)

        this.TopologicalSortDFS(i, vertices, visited, parents, list, answer, animation, statuses, labels, edgeStatuses, names)
    }

    answer.reverse()

    for (let i = 0; i < vertices.length; i++) {
        labels[answer[i]] = (i + 1) + ''
    }


    let text = 'Топологическая сортировка: ' + answer.map((v) => vertices[v].GetName()).join(', ')

    animation.AddAction(ANIMATE_GRAPH, {
        vertices: vertices,
        edges: this.edges,
        statuses: statuses.slice(),
        edgeStatuses: edgeStatuses.slice(),
        labels: labels.slice(),
        text: text
    }, ALGORITHMS_ANIMATION_TIME)

    animation.Start()
    this.activeObject = animation
}
;
function GetNodeFromList(list, v1, v2) {
    for (let node of list[v1])
        if (node.vertex == v2)
            return node

    return null
}

GraphRedactor.prototype.EulerPath = function(isLoop) {
    if (isLoop && !this.HaveEulerLoop()) {
        alert("Граф не содержит эйлеров цикл")
        return
    }

    if (!this.HaveEulerPath()) {
        alert("Граф не содержит эйлеров путь")
        return
    }

    let animation = new Animation(`euler_${isLoop ? 'loop' : 'path'}.gif`)
    let labels = []
    let statuses = []
    let edgeStatuses = []
    let target = isLoop ? 'цикл' : 'путь'

    let list = this.GetConnectivityList()
    let isDirected = this.IsDirected()
    let degrees = this.GetDegrees()
    let vertices = this.vertices.ToArray()
    let v = 0

    for (let i = 1; i < vertices.length; i++) {
        if (!isDirected && degrees[i] % 2 == 1) {
            v = i
            break
        }
        else if (isDirected && degrees[i].degIn == degrees[i].degOut - 1) {
            v = i
            break
        }
    }

    if (v != 0) {
        for (let i = 0; i < vertices.length; i++) {
            labels[i] = isDirected ? `in=${degrees[i].degIn}, out=${degrees[i].degOut}` : `deg=${degrees[i]}`
        }

        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: this.edges,
            labels: labels.slice(),
            statuses: statuses.slice(),
            edgeStatuses: edgeStatuses.slice(),
            text: 'Расчитываем степени вершин для поиска начальной вершины'
        }, ALGORITHMS_ANIMATION_TIME)
    }

    for (let i = 0; i < vertices.length; i++) {
        labels[i] = ''
    }

    statuses[v] = SELECTED_STATUS

    animation.AddAction(ANIMATE_GRAPH, {
        vertices: vertices,
        edges: this.edges,
        labels: labels.slice(),
        statuses: statuses.slice(),
        edgeStatuses: edgeStatuses.slice(),
        text: `Начинаем ${target} из вершины ${vertices[v].GetName()}\nСтек: [${vertices[v].GetName()}]`
    }, ALGORITHMS_ANIMATION_TIME)

    let stack = [v]
    let path = []

    while (stack.length) {
        let w = stack[stack.length - 1]

        statuses[w] = ANIMATED_STATUS
        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: this.edges,
            labels: labels.slice(),
            statuses: statuses.slice(),
            edgeStatuses: edgeStatuses.slice(),
            text: `Получаем вершину ${vertices[w].GetName()} на вершине стека и ищем смежные ей рёбра\nСтек: [${stack.map((v) => vertices[v].GetName()).join(', ')}]\nТекущий ${target}: ${path.map((v) => vertices[v].GetName()).join('🠒')}`
        }, ALGORITHMS_ANIMATION_TIME)

        let foundEdge = false

        for (let i = 0; i < list[w].length; i++) {
            let edge = list[w][i].edge
            let index = this.edges.indexOf(edge)

            if (edge == null)
                continue

            let u = list[w][i].vertex
            edgeStatuses[index] = SELECTED_STATUS
            statuses[u] = SELECTED_STATUS

            animation.AddAction(ANIMATE_GRAPH, {
                vertices: vertices,
                edges: this.edges,
                labels: labels.slice(),
                statuses: statuses.slice(),
                edgeStatuses: edgeStatuses.slice(),
                text: `Обрабатываем ребро ${edge.GetName()}\nСтек: [${stack.map((v) => vertices[v].GetName()).join(', ')}]\nТекущий ${target}: ${path.map((v) => vertices[v].GetName()).join('🠒')}`
            }, ALGORITHMS_ANIMATION_TIME)

            stack.push(u)
            list[w][i].edge = null

            if (!isDirected) {
                GetNodeFromList(list, u, w).edge = null
            }

            edgeStatuses[index] = VISITED_STATUS
            foundEdge = true

            animation.AddAction(ANIMATE_GRAPH, {
                vertices: vertices,
                edges: this.edges,
                labels: labels.slice(),
                statuses: statuses.slice(),
                edgeStatuses: edgeStatuses.slice(),
                text: `Кладём в стек вершину ${vertices[u].GetName()} и удаляем найденное ребро\nСтек: [${stack.map((v) => vertices[v].GetName()).join(', ')}]\nТекущий ${target}: ${path.map((v) => vertices[v].GetName()).join('🠒')}`
            }, ALGORITHMS_ANIMATION_TIME)
            break
        }

        statuses[w] = VISITED_STATUS

        if (!foundEdge) {
            stack.pop()

            animation.AddAction(ANIMATE_GRAPH, {
                vertices: vertices,
                edges: this.edges,
                labels: labels.slice(),
                statuses: statuses.slice(),
                edgeStatuses: edgeStatuses.slice(),
                text: `Неудалённых рёбер нет, добавляем вершину в итоговый ${target}\nСтек: [${stack.map((v) => vertices[v].GetName()).join(', ')}]\nТекущий ${target}: ${path.map((v) => vertices[v].GetName()).join('🠒')}`
            }, ALGORITHMS_ANIMATION_TIME)

            path.push(w)
        }
    }

    path.reverse()

    if (!isLoop && path[0] == path[path.length - 1])
        path.pop()

    for (let i = 0; i < vertices.length; i++) {
        labels[i] = ''
        statuses[i] = DEFAULT_STATUS
    }

    for (let i = 0; i < this.edges.length; i++) {
        edgeStatuses[i] = DEFAULT_STATUS
    }

    let text = `Эйлеров ${target} существует: ${path.map((v) => vertices[v].GetName()).join('🠒')}`

    for (let i = 0; i < path.length; i++) {
        v = path[i]

        if (labels[v] == '') {
            labels[v] = (i + 1) + ''
        }
        else {
            labels[v] += ', ' + (i + 1)
        }

        if (i > 0) {
            let index = this.GetEdgeByVerticesIndex(vertices[path[i - 1]], vertices[path[i]])
            edgeStatuses[index] = ANIMATED_STATUS

            animation.AddAction(ANIMATE_GRAPH, {
                vertices: vertices,
                edges: this.edges,
                labels: labels.slice(),
                statuses: statuses.slice(),
                edgeStatuses: edgeStatuses.slice(),
                text: text
            }, ALGORITHMS_ANIMATION_TIME)
        }
    }

    animation.Start()
    this.activeObject = animation
}
;
// поиск Гамильтонова цикла
GraphRedactor.prototype.HamiltonianLoopBacktracking = function(list, vertices, path, pos, animation, statuses, labels, edgeStatuses) {
    if (pos == vertices.length) {
        for (let node of list[path[pos - 1]]) {
            if (node.vertex == path[0]) {
                edgeStatuses[this.edges.indexOf(node.edge)] = ANIMATED_STATUS
                return true
            }
        }

        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: this.edges,
            statuses: statuses.slice(),
            labels: labels.slice(),
            edgeStatuses: edgeStatuses.slice(),
            text: 'Цикл невозможен, выполняем откат'
        }, ALGORITHMS_ANIMATION_TIME)

        return false
    }

    for (let i = 0; i < list[path[pos - 1]].length; i++) {
        let v = list[path[pos - 1]][i].vertex
        let edge = list[path[pos - 1]][i].edge

        if (path.indexOf(v) != -1)
            continue

        path[pos] = v
        statuses[v] = ANIMATED_STATUS
        labels[v] = (pos + 1) + ''
        edgeStatuses[this.edges.indexOf(edge)] = ANIMATED_STATUS

        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: this.edges,
            statuses: statuses.slice(),
            labels: labels.slice(),
            edgeStatuses: edgeStatuses.slice(),
            text: 'Текущий цикл: ' + path.slice(0, pos + 1).map((v) => vertices[v].GetName()).join(', ')
        }, ALGORITHMS_ANIMATION_TIME)

        if (this.HamiltonianLoopBacktracking(list, vertices, path, pos + 1, animation, statuses, labels, edgeStatuses))
            return true

        path[pos] = -1
        statuses[v] = DEFAULT_STATUS
        edgeStatuses[this.edges.indexOf(edge)] = DEFAULT_STATUS
        labels[v] = ''

        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: this.edges,
            statuses: statuses.slice(),
            labels: labels.slice(),
            edgeStatuses: edgeStatuses.slice(),
            text: 'Текущий цикл: ' + path.slice(0, pos).map((v) => vertices[v].GetName()).join(', ')
        }, ALGORITHMS_ANIMATION_TIME)
    }

    return false
}

// поиск Гамильтонова цикла
GraphRedactor.prototype.HamiltonianLoop = function() {
    let path = []
    let list = this.GetConnectivityList()
    let animation = new Animation("hamiltonian_loop.gif")
    let statuses = []
    let labels = []
    let edgeStatuses = []
    let vertices = this.vertices.ToArray()
    let start = 0

    for (let i = 0; i < vertices.length; i++) {
        path[i] = -1
        statuses[i] = DEFAULT_STATUS
        labels[i] = ''
    }

    for (let i = 0; i < this.edges.length; i++)
        edgeStatuses[i] = DEFAULT_STATUS
 
    path[start] = 0

    statuses[start] = ANIMATED_STATUS
    labels[start] = '1'

    animation.AddAction(ANIMATE_GRAPH, {
        vertices: vertices,
        edges: this.edges,
        statuses: statuses.slice(),
        labels: labels.slice(),
        edgeStatuses: edgeStatuses.slice(),
        text: `Начинаем с вершины ${vertices[0].GetName()}`
    }, ALGORITHMS_ANIMATION_TIME)

    if (!this.HamiltonianLoopBacktracking(list, vertices, path, 1, animation, statuses, labels, edgeStatuses)) {
        labels[start] = ''
        statuses[start] = DEFAULT_STATUS

        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: this.edges,
            statuses: statuses.slice(),
            labels: labels.slice(),
            edgeStatuses: edgeStatuses.slice(),
            text: 'Граф не содержит Гамильтонов цикл'
        }, ALGORITHMS_ANIMATION_TIME)      
    }
    else {
        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: this.edges,
            statuses: statuses.slice(),
            labels: labels.slice(),
            edgeStatuses: edgeStatuses.slice(),
            text: `Гамильтонов цикл существует: ${path.map((v) => vertices[v].GetName()).join(', ')}`
        }, ALGORITHMS_ANIMATION_TIME)

        animation.SetSaveInfo({ vertices: path.map((v) => vertices[v]), edges: this.edges.filter((edge, i) => edgeStatuses[i] == ANIMATED_STATUS) })
    }

    animation.Start()
    this.activeObject = animation
}

;
// получение вершины с наибольшим насыщением
GraphRedactor.prototype.GetVertexWithHighestSaturation = function(list, colors, degrees) {
    let saturation = -1
    let vertex = 0

    for (let i = 0; i < this.vertices.Count(); i++) {
        if (colors[i] != -1)
            continue

        let adjColors = new Set()

        for (let node of list[i])
            if (colors[node.vertex] != -1)
                adjColors.add(colors[node.vertex])

        if (adjColors.size > saturation) {
            saturation = adjColors.size
            vertex = i
        }
        else if (adjColors.size == saturation && degrees[i] >= degrees[vertex]) {
            vertex = i
        }
    }

    return vertex
}

// раскраска графа
GraphRedactor.prototype.Coloring = function() {
    let animation = new Animation("coloring.gif")
    let list = this.GetConnectivityList(true)
    let vertices = this.vertices.ToArray()

    let degrees = list.map((row)=> row.length)
    let start = 0

    for (let i = 1; i < vertices.length; i++)
        if (degrees[i] > degrees[start])
            start = i

    let colors = []
    let labels = []
    let statuses = []
    let edgeStatuses = []

    for (let i = 0; i < vertices.length; i++) {
        colors[i] = -1
        labels[i] = ''
        statuses[i] = DEFAULT_STATUS
    }

    for (let i = 0; i < this.edges.length; i++) {
        edgeStatuses[i] = DEFAULT_STATUS
    }

    colors[start] = 0
    statuses[start] = HSL_STATUS
    labels[start] = '1'

    animation.AddAction(ANIMATE_GRAPH, {
        vertices: vertices,
        edges: this.edges,
        statuses: statuses.slice(),
        labels: labels.slice(),
        colors: colors.slice(),
        edgeStatuses: edgeStatuses.slice(),
        text: 'Начинаем с вершины с наибольшей степенью (' + vertices[start].GetName() + ')'
    }, ALGORITHMS_ANIMATION_TIME)

    for (let i = 1; i < vertices.length; i++) {
        let u = this.GetVertexWithHighestSaturation(list, colors, degrees)
        statuses[u] = SELECTED_STATUS

        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: this.edges,
            statuses: statuses.slice(),
            labels: labels.slice(),
            colors: colors.slice(),
            edgeStatuses: edgeStatuses.slice(),
            text: 'Выбираем вершину с наибольшим количеством различных цветов у соседей (' + vertices[u].GetName() + ')'
        }, ALGORITHMS_ANIMATION_TIME)

        let availableColors = []

        for (let j = 0; j < vertices.length; j++)
            availableColors[j] = true

        let usedColors = new Set()

        for (let node of list[u]) {
            if (colors[node.vertex] == -1)
                continue

            availableColors[colors[node.vertex]] = false
            usedColors.add(colors[node.vertex] + 1)
            edgeStatuses[this.edges.indexOf(node.edge)] = SELECTED_STATUS
        }

        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: this.edges,
            statuses: statuses.slice(),
            labels: labels.slice(),
            colors: colors.slice(),
            edgeStatuses: edgeStatuses.slice(),
            text: 'Идём по смежным раскрашенным вершинам с вершиной ' + vertices[u].GetName() + (availableColors.length > 0 ? '\nИспользуемые цвета смежных вершин: ' + Array.from(usedColors).join(', ') : '')
        }, ALGORITHMS_ANIMATION_TIME)

        let color = 0

        for (let j = 0; j < vertices.length; j++) {
            if (availableColors[j]) {
                color = j
                break
            }
        }

        colors[u] = color
        labels[u] = (color + 1) + ''
        statuses[u] = HSL_STATUS

        for (let node of list[u]) {
            if (colors[node.vertex] == -1)
                continue

            edgeStatuses[this.edges.indexOf(node.edge)] = DEFAULT_STATUS
        }

        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: this.edges,
            statuses: statuses.slice(),
            labels: labels.slice(),
            colors: colors.slice(),
            edgeStatuses: edgeStatuses.slice(),
            text: 'Раскрашиваем вершину ' + vertices[u].GetName() + ' в первый неиспользуемый цвет — ' + (color + 1)
        }, ALGORITHMS_ANIMATION_TIME)
    }

    for (let i = 0; i < vertices.length; i++)
        statuses[i] = HSL_STATUS

    let maxColor = Math.max.apply(null, colors) + 1

    animation.AddAction(ANIMATE_GRAPH, {
        vertices: vertices,
        edges: this.edges,
        statuses: statuses.slice(),
        labels: labels.slice(),
        colors: colors.slice(),
        edgeStatuses: edgeStatuses.slice(),
        text: `Количество цветов: ${maxColor}`
    }, ALGORITHMS_ANIMATION_TIME)

    let coloredVertices = []
    let coloredEdges = []

    for (let i = 0; i < vertices.length; i++) {
        let vertex = vertices[i].Copy()
        let part = maxColor < 12 ? colors[i] * 30 : colors[i] / maxColor * 360
        let color = `hsl(${part}, 100%, 80%)`

        vertex.SetBackground(color)
        coloredVertices.push(vertex)
    }

    for (let edge of this.edges) {
        let coloredEdge = edge.Copy()
        coloredEdge.vertex1 = coloredVertices[this.vertices.IndexOf(edge.vertex1)]
        coloredEdge.vertex2 = coloredVertices[this.vertices.IndexOf(edge.vertex2)]
        coloredEdges.push(coloredEdge)
    }

    animation.SetSaveInfo({ vertices: coloredVertices, edges: coloredEdges })
    animation.Start()
    this.activeObject = animation
}
;
// обновление высот
GraphRedactor.prototype.MaxFlowUpdateHeights = function(maxh, s, t, e, h) {
    for (let i = 0; i < this.vertices.Count(); i++) {
        if (i == s || i == t || Math.abs(e[i]) < 1e-10)
            continue

        if (maxh.length > 0 && h[i] > h[maxh[0]])
            maxh.length = 0

        if (maxh.length == 0 || h[i] == h[maxh[0]])
            maxh.push(i)
    }
}

// проталкивание
GraphRedactor.prototype.MaxFlowPush = function(u, v, c, f, e) {
    let flow = Math.min(e[u], c[u][v] - f[u][v])

    f[u][v] += flow
    f[v][u] -= flow
    e[u] -= flow
    e[v] += flow
}

// подъём
GraphRedactor.prototype.MaxFlowRelabel = function(u, c, f, h) {
    h[u] = Infinity

    for (let v = 0; v < this.vertices.Count(); v++)
        if (c[u][v] - f[u][v] > 0 && h[v] + 1 < h[u])
            h[u] = h[v] + 1
}

// инициализация алгоритма проталкивания предпотока
GraphRedactor.prototype.MaxFlowPreflowPushInitialize = function(s, c, f, e, h, maxh) {
    for (let i = 0; i < this.vertices.Count(); i++) {
        f[i] = []

        for (let j = 0; j < this.vertices.Count(); j++)
            f[i][j] = 0
    }

    for (let i = 0; i < this.vertices.Count(); i++) {
        f[s][i] = c[s][i]
        f[i][s] = -c[s][i]
        h[i] = 0
        e[i] = c[s][i]
    }

    h[s] = this.vertices.Count() - 1
}

// обновление меток вершин
GraphRedactor.prototype.MaxFlowUpdateLabels = function(labels, h, e, s, t) {
    for (let i = 0; i < this.vertices.Count(); i++) {
        let text = ''

        if (i == s) {
            text = 'исток\n'
        }
        else if (i == t) {
            text = 'сток\n'
        }

        labels[i] = text + 'h:' + h[i] + '\ne:' + Round(e[i])
    }
}

// обновление меток рёбер
GraphRedactor.prototype.MaxFlowUpdateEdgeLabels = function(edgeStatuses, edgeLabels, c, f) {
    for (let i = 0; i < this.edges.length; i++) {
        let v1 = this.vertices.IndexOf(this.edges[i].vertex1)
        let v2 = this.vertices.IndexOf(this.edges[i].vertex2)

        if (!this.edges[i].IsDirected() && f[v1][v2] < 0 && f[v2][v1] > 0) {
            let tmp = v1
            v1 = v2
            v2 = tmp
        }

        let flow = Round(f[v1][v2])
        let cost = Round(c[v1][v2])

        edgeLabels[i] = flow + '/' + cost
        edgeStatuses[i] = DEFAULT_STATUS

        if (flow < 0) {
            edgeStatuses[i] = VISITED_STATUS
        }
        else if (flow > 0) {
            edgeStatuses[i] = ANIMATED_STATUS
        }
    }
}

// алгоритм проталкивания предпотока
GraphRedactor.prototype.MaxFlowPreflowPush = function(startVertex, endVertex) {
    let s = this.vertices.IndexOf(startVertex)
    let t = this.vertices.IndexOf(endVertex)
    let c = this.GetAdjacencyMatrix()
    let f = []
    let e = []
    let h = []
    let maxh = []

    let animation = new Animation("preflow_push.gif")
    let labels = []
    let statuses = []
    let edgeStatuses = []
    let edgeLabels = []
    let vertices = this.vertices.ToArray()

    this.MaxFlowPreflowPushInitialize(s, c, f, e, h, maxh)
    this.MaxFlowUpdateHeights(maxh, s, t, e, h)

    for (let i = 0; i < vertices.length; i++)
        statuses[i] = DEFAULT_STATUS

    for (let i = 0; i < this.edges.length; i++)
        edgeStatuses[i] = DEFAULT_STATUS

    this.MaxFlowUpdateLabels(labels, h, e, s, t)
    this.MaxFlowUpdateEdgeLabels(edgeStatuses, edgeLabels, c, f)

    statuses[s] = HOT_STATUS
    statuses[t] = HOT_STATUS

    animation.AddAction(ANIMATE_GRAPH, {
        vertices: vertices,
        edges: this.edges,
        statuses: statuses.slice(),
        labels: labels.slice(),
        edgeStatuses: edgeStatuses.slice(),
        edgeLabels: edgeLabels.slice(),
        text: `Инициализируем алгоритм\nВершины для проталкивания: [${maxh.map((v) => vertices[v].GetName()).join(', ')}]`
    }, ALGORITHMS_ANIMATION_TIME)

    while (maxh.length != 0) {
        while (maxh.length > 0) {
            let u = maxh[maxh.length - 1]
            let pushed = false

            let statusU = statuses[u]
            statuses[u] = ANIMATED_STATUS

            for (let v = 0; v < vertices.length && Math.abs(e[u]) > 1e-10; v++) {
                if (c[u][v] - f[u][v] > 0 && h[u] == h[v] + 1) {
                    pushed = true
                    this.MaxFlowPush(u, v, c, f, e)

                    if (Math.abs(e[u]) < 1e-10) {
                        maxh.pop()
                    }

                    let statusV = statuses[v]
                    statuses[v] = SELECTED_STATUS

                    this.MaxFlowUpdateLabels(labels, h, e, s, t)
                    this.MaxFlowUpdateEdgeLabels(edgeStatuses, edgeLabels, c, f)

                    animation.AddAction(ANIMATE_GRAPH, {
                        vertices: vertices,
                        edges: this.edges,
                        statuses: statuses.slice(),
                        labels: labels.slice(),
                        edgeStatuses: edgeStatuses.slice(),
                        edgeLabels: edgeLabels.slice(),
                        text: `Проталкиваем вершину ${vertices[u].GetName()} через вершину ${vertices[v].GetName()}\nВершины для проталкивания: [${maxh.map((v) => vertices[v].GetName()).join(', ')}]`
                    }, ALGORITHMS_ANIMATION_TIME)

                    statuses[v] = statusV
                }
            }

            if (!pushed) {
                this.MaxFlowRelabel(u, c, f, h)
                this.MaxFlowUpdateLabels(labels, h, e, s, t)
                this.MaxFlowUpdateEdgeLabels(edgeStatuses, edgeLabels, c, f)

                animation.AddAction(ANIMATE_GRAPH, {
                    vertices: vertices,
                    edges: this.edges,
                    statuses: statuses.slice(),
                    labels: labels.slice(),
                    edgeStatuses: edgeStatuses.slice(),
                    edgeLabels: edgeLabels.slice(),
                    text: `Поднимаем вершину ${vertices[u].GetName()}\nВершины для проталкивания: [${maxh.map((v) => vertices[v].GetName()).join(', ')}]`
                }, ALGORITHMS_ANIMATION_TIME)

                if (h[u] > h[maxh[0]]) {
                    maxh.length = 0
                    statuses[u] = statusU
                    break
                }
            }

            statuses[u] = statusU
        }

        this.MaxFlowUpdateHeights(maxh, s, t, e, h)

        if (maxh.length > 0) {
            this.MaxFlowUpdateLabels(labels, h, e, s, t)
            this.MaxFlowUpdateEdgeLabels(edgeStatuses, edgeLabels, c, f)

            animation.AddAction(ANIMATE_GRAPH, {
                vertices: vertices,
                edges: this.edges,
                statuses: statuses.slice(),
                labels: labels.slice(),
                edgeStatuses: edgeStatuses.slice(),
                edgeLabels: edgeLabels.slice(),
                text: `Обновляем вершины для проталкивания: [${maxh.map((v) => vertices[v].GetName()).join(', ')}]`
            }, ALGORITHMS_ANIMATION_TIME)
        }
    }

    let maxFlow = 0

    for (let i = 0; i < vertices.length; i++) {
        maxFlow += f[i][t]
        labels[i] = ''

        if (i == s) {
            labels[i] = 'исток'
        }
        else if (i == t) {
            labels[i] = 'сток'
        }
    }

    this.MaxFlowUpdateEdgeLabels(edgeStatuses, edgeLabels, c, f)

    animation.AddAction(ANIMATE_GRAPH, {
        vertices: vertices,
        edges: this.edges,
        labels: labels.slice(),
        statuses: statuses.slice(),
        edgeStatuses: edgeStatuses.slice(),
        edgeLabels: edgeLabels.slice(),
        text: `Максимальный поток из вершины ${vertices[s].GetName()} в вершину ${vertices[t].GetName()}: ${maxFlow}`
    }, ALGORITHMS_ANIMATION_TIME)

    let verticesSaved = []
    let edgesSaved = []

    for (let i = 0; i < this.edges.length; i++) {
        if (edgeStatuses[i] != ANIMATED_STATUS)
            continue

        edgesSaved.push(this.edges[i])

        if (verticesSaved.indexOf(this.edges[i].vertex1) == -1)
            verticesSaved.push(this.edges[i].vertex1)

        if (verticesSaved.indexOf(this.edges[i].vertex2) == -1)
            verticesSaved.push(this.edges[i].vertex2)
    }

    animation.SetSaveInfo({ vertices: verticesSaved, edges: edgesSaved })
    animation.Start()
    this.activeObject = animation
}
;
// обновление меток вершин
GraphRedactor.prototype.MaxFlowDinicUpdateLabels = function(labels, d, ptr, s, t) {
    for (let i = 0; i < this.vertices.Count(); i++) {
        let text = ''

        if (i == s) {
            text = 'исток\n'
        }
        else if (i == t) {
            text = 'сток\n'
        }

        labels[i] = text + 'd:' + d[i] + '\nptr:' + ptr[i]
    }
}

GraphRedactor.prototype.MaxFlowDinicBFS = function(s, t, d, ptr, f, c, vertices, animation, statuses, labels, edgeStatuses, edgeLabels) {
    let q = [s]

    for (let i = 0; i < vertices.length; i++)
        d[i] = -1

    d[s] = 0

    this.MaxFlowDinicUpdateLabels(labels, d, ptr, s, t)
    this.MaxFlowUpdateEdgeLabels(edgeStatuses, edgeLabels, c, f)

    statuses[s] = SELECTED_STATUS

    animation.AddAction(ANIMATE_GRAPH, {
        vertices: vertices,
        edges: this.edges,
        statuses: statuses.slice(),
        labels: labels.slice(),
        edgeStatuses: edgeStatuses.slice(),
        edgeLabels: edgeLabels.slice(),
        text: `Запускаем обход в ширину из вершины ${vertices[s].GetName()}`
    }, ALGORITHMS_ANIMATION_TIME)

    while (q.length > 0) {
        let v = q.shift()

        let statusV = statuses[v]
        statuses[v] = SELECTED_STATUS
        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: this.edges,
            statuses: statuses.slice(),
            labels: labels.slice(),
            edgeStatuses: edgeStatuses.slice(),
            edgeLabels: edgeLabels.slice(),
            text: `Извлекаем из очереди вершину ${vertices[v].GetName()}\nОчередь: [${q.map((v) => vertices[v].GetName()).join(', ')}]`
        }, ALGORITHMS_ANIMATION_TIME)

        for (let to = 0; to < vertices.length; to++) {
            if (d[to] == -1 && f[v][to] < c[v][to]) {
                q.push(to)
                d[to] = d[v] + 1

                this.MaxFlowDinicUpdateLabels(labels, d, ptr, s, t)

                animation.AddAction(ANIMATE_GRAPH, {
                    vertices: vertices,
                    edges: this.edges,
                    statuses: statuses.slice(),
                    labels: labels.slice(),
                    edgeStatuses: edgeStatuses.slice(),
                    edgeLabels: edgeLabels.slice(),
                    text: `Кладём вершину ${vertices[to].GetName()} в очередь\nОчередь: [${q.map((v) => vertices[v].GetName()).join(', ')}]`
                }, ALGORITHMS_ANIMATION_TIME)
            }
        }

        statuses[v] = statusV
    }

    statuses[s] = HOT_STATUS

    return d[t] != -1
}

GraphRedactor.prototype.MaxFlowDinicDFS = function(v, s, t, c, f, d, ptr, flow, vertices, animation, statuses, labels, edgeStatuses, edgeLabels) {
    if (flow == 0)
        return 0

    if (v == t) {
        statuses[v] = SELECTED_STATUS
        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: this.edges,
            statuses: statuses.slice(),
            labels: labels.slice(),
            edgeStatuses: edgeStatuses.slice(),
            edgeLabels: edgeLabels.slice(),
            text: `Достигли конечной вершины, возвращаем поток (${flow})`
        }, ALGORITHMS_ANIMATION_TIME)
        statuses[v] = HOT_STATUS

        return flow
    }

    for (; ptr[v] < vertices.length; ptr[v]++) {
        let to = ptr[v]

        if (d[to] != d[v] + 1)
            continue

        let statusTo = statuses[to]
        statuses[to] = SELECTED_STATUS
        animation.AddAction(ANIMATE_GRAPH, {
            vertices: vertices,
            edges: this.edges,
            statuses: statuses.slice(),
            labels: labels.slice(),
            edgeStatuses: edgeStatuses.slice(),
            edgeLabels: edgeLabels.slice(),
            text: `Обрабатываем вершину ${vertices[to].GetName()}`
        }, ALGORITHMS_ANIMATION_TIME)
        statuses[to] = statusTo

        let pushed = this.MaxFlowDinicDFS(to, s, t, c, f, d, ptr, Math.min(flow, c[v][to] - f[v][to]), vertices, animation, statuses, labels, edgeStatuses, edgeLabels)

        if (pushed != 0) {
            f[v][to] += pushed
            f[to][v] -= pushed

            this.MaxFlowDinicUpdateLabels(labels, d, ptr, s, t)
            this.MaxFlowUpdateEdgeLabels(edgeStatuses, edgeLabels, c, f)

            animation.AddAction(ANIMATE_GRAPH, {
                vertices: vertices,
                edges: this.edges,
                statuses: statuses.slice(),
                labels: labels.slice(),
                edgeStatuses: edgeStatuses.slice(),
                edgeLabels: edgeLabels.slice(),
                text: `Обновляем потоки между вершинами ${vertices[v].GetName()} и ${vertices[to].GetName()}`
            }, ALGORITHMS_ANIMATION_TIME)

            return pushed 
        }
    }

    return 0
}

GraphRedactor.prototype.MaxFlowDinic = function(startVertex, endVertex) {
    let s = this.vertices.IndexOf(startVertex)
    let t = this.vertices.IndexOf(endVertex)
    let c = this.GetAdjacencyMatrix()
    let f = []
    let d = []
    let ptr = []
    let vertices = this.vertices.ToArray()

    for (let i = 0; i < vertices.length; i++) {
        f[i] = []
        ptr[i] = 0
        d[i] = -1

        for (let j = 0; j < vertices.length; j++)
            f[i][j] = 0
    }

    let animation = new Animation("dinic_algorithm.gif")
    let statuses = []
    let labels = []
    let edgeStatuses = []
    let edgeLabels = []

    for (let i = 0; i < vertices.length; i++) {
        statuses[i] = DEFAULT_STATUS
        labels[i] = ''
    }

    for (let i = 0; i < this.edges.length; i++)
        edgeStatuses[i] = DEFAULT_STATUS

    this.MaxFlowDinicUpdateLabels(labels, d, ptr, s, t)
    this.MaxFlowUpdateEdgeLabels(edgeStatuses, edgeLabels, c, f)

    statuses[s] = HOT_STATUS
    statuses[t] = HOT_STATUS

    let maxFlow = 0

    while (this.MaxFlowDinicBFS(s, t, d, ptr, f, c, vertices, animation, statuses, labels, edgeStatuses, edgeLabels)) {
        for (let i = 0; i < vertices.length; i++)
            ptr[i] = 0

        let pushed

        do {
            statuses[s] = SELECTED_STATUS

            this.MaxFlowDinicUpdateLabels(labels, d, ptr, s, t)
            this.MaxFlowUpdateEdgeLabels(edgeStatuses, edgeLabels, c, f)

            animation.AddAction(ANIMATE_GRAPH, {
                vertices: vertices,
                edges: this.edges,
                statuses: statuses.slice(),
                labels: labels.slice(),
                edgeStatuses: edgeStatuses.slice(),
                edgeLabels: edgeLabels.slice(),
                text: `Запускаем обход в глубину из вершины ${vertices[s].GetName()}`
            }, ALGORITHMS_ANIMATION_TIME)

            pushed = this.MaxFlowDinicDFS(s, s, t, c, f, d, ptr, Infinity, vertices, animation, statuses, labels, edgeStatuses, edgeLabels)
            maxFlow += pushed
        } while (pushed != 0)
    }

    for (let i = 0; i < vertices.length; i++) {
        labels[i] = ''

        if (i == s) {
            labels[i] = 'исток'
        }
        else if (i == t) {
            labels[i] = 'сток'
        }
    }

    this.MaxFlowUpdateEdgeLabels(edgeStatuses, edgeLabels, c, f)
    animation.AddAction(ANIMATE_GRAPH, {
        vertices: vertices,
        edges: this.edges,
        statuses: statuses.slice(),
        labels: labels.slice(),
        edgeStatuses: edgeStatuses.slice(),
        edgeLabels: edgeLabels.slice(),
        text: `Максимальный поток из вершины ${vertices[s].GetName()} в вершину ${vertices[t].GetName()}: ${maxFlow}`
    }, ALGORITHMS_ANIMATION_TIME)

    let verticesSaved = []
    let edgesSaved = []

    for (let i = 0; i < this.edges.length; i++) {
        if (edgeStatuses[i] != ANIMATED_STATUS)
            continue

        edgesSaved.push(this.edges[i])

        if (verticesSaved.indexOf(this.edges[i].vertex1) == -1)
            verticesSaved.push(this.edges[i].vertex1)

        if (verticesSaved.indexOf(this.edges[i].vertex2) == -1)
            verticesSaved.push(this.edges[i].vertex2)
    }

    animation.SetSaveInfo({ vertices: verticesSaved, edges: edgesSaved })
    animation.Start()
    this.activeObject = animation
}
;
GraphRedactor.prototype.Complement = function() {
    let animation = new Animation("complement.gif")
    let vertices = this.vertices.ToArray()
    let statuses = []
    let isDirected = this.IsDirected()

    let edges = []
    let edgeStatuses = []
    let list = {}

    for (let i = 0; i < vertices.length; i++) {
        list[i] = new Set()
        statuses[i] = DEFAULT_STATUS
    }

    for (let edge of this.edges) {
        let v1 = this.vertices.IndexOf(edge.vertex1)
        let v2 = this.vertices.IndexOf(edge.vertex2)

        list[v1].add(v2)

        if (!edge.IsDirected())
            list[v2].add(v1)

        edges.push(edge)
        edgeStatuses.push(VISITED_STATUS)
    }

    let complementEdgesCount = 0

    for (let i = 0; i < vertices.length; i++) {
        for (let j = isDirected ? 0 : i + 1; j < vertices.length; j++) {
            if (i == j || list[i].has(j))
                continue

            let v1 = this.vertices.Get(i)
            let v2 = this.vertices.Get(j)
            let edge = new Edge(v1, v2, '', isDirected, isDirected ? 8 * GRID_SIZE : 0)

            edges.push(edge)
            edgeStatuses.push(ANIMATED_STATUS)

            animation.AddAction(ANIMATE_GRAPH, {
                vertices: vertices,
                statuses: statuses,
                edges: edges.slice(),
                edgeStatuses: edgeStatuses.slice(),
                text: `Добавляем ребро ${edge.GetName()} (количество рёбер - ${++complementEdgesCount})`
            }, ALGORITHMS_ANIMATION_TIME)

            edgeStatuses[edgeStatuses.length - 1] = GREEN_STATUS
        }
    }

    animation.AddAction(ANIMATE_GRAPH, {
        vertices: vertices,
        statuses: statuses,
        edges: edges,
        edgeStatuses: edgeStatuses,
        text: `Дополнение построено: (количество рёбер - ${complementEdgesCount})`
    }, ALGORITHMS_ANIMATION_TIME)

    animation.SetSaveInfo({ vertices: vertices.slice(), edges: edges.slice(this.edges.length) })
    animation.Start()
    this.activeObject = animation
}
;
GraphRedactor.prototype.GetVerticesCoordinates=function(vertices){let coordinates=[]
for(let i=0;i<vertices.length;i++)coordinates.push({x:vertices[i].x,y:vertices[i].y})
return coordinates}
GraphRedactor.prototype.AddVerticesMovementToUndo=function(vertices,coordinates){let movements=[]
for(let i=0;i<vertices.length;i++){vertices[i].x=Math.round(vertices[i].x/GRID_SIZE)*GRID_SIZE
vertices[i].y=Math.round(vertices[i].y/GRID_SIZE)*GRID_SIZE
let dx=vertices[i].x-coordinates[i].x
let dy=vertices[i].y-coordinates[i].y
movements.push({vertex:vertices[i],dx:dx,dy:dy})}this.AddAction(ACTION_PLACE,{movements:movements})
this.placeStatus=PLACE_END_STATUS}
GraphRedactor.prototype.GetMaxVertexRadius=function(){let maxRadius=0
for(let vertex of this.vertices.Iterator())maxRadius=Math.max(maxRadius,vertex.radius)
return maxRadius}
GraphRedactor.prototype.WaitPlaceAlgortihm=function(algorithm){if(this.placeStatus==PLACE_END_STATUS){this.placeStatus=PLACE_RUN_STATUS
algorithm()
return}window.requestAnimationFrame(()=>this.WaitPlaceAlgortihm(algorithm))}
GraphRedactor.prototype.InitPlaceAlgorithm=function(algorithm){if(this.placeStatus==PLACE_RUN_STATUS)this.placeStatus=PLACE_STOP_STATUS
this.WaitPlaceAlgortihm(algorithm)}
GraphRedactor.prototype.PlaceByCircle=function(){let bbox=this.GetViewAreaBoundingBoxReal()
let maxRadius=this.GetMaxVertexRadius()
let x0=(bbox.xmin+bbox.xmax)/2
let y0=(bbox.ymin+bbox.ymax)/2
let radius=Math.min(bbox.xmax-bbox.xmin,bbox.ymax-bbox.ymin)/2-maxRadius-GRID_SIZE
let vertices=this.vertices.ToArray()
let prevCoordinates=this.GetVerticesCoordinates(vertices)
let angle=2*Math.PI/vertices.length
let indices=vertices.map((v,i)=>i)
Shuffle(indices)
for(let i=0;i<vertices.length;i++){vertices[indices[i]].x=x0+radius*Math.cos(angle*i)
vertices[indices[i]].y=y0+radius*Math.sin(angle*i)}this.AddVerticesMovementToUndo(vertices,prevCoordinates)}
GraphRedactor.prototype.PlaceBySphere=function(){let bbox=this.GetViewAreaBoundingBoxReal()
let maxRadius=this.GetMaxVertexRadius()
let x0=(bbox.xmin+bbox.xmax)/2
let y0=(bbox.ymin+bbox.ymax)/2
let radius=Math.min(bbox.xmax-bbox.xmin,bbox.ymax-bbox.ymin)/2-maxRadius-GRID_SIZE
let vertices=this.vertices.ToArray()
let prevCoordinates=this.GetVerticesCoordinates(vertices)
for(let vertex of vertices){let angle=Math.random()*2*Math.PI
vertex.x=x0+Math.sqrt(Math.random())*radius*Math.cos(angle)
vertex.y=y0+Math.sqrt(Math.random())*radius*Math.sin(angle)}this.AddVerticesMovementToUndo(vertices,prevCoordinates)}
GraphRedactor.prototype.PlaceByLine=function(){let bbox=this.GetViewAreaBoundingBoxReal()
let maxRadius=this.GetMaxVertexRadius()
let x0=(bbox.xmin+bbox.xmax)/2
let offset=Math.max(maxRadius*2+5*GRID_SIZE,GRID_SIZE*10)
let vertices=this.vertices.ToArray()
let prevCoordinates=this.GetVerticesCoordinates(vertices)
let y=bbox.ymin
for(let vertex of vertices){vertex.x=x0
vertex.y=y
y+=offset}this.AddAction(ACTION_BEGIN_BLOCK,{})
this.AddVerticesMovementToUndo(vertices,prevCoordinates)
for(let edge of this.edges){let dy=Math.abs(edge.vertex1.y-edge.vertex2.y)
let step=edge.controlStep
edge.controlStep=dy<=offset+0.5?0:(dy/offset)*5*GRID_SIZE*(Math.random()<0.5?1:-1)
this.AddAction(ACTION_CHANGE_EDGE_CONTROL_STEP,{edge:edge,prev:step,step:edge.GetControlStep()})}this.AddAction(ACTION_END_BLOCK,{})}
GraphRedactor.prototype.PlaceRandom=function(){let bbox=this.GetViewAreaBoundingBoxReal()
let maxRadius=this.GetMaxVertexRadius()
bbox.xmin+=maxRadius+GRID_SIZE
bbox.ymin+=maxRadius+GRID_SIZE
bbox.xmax-=maxRadius+GRID_SIZE
bbox.ymax-=maxRadius+GRID_SIZE
let vertices=this.vertices.ToArray()
let prevCoordinates=this.GetVerticesCoordinates(vertices)
for(let vertex of vertices){let index=this.vertices.IndexOf(vertex)
vertex.x=bbox.xmin+Math.random()*(bbox.xmax-bbox.xmin)
vertex.y=bbox.ymin+Math.random()*(bbox.ymax-bbox.ymin)}this.AddVerticesMovementToUndo(vertices,prevCoordinates)}
;
GraphRedactor.prototype.GetVertexDegree=function(vertex){let degree=0
for(let edge of this.edges)if(edge.vertex1==vertex||edge.vertex2==vertex)degree++
return degree}
GraphRedactor.prototype.GetVerticesDegrees=function(vertices){let degrees=[]
for(let i=0;i<vertices.length;i++)degrees[i]=this.GetVertexDegree(vertices[i])
return degrees}
GraphRedactor.prototype.CalculateAttractiveForces=function(vertices,l,forces,degrees){for(let i=0;i<vertices.length;i++){for(let j=0;j<vertices.length;j++){if(i==j)continue
let dx=vertices[i].x-vertices[j].x
let dy=vertices[i].y-vertices[j].y
let norm=dx*dx+dy*dy
if(norm<FRUNCTERMAN_REINGOLD_MIN_NORM){dx=Math.sign(i-j)*FRUNCTERMAN_REINGOLD_ZERO_SHIFT
dy=Math.sign(i-j)*FRUNCTERMAN_REINGOLD_ZERO_SHIFT
norm=1}let mass=1+degrees[j]/2
forces[i].x+=l*l*(dx/norm)/mass
forces[i].y+=l*l*(dy/norm)/mass}}}
GraphRedactor.prototype.CalculateRepulsiveForces=function(vertices,l,forces){for(let edge of this.edges){let dx=edge.vertex1.x-edge.vertex2.x
let dy=edge.vertex1.y-edge.vertex2.y
let norm=Math.max(dx*dx+dy*dy,1)
let dst=Math.sqrt(norm)
let v1=this.vertices.IndexOf(edge.vertex1)
forces[v1].x-=norm/l*(dx/dst)
forces[v1].y-=norm/l*(dy/dst)
let v2=this.vertices.IndexOf(edge.vertex2)
forces[v2].x+=norm/l*(dx/dst)
forces[v2].y+=norm/l*(dy/dst)}}
GraphRedactor.prototype.CalculateGravitation=function(vertices,forces,degrees,baricenter){for(let i=0;i<vertices.length;i++){let dx=baricenter.x-vertices[i].x
let dy=baricenter.y-vertices[i].y
let mass=1+degrees[i]/2
forces[i].x+=FRUNCTERMAN_REINGOLD_GRAVITATION*dx*mass
forces[i].y+=FRUNCTERMAN_REINGOLD_GRAVITATION*dy*mass}}
GraphRedactor.prototype.GetMaxForce=function(forces){let maxForce=0
for(let force of forces){let norm=Math.sqrt(force.x*force.x+force.y*force.y)
if(norm>maxForce)maxForce=norm}return maxForce}
GraphRedactor.prototype.FruchtermanReingoldIteration=function(vertices,degrees,maxTemperature,fixedIndices){let bbox=this.GetViewAreaBoundingBoxReal()
let width=bbox.xmax-bbox.xmin
let height=bbox.ymax-bbox.ymin
let l=Math.sqrt(width*height/vertices.length)
let forces=[]
for(let i=0;i<vertices.length;i++)forces[i]={x:0,y:0}
let baricenter={x:(bbox.xmin+bbox.xmax)/2,y:(bbox.ymin+bbox.ymax)/2}
this.CalculateAttractiveForces(vertices,l,forces,degrees)
this.CalculateGravitation(vertices,forces,degrees,baricenter)
this.CalculateRepulsiveForces(vertices,l,forces)
for(let i=0;i<vertices.length;i++){if(fixedIndices.has(i))continue
vertices[i].x+=FRUNCTERMAN_REINGOLD_DELTA*Math.sign(forces[i].x)*Math.min(Math.abs(forces[i].x),maxTemperature)
vertices[i].y+=FRUNCTERMAN_REINGOLD_DELTA*Math.sign(forces[i].y)*Math.min(Math.abs(forces[i].y),maxTemperature)
let delta=vertices[i].radius
vertices[i].x=Math.max(bbox.xmin+delta,Math.min(bbox.xmax-delta,vertices[i].x))
vertices[i].y=Math.max(bbox.ymin+delta,Math.min(bbox.ymax-delta,vertices[i].y))}return this.GetMaxForce(forces)}
GraphRedactor.prototype.FruchtermanReingoldAnimationStep=function(vertices,degrees,maxTemperature,fixedIndices,iteration,prevCoordinates,prevForce,prevTime){let currTime=performance.now()
if(currTime-prevTime>=FRUNCTERMAN_REINGOLD_TIME||this.placeStatus!=PLACE_RUN_STATUS){let currForce=this.FruchtermanReingoldIteration(vertices,degrees,maxTemperature,fixedIndices)
if(iteration<0||Math.abs(prevForce-currForce)<1||this.placeStatus!=PLACE_RUN_STATUS){this.AddVerticesMovementToUndo(vertices,prevCoordinates)
return}maxTemperature*=FRUNCTERMAN_REINGOLD_TEMPERATURE_SCALE
iteration--
prevForce=currForce
prevTime=currTime}window.requestAnimationFrame(()=>this.FruchtermanReingoldAnimationStep(vertices,degrees,maxTemperature,fixedIndices,iteration,prevCoordinates,prevForce,prevTime))}
GraphRedactor.prototype.FruchtermanReingoldAnimation=function(iterations=1000,fixedIndices=null){let vertices=this.vertices.ToArray()
let degrees=this.GetVerticesDegrees(vertices)
let prevCoordinates=this.GetVerticesCoordinates(vertices)
let maxTemperature=Math.sqrt(this.width*this.height/2)
let currTime=performance.now()
if(fixedIndices==null)fixedIndices=new Set()
this.FruchtermanReingoldAnimationStep(vertices,degrees,maxTemperature,fixedIndices,iterations,prevCoordinates,-1,currTime)}
GraphRedactor.prototype.FruchtermanReingold=function(iterations=100,fixedIndices=null){let vertices=this.vertices.ToArray()
let degrees=this.GetVerticesDegrees(vertices)
let prevForce=-1
let prevCoordinates=this.GetVerticesCoordinates(vertices)
let maxTemperature=Math.sqrt(this.width*this.height)
if(fixedIndices==null)fixedIndices=new Set()
for(let i=0;i<iterations;i++){let currForce=this.FruchtermanReingoldIteration(vertices,degrees,maxTemperature,fixedIndices)
if(Math.abs(prevForce-currForce)<1)break
prevForce=currForce
maxTemperature*=FRUNCTERMAN_REINGOLD_TEMPERATURE_SCALE}this.AddVerticesMovementToUndo(vertices,prevCoordinates)}
;
GraphRedactor.prototype.KamadaKawaiInitDistances=function(vertices){let distances=[]
for(let i=0;i<vertices.length;i++){distances[i]=[]
for(let j=0;j<vertices.length;j++)distances[i][j]=Infinity
distances[i][i]=0}for(let edge of this.edges){let v1=this.vertices.IndexOf(edge.vertex1)
let v2=this.vertices.IndexOf(edge.vertex2)
distances[v1][v2]=1
distances[v2][v1]=1}for(let k=0;k<vertices.length;k++)for(let i=0;i<vertices.length;i++)for(let j=0;j<vertices.length;j++)distances[i][j]=Math.min(distances[i][j],distances[i][k]+distances[k][j])
return distances}
GraphRedactor.prototype.KamadaKawaiInitSprings=function(vertices,bbox){let distances=this.KamadaKawaiInitDistances(vertices)
let maxDistance=0
for(let i=0;i<vertices.length;i++)for(let j=0;j<vertices.length;j++)if(distances[i][j]<Infinity)maxDistance=Math.max(maxDistance,distances[i][j])
let width=bbox.xmax-bbox.xmin
let height=bbox.ymax-bbox.ymin
let length=Math.min(width,height)/maxDistance
let springs=[]
for(let i=0;i<vertices.length;i++){springs[i]=[]
for(let j=0;j<vertices.length;j++){springs[i][j]={strength:0,length:0}
if(i!=j){let distance=Math.min(distances[i][j],maxDistance)
springs[i][j].length=distance*length
springs[i][j].strength=1/(distance*distance)}}}return springs}
GraphRedactor.prototype.KamadaKawaiIteration=function(iterations,vertices,springs,prevCoordinates,bbox,prevEnergy){let max=this.FindMaxVertexEnergy(vertices,springs)
let delta=Math.abs(prevEnergy-max.energy)
if(max.vertex==null||iterations<0||max.energy<0.01||delta<0.01||this.placeStatus!=PLACE_RUN_STATUS){this.AddVerticesMovementToUndo(vertices,prevCoordinates)
this.ScaleToGraph()
return}this.KamadaKawaiUpdateVertex(vertices,max.vertex,springs,bbox)
window.requestAnimationFrame(()=>this.KamadaKawaiIteration(iterations-1,vertices,springs,prevCoordinates,bbox,max.energy))}
GraphRedactor.prototype.KamadaKawaiAnimation=function(iterations=1000){let vertices=this.vertices.ToArray()
let bbox=this.GetViewAreaBoundingBoxReal()
let springs=this.KamadaKawaiInitSprings(vertices,bbox)
let prevCoordinates=this.GetVerticesCoordinates(vertices)
this.KamadaKawaiIteration(iterations,vertices,springs,prevCoordinates,bbox,Infinity)}
GraphRedactor.prototype.KamadaKawai=function(iterations=1000){let vertices=this.vertices.ToArray()
let bbox=this.GetViewAreaBoundingBoxReal()
let springs=this.KamadaKawaiInitSprings(vertices,bbox)
let prevCoordinates=this.GetVerticesCoordinates(vertices)
let prevEnergy=Infinity
for(let i=0;i<iterations;i++){let max=this.FindMaxVertexEnergy(vertices,springs)
let delta=Math.abs(prevEnergy-max.energy)
if(max.vertex==null||max.energy<0.01||delta<0.01)break
this.KamadaKawaiUpdateVertex(vertices,max.vertex,springs,bbox)
prevEnergy=max.energy}this.AddVerticesMovementToUndo(vertices,prevCoordinates)
this.ScaleToGraph()}
GraphRedactor.prototype.FindMaxVertexEnergy=function(vertices,springs){let maxEnergy=-1
let maxVertex=null
for(let i=0;i<vertices.length;i++){let energy=this.GetVertexEnergy(vertices,i,springs)
if(energy>maxEnergy){maxEnergy=energy
maxVertex=i}}return{vertex:maxVertex,energy:maxEnergy}}
GraphRedactor.prototype.GetVertexEnergy=function(vertices,vertexIndex,springs){let energy={x:0,y:0}
for(let i=0;i<vertices.length;i++){if(i==vertexIndex)continue
let dx=vertices[vertexIndex].x-vertices[i].x
let dy=vertices[vertexIndex].y-vertices[i].y
let distance=Math.sqrt(dx*dx+dy*dy)
let spring=springs[vertexIndex][i]
energy.x+=dx*spring.strength*(1-spring.length/distance)
energy.y+=dy*spring.strength*(1-spring.length/distance)}return Math.sqrt(energy.x*energy.x+energy.y*energy.y)}
GraphRedactor.prototype.KamadaKawaiUpdateVertex=function(vertices,vertexIndex,springs,bbox){let energy={x:0,y:0,xx:0,xy:0,yy:0}
for(let i=0;i<vertices.length;i++){if(i==vertexIndex)continue
let dx=vertices[vertexIndex].x-vertices[i].x
let dy=vertices[vertexIndex].y-vertices[i].y
let distance=Math.sqrt(dx*dx+dy*dy)
let distance3=distance*distance*distance
let spring=springs[vertexIndex][i]
energy.x+=dx*spring.strength*(1-spring.length/distance)
energy.y+=dy*spring.strength*(1-spring.length/distance)
energy.xy+=spring.strength*spring.length*dx*dy/distance3
energy.xx+=spring.strength*(1-spring.length*dy*dy/distance3)
energy.yy+=spring.strength*(1-spring.length*dx*dx/distance3)}let den=energy.xx*energy.yy-energy.xy*energy.xy
vertices[vertexIndex].x+=(energy.xy*energy.y-energy.yy*energy.x)/den
vertices[vertexIndex].y+=(energy.xy*energy.x-energy.xx*energy.y)/den}
;
